/* Modul „Medizin“ – medizinische Fachbegriffe für den Praxisalltag
   Erstellt Juli 2026, fachlich lektoriert. syn = unsichtbare Suchbegriffe
   (Synonyme, Latein, gängige Falschschreibungen), wird nicht angezeigt. */
window.MEDIZIN = [

  // ===== Bewegungsapparat & Verletzungen =====
  { k: "Achillessehne", v: "Kräftigste Sehne des Körpers; sie verbindet die Wadenmuskulatur mit dem Fersenbein und ermöglicht das Abstoßen beim Gehen und Laufen. Häufige Beschwerdebilder in der Praxis sind die Achillessehnenreizung (Achillodynie) und der Achillessehnenriss.", syn: "Achillodynie, Achillessehnenentzündung, Achillessehnenruptur, Achillessehnenriss, Tendo calcaneus, Achilles-Sehne, Achilessehne, Achillesehne", group: "Bewegungsapparat & Verletzungen" },
  { k: "Arthritis (Gelenkentzündung)", v: "Entzündung eines oder mehrerer Gelenke mit Schmerz, Schwellung, Überwärmung und Rötung; Ursachen sind u. a. Rheuma (rheumatoide Arthritis), Gicht oder Infektionen. Nicht zu verwechseln mit Arthrose, die einen Verschleiß bezeichnet.", syn: "Gelenkentzündung, rheumatoide Arthritis, Polyarthritis, Gichtarthritis, Arthritis urica, Rheuma, Athritis, Artritis", group: "Bewegungsapparat & Verletzungen" },
  { k: "Arthrose (Gelenkverschleiß)", v: "Verschleiß des Gelenkknorpels über das altersübliche Maß hinaus, am häufigsten an Knie (Gonarthrose), Hüfte (Coxarthrose) und Fingern. Eine der häufigsten Dauerdiagnosen in der Hausarztpraxis; nicht zu verwechseln mit Arthritis (Gelenkentzündung).", syn: "Gelenkverschleiß, Gonarthrose, Coxarthrose, Kniearthrose, Hüftarthrose, Fingerarthrose, Osteoarthrose, Athrose, Artrose", group: "Bewegungsapparat & Verletzungen" },
  { k: "Bandscheibe", v: "Elastische Knorpelscheibe mit weichem Gallertkern, die zwischen je zwei Wirbelkörpern liegt und als Stoßdämpfer der Wirbelsäule wirkt. Taucht in Befunden häufig bei Rückenschmerzen auf, z. B. als Bandscheibenvorwölbung (Protrusion) oder Bandscheibenvorfall.", syn: "Discus intervertebralis, Zwischenwirbelscheibe, Diskus, Bandscheiben, Bandscheibenvorwölbung, Protrusion, Bandscheibenschaden", group: "Bewegungsapparat & Verletzungen" },
  { k: "Bandscheibenvorfall (Diskusprolaps)", v: "Bei der Bandscheibenvorwölbung (Protrusion) bleibt der Faserring intakt und die Bandscheibe wölbt sich nur vor; erst beim Bandscheibenvorfall (Prolaps) durchbricht der Gallertkern den Faserring. Das sind unterschiedliche Befunde und keine Synonyme - die Vorwölbung sollte höchstens als verwandter Begriff geführt werden.", syn: "Diskusprolaps, Discusprolaps, Prolaps, Bandscheibenprolaps, NPP, Nucleus-pulposus-Prolaps, Diskushernie, Bandscheibenvorwölbung", group: "Bewegungsapparat & Verletzungen" },
  { k: "Bursitis (Schleimbeutelentzündung)", v: "Entzündung eines Schleimbeutels – eines kleinen Gleitkissens zwischen Knochen, Sehnen und Haut –, häufig an Ellenbogen, Knie, Schulter oder Hüfte. Ursachen sind meist Dauerdruck, Überlastung oder eine Infektion; typisch sind Schwellung und Druckschmerz.", syn: "Schleimbeutelentzündung, Bursitis olecrani, Bursitis praepatellaris, Bursitis trochanterica, Schleimbeutel, Bursa, Burzitis, Bursitits", group: "Bewegungsapparat & Verletzungen" },
  { k: "Distale Radiusfraktur (Handgelenksbruch)", v: "Bruch der Speiche kurz oberhalb des Handgelenks, meist nach Sturz auf die ausgestreckte Hand; der häufigste Knochenbruch überhaupt. Kommt in der Hausarztpraxis oft bei älteren Patienten nach Stürzen vor, häufig im Zusammenhang mit Osteoporose.", syn: "Handgelenksbruch, Speichenbruch, Radiusfraktur, Colles-Fraktur, Smith-Fraktur, Handgelenksfraktur, Radiusfraktur loco typico, Handgelenkbruch", group: "Bewegungsapparat & Verletzungen" },
  { k: "Distorsion (Verstauchung)", v: "Verstauchung eines Gelenks durch gewaltsame Überdehnung von Gelenkkapsel und Bändern, meist durch Umknicken – am häufigsten am Sprunggelenk. Sehr häufiger Vorstellungsgrund nach Sport- und Alltagsunfällen.", syn: "Verstauchung, Sprunggelenksdistorsion, Supinationstrauma, Umknicktrauma, Distorsionstrauma, Zerrung, Disdorsion, Distortion", group: "Bewegungsapparat & Verletzungen" },
  { k: "Epicondylitis (Tennisellenbogen/Golferellenbogen)", v: "Schmerzhafte Reizung der Sehnenansätze am Ellenbogen durch Überlastung: außen als Tennisellenbogen (Epicondylitis humeri radialis), innen als Golferellenbogen (Epicondylitis humeri ulnaris). Häufig bei handwerklicher Arbeit, Bildschirmarbeit oder Sport.", syn: "Tennisarm, Tennisellenbogen, Golferarm, Golferellenbogen, Epicondylitis humeri radialis, Epicondylitis humeri ulnaris, Epikondylitis, Epicondilitis, Epicondylopathie", group: "Bewegungsapparat & Verletzungen" },
  { k: "Ermüdungsfraktur (Stressfraktur)", v: "Knochenbruch durch wiederholte Überlastung statt durch einen einzelnen Unfall, typischerweise am Mittelfuß oder Schienbein, z. B. bei Läufern oder nach ungewohnt langem Gehen. Wird auch Stress- oder Marschfraktur genannt.", syn: "Stressfraktur, Marschfraktur, Ermüdungsbruch, Überlastungsfraktur, Stressreaktion, Ermüdungsbruch Mittelfuß", group: "Bewegungsapparat & Verletzungen" },
  { k: "Fersensporn (Kalkaneussporn)", v: "Dornartiger Knochenauswuchs am Fersenbein, meist am Ansatz der Sehnenplatte der Fußsohle; die Schmerzen entstehen vor allem durch die begleitende Reizung dieser Plantarfaszie (Plantarfasziitis). Typisch ist stechender Anlaufschmerz an der Ferse morgens oder nach längerem Sitzen.", syn: "Kalkaneussporn, Calcaneussporn, Plantarfasziitis, Plantarfasciitis, Fersenschmerz, plantarer Fersensporn, Fersenspor, Fersensporen", group: "Bewegungsapparat & Verletzungen" },
  { k: "Fissur (Knochenriss)", v: "Feiner Riss im Knochen ohne vollständige Durchtrennung (\"Haarriss\"), oft nur im Röntgen oder CT erkennbar. Der Begriff bezeichnet außerhalb des Bewegungsapparats auch schmale Einrisse der Haut oder Schleimhaut (z. B. Analfissur).", syn: "Haarriss, Knochenriss, Knochenfissur, unvollständige Fraktur, Fissuren, Fisur, Fissur Knochen", group: "Bewegungsapparat & Verletzungen" },
  { k: "Fraktur (Knochenbruch)", v: "Knochenbruch: vollständige oder teilweise Durchtrennung eines Knochens, meist durch Sturz oder Unfall. In Befunden wird die Form beschrieben, z. B. Quer-, Spiral- oder Trümmerfraktur, offen oder geschlossen; \"disloziert\" bedeutet verschoben.", syn: "Knochenbruch, Bruch, Querfraktur, Spiralfraktur, Trümmerfraktur, offene Fraktur, geschlossene Fraktur, dislozierte Fraktur, Fractur, Fraktion", group: "Bewegungsapparat & Verletzungen" },
  { k: "Hallux valgus (Ballenzeh)", v: "Fehlstellung der Großzehe, die sich zunehmend in Richtung der kleinen Zehen neigt, wodurch der Großzehenballen sichtbar hervortritt (\"Ballenzeh\"). Häufig bei Frauen und oft mit Druckschmerzen im Schuh verbunden.", syn: "Ballenzeh, Großzehenfehlstellung, Ballengroßzehe, Schiefzehe, Frostballen, Hallux, Halux valgus, Hallux-valgus-Fehlstellung", group: "Bewegungsapparat & Verletzungen" },
  { k: "Iliosakralgelenk (ISG)", v: "Gelenk zwischen Kreuzbein und Darmbein am Übergang von der Wirbelsäule zum Becken; es ist kaum beweglich, aber eine häufige Quelle tiefsitzender Rückenschmerzen. Wird in der Praxis oft als ISG-Blockade oder ISG-Syndrom diktiert.", syn: "ISG, Kreuzbein-Darmbein-Gelenk, Kreuz-Darmbein-Gelenk, Sakroiliakalgelenk, ISG-Blockade, ISG-Syndrom, Ileosakralgelenk, Iliosacralgelenk", group: "Bewegungsapparat & Verletzungen" },
  { k: "Impingement-Syndrom (Schulterengpasssyndrom)", v: "Engpass-Syndrom meist der Schulter: Sehnen der Rotatorenmanschette und der Schleimbeutel werden unter dem Schulterdach eingeklemmt. Typisch sind Schmerzen beim seitlichen Anheben des Arms, etwa bei Überkopfarbeiten.", syn: "Schulterengpasssyndrom, Engpasssyndrom, subakromiales Impingement, Impingementsyndrom, Schulterimpingement, Impingment, Impingement Schulter", group: "Bewegungsapparat & Verletzungen" },
  { k: "Ischialgie (Ischias)", v: "Schmerz entlang des Ischiasnervs, der vom Gesäß über die Rückseite des Beins bis in den Fuß ausstrahlen kann; häufige Ursache ist eine gereizte Nervenwurzel, z. B. beim Bandscheibenvorfall. Die Kombination mit Kreuzschmerzen heißt Lumboischialgie.", syn: "Ischias, Ischiasschmerz, Lumboischialgie, Ischiassyndrom, Ischiasnerv, Nervus ischiadicus, Ischalgie, Ischiagie", group: "Bewegungsapparat & Verletzungen" },
  { k: "Karpaltunnelsyndrom", v: "Der Nervus medianus heißt auf Deutsch 'Mittelnerv' (bzw. mittlerer Armnerv); er zieht am Unterarm entlang und durch den Karpaltunnel zur Hand. 'Mittelhandnerv' ist keine korrekte Bezeichnung und sollte durch 'Nervus medianus (Mittelnerv)' ersetzt werden.", syn: "KTS, CTS, Carpaltunnelsyndrom, Karpaltunnel, Medianuskompressionssyndrom, Nervenengpasssyndrom, Karpaltunnel-Syndrom, Kapaltunnelsyndrom", group: "Bewegungsapparat & Verletzungen" },
  { k: "Kontusion (Prellung)", v: "Prellung: Verletzung durch stumpfe Gewalt (Stoß, Schlag, Sturz) ohne offene Wunde, meist mit Bluterguss, Schwellung und Druckschmerz. Einer der häufigsten Beratungsanlässe nach Sport- und Alltagsunfällen.", syn: "Prellung, Quetschung, Muskelprellung, Rippenprellung, Knieprellung, Contusio, Kontusio, Kondusion, Schulterprellung", group: "Bewegungsapparat & Verletzungen" },
  { k: "Kreuzband (vorderes/hinteres)", v: "Zwei sich überkreuzende Bänder im Inneren des Kniegelenks (vorderes und hinteres Kreuzband), die das Knie nach vorne und hinten stabilisieren. Der Kreuzbandriss ist eine typische Sportverletzung, die oft zuerst in der Hausarztpraxis vorgestellt wird.", syn: "vorderes Kreuzband, hinteres Kreuzband, VKB, HKB, Kreuzbandriss, Kreuzbandruptur, Ligamentum cruciatum, Kreutzband, Kreuzbänder", group: "Bewegungsapparat & Verletzungen" },
  { k: "Lumbago (Hexenschuss)", v: "Plötzlich einschießender, heftiger Kreuzschmerz im Lendenbereich, oft nach Bücken oder Heben; meist ohne ausstrahlende Nervenschmerzen und in der Regel harmlos. In Befunden auch als akute Lumbalgie oder LWS-Syndrom bezeichnet.", syn: "Hexenschuss, Lumbalgie, akute Lumbalgie, akuter Kreuzschmerz, LWS-Syndrom, Kreuzschmerzen, unterer Rückenschmerz, Lummbago", group: "Bewegungsapparat & Verletzungen" },
  { k: "Luxation (Verrenkung)", v: "Verrenkung oder Ausrenkung: Die gelenkbildenden Knochen springen vollständig aus ihrer normalen Position, häufig an Schulter, Ellenbogen, Kniescheibe oder Fingern. Eine unvollständige Ausrenkung heißt Subluxation.", syn: "Verrenkung, Ausrenkung, Auskugelung, ausgekugelt, Schulterluxation, Patellaluxation, Subluxation, Luxsation, Luxierung", group: "Bewegungsapparat & Verletzungen" },
  { k: "Meniskus (Menisken)", v: "Halbmondförmige Knorpelscheibe im Kniegelenk, die als Stoßdämpfer zwischen Ober- und Unterschenkel wirkt; jedes Knie hat einen Innen- und einen Außenmeniskus. Taucht in Befunden häufig bei Knieschmerzen auf, z. B. als Meniskusriss oder Meniskusläsion.", syn: "Menisken, Innenmeniskus, Außenmeniskus, Meniskusriss, Meniskusläsion, Meniskusschaden, Meniscus, Miniskus, Menikus", group: "Bewegungsapparat & Verletzungen" },
  { k: "Muskelfaserriss", v: "Riss einzelner Muskelfaserbündel durch plötzliche starke Belastung, typisch in Wade oder Oberschenkel beim Sport. Die leichtere Vorstufe ist die Muskelzerrung, die schwerere Form der Muskelbündel- oder komplette Muskelriss.", syn: "Muskelriss, Muskelbündelriss, Faserriss, Muskelzerrung, Zerrung, Wadenzerrung, Muskelfaserriß, Muskelfasereinriss", group: "Bewegungsapparat & Verletzungen" },
  { k: "Osteoporose (Knochenschwund)", v: "Osteopenie bezeichnet eine leichte Minderung der Knochendichte (T-Wert zwischen -1 und -2,5), die Osteoporose die stärkere Form (T-Wert <= -2,5) mit deutlich erhöhtem Bruchrisiko. Osteopenie ist eine eigenständige Vorstufe, kein Synonym.", syn: "Knochenschwund, Knochendichteminderung, Osteopenie, Knochendichtemessung, Osteodensitometrie, DXA, Osteoperose, Osteoprose", group: "Bewegungsapparat & Verletzungen" },
  { k: "Rotatorenmanschette", v: "Gruppe von vier Muskeln und ihren Sehnen, die das Schultergelenk wie eine Manschette umschließen und das Heben und Drehen des Arms ermöglichen. In Befunden häufig bei Schulterschmerzen, z. B. als Rotatorenmanschettenruptur (Sehnenriss).", syn: "Rotatorenmanschettenruptur, Rotatorenmanschettenriss, Rotatoren, Schultermanschette, Supraspinatussehne, Rotatorenmannschette, Rotatorenmanschettenläsion", group: "Bewegungsapparat & Verletzungen" },
  { k: "Ruptur (Riss)", v: "Riss oder Zerreißung von Gewebe wie Sehne, Band oder Muskel, z. B. Achillessehnenruptur oder Kreuzbandruptur. In Befunden oft mit dem Zusatz Partialruptur (Teilriss) oder Totalruptur (kompletter Riss).", syn: "Riss, Zerreißung, Sehnenruptur, Bandruptur, Bänderriss, Muskelriss, Partialruptur, Totalruptur, Rubtur, Rupture", group: "Bewegungsapparat & Verletzungen" },
  { k: "Schenkelhalsfraktur", v: "Die Schenkelhalsfraktur liegt am Oberschenkelhals unterhalb des Hüftkopfes (meist innerhalb der Gelenkkapsel), die pertrochantäre Fraktur dagegen im Bereich der Rollhügel (Trochanteren) außerhalb der Kapsel. Beides sind hüftgelenksnahe Frakturen, aber unterschiedliche Diagnosen - 'Hüftfraktur' wäre der passende Oberbegriff.", syn: "Oberschenkelhalsbruch, Schenkelhalsbruch, Hüftfraktur, Femurhalsfraktur, SHF, hüftgelenksnahe Fraktur, pertrochantäre Fraktur, Oberschenkelbruch", group: "Bewegungsapparat & Verletzungen" },
  { k: "Schleudertrauma (HWS-Distorsion)", v: "Verletzung der Halswirbelsäule durch plötzliches Vor- und Zurückschleudern des Kopfes, klassisch beim Auffahrunfall; in Befunden meist als HWS-Distorsion bezeichnet. Typisch sind Nackenschmerzen und Bewegungseinschränkung, oft erst Stunden nach dem Unfall.", syn: "HWS-Distorsion, HWS-Schleudertrauma, Halswirbelsäulen-Distorsion, Beschleunigungstrauma, Peitschenschlagverletzung, Whiplash, Schleuder-Trauma", group: "Bewegungsapparat & Verletzungen" },
  { k: "Skoliose", v: "Seitliche Verbiegung der Wirbelsäule mit Verdrehung der Wirbelkörper, die meist im Wachstumsalter entsteht. Fällt in der Praxis oft bei Vorsorge- und Jugenduntersuchungen oder in orthopädischen Befunden auf.", syn: "Wirbelsäulenverkrümmung, Wirbelsäulenverbiegung, seitliche Wirbelsäulenkrümmung, Skoliosen, Scoliose, Skolliose, Rückgratverkrümmung", group: "Bewegungsapparat & Verletzungen" },
  { k: "Spinalkanalstenose", v: "Einengung des Wirbelkanals, in dem Rückenmark und Nerven verlaufen, meist verschleißbedingt an der Lendenwirbelsäule. Typisch sind Rücken- und Beinschmerzen beim Gehen, die sich beim Vorbeugen oder Hinsetzen bessern.", syn: "Wirbelkanalverengung, Wirbelkanalstenose, Spinalstenose, Spinalkanalverengung, lumbale Spinalkanalstenose, Claudicatio spinalis, Spinalkanalstenose LWS", group: "Bewegungsapparat & Verletzungen" },
  { k: "Syndesmose (Syndesmosenband)", v: "Straffe Bandverbindung zwischen zwei Knochen; gemeint ist meist das Band zwischen Schienbein und Wadenbein direkt oberhalb des Sprunggelenks. Kommt in Befunden häufig bei Sprunggelenksverletzungen vor, z. B. als Syndesmosenruptur (Riss) nach einem Umknicktrauma.", syn: "Syndesmosenband, Syndesmoseband, Zyndesmose, Sindesmose, Syndesmosenruptur, Syndesmosenverletzung, tibiofibulare Syndesmose, Sprunggelenksband", group: "Bewegungsapparat & Verletzungen" },
  { k: "Tendinitis (Sehnenentzündung)", v: "Entzündung oder Reizung einer Sehne durch Überlastung, z. B. an Schulter, Achillessehne oder Handgelenk. In Befunden steht heute oft der Oberbegriff Tendinopathie, weil meist Verschleiß und Reizung statt einer echten Entzündung vorliegen; Sonderform ist die Kalkschulter (Tendinitis calcarea).", syn: "Sehnenentzündung, Sehnenreizung, Tendinopathie, Tendinose, Tendopathie, Tendinitis calcarea, Kalkschulter, Tendinitits", group: "Bewegungsapparat & Verletzungen" },
  { k: "Tendovaginitis (Sehnenscheidenentzündung)", v: "Entzündung der Sehnenscheide, also der Gleithülle um eine Sehne, meist am Handgelenk oder Unterarm durch gleichförmige Belastung wie Bildschirmarbeit. Eine bekannte Sonderform ist die Tendovaginitis de Quervain am daumenseitigen Handgelenk.", syn: "Sehnenscheidenentzündung, Tendovaginitis de Quervain, Tenosynovitis, Mausarm, RSI-Syndrom, Sehnenscheiden-Entzündung, Tendovaginits", group: "Bewegungsapparat & Verletzungen" },

  // ===== Herz, Kreislauf & Gefäße =====
  { k: "Aneurysma", v: "Krankhafte Aussackung einer Arterienwand, am häufigsten an der Bauchschlagader; oft ein Zufallsbefund im Ultraschall. Männer ab 65 Jahren haben Anspruch auf ein einmaliges Ultraschall-Screening auf ein Bauchaortenaneurysma.", syn: "Gefäßaussackung, Aortenaneurysma, Bauchaortenaneurysma, BAA, Arterienerweiterung, Aneurisma, Anerysma, Aneurysm", group: "Herz, Kreislauf & Gefäße" },
  { k: "Angina pectoris", v: "Anfallsartiges Enge- oder Druckgefühl in der Brust durch Minderdurchblutung des Herzmuskels bei koronarer Herzkrankheit, oft bei Belastung. In der Hausarztpraxis häufiger Anlass für EKG und Überweisung zum Kardiologen.", syn: "Brustenge, Herzenge, Stenokardie, AP-Beschwerden, stabile Angina, instabile Angina, Angina Pektoris, Angina pektoris, Anginapectoris", group: "Herz, Kreislauf & Gefäße" },
  { k: "Antikoagulation (Blutverdünnung)", v: "Medikamentöse Hemmung der Blutgerinnung („Blutverdünnung“) zum Schutz vor Gerinnseln, z. B. bei Vorhofflimmern oder nach Thrombose. Unter Marcumar sind regelmäßige INR-Kontrollen (Gerinnungswert) in der Praxis nötig, DOAK kommen ohne Routinemessung aus.", syn: "Gerinnungshemmung, Blutverdünner, Marcumar, Phenprocoumon, Falithrom, DOAK, NOAK, Apixaban, Eliquis, Rivaroxaban, Xarelto, Edoxaban, Lixiana, Dabigatran, Pradaxa, INR, Quick-Wert, Antikoagulanzien, Antikoagulantien, Markumar", group: "Herz, Kreislauf & Gefäße" },
  { k: "Arterielle Hypertonie (Bluthochdruck)", v: "Dauerhaft erhöhter Blutdruck (in der Praxis ab etwa 140/90 mmHg), der lange keine Beschwerden macht, aber Gefäße, Herz und Nieren schädigt. Einer der häufigsten Behandlungsanlässe der Hausarztpraxis mit regelmäßigen Blutdruckkontrollen.", syn: "Bluthochdruck, hoher Blutdruck, Hypertonus, Hypertension, essenzielle Hypertonie, essentielle Hypertonie, RR erhöht, Blutdruckkrankheit, Hipertonie, Hyperthonie", group: "Herz, Kreislauf & Gefäße" },
  { k: "Arteriosklerose", v: "Chronische „Verkalkung“ der Arterien durch Ablagerungen (Plaques) in der Gefäßwand, die Gefäße verengen oder verschließen können. Gemeinsame Ursache von Herzinfarkt, Schlaganfall und pAVK – daher spielen Risikofaktoren wie Rauchen, Blutdruck und Cholesterin in der Praxis eine große Rolle.", syn: "Atherosklerose, Gefäßverkalkung, Arterienverkalkung, Plaques, Gefäßablagerungen, Arteriosclerose, Ateriosklerose, Arterioskleose", group: "Herz, Kreislauf & Gefäße" },
  { k: "Bypass (Bypass-Operation)", v: "Operativ angelegte Umleitung, die eine verengte oder verschlossene Arterie – meist am Herzen – mit körpereigenem Gefäßmaterial überbrückt. Patienten nach Bypass-OP kommen regelmäßig zur Nachsorge in die Hausarztpraxis.", syn: "aortokoronarer Bypass, ACB, ACVB, koronare Bypass-OP, Umgehungsgefäß, Gefäßüberbrückung, Beipass, Baipass, Bypas", group: "Herz, Kreislauf & Gefäße" },
  { k: "Embolie", v: "Plötzlicher Gefäßverschluss durch verschlepptes Material, meist ein Blutgerinnsel, das mit dem Blutstrom weitertransportiert wurde. Bekannteste Form ist die Lungenembolie nach Beinvenenthrombose – ein Notfall mit Luftnot und Brustschmerz.", syn: "Lungenembolie, LE, Embolus, arterielle Embolie, Gefäßverschluss, Thromboembolie, Embollie, Ämbolie, Embolle", group: "Herz, Kreislauf & Gefäße" },
  { k: "Endokarditis", v: "Meist bakterielle Entzündung der Herzinnenhaut und der Herzklappen; gefährliche Erkrankung, an die bei anhaltendem Fieber und bekanntem Klappenfehler gedacht wird. Patienten mit Kunstklappen tragen häufig einen Endokarditis-Ausweis.", syn: "Herzinnenhautentzündung, Endocarditis, Herzklappenentzündung, Endokarditisprophylaxe (verwandt), Endokardit, Endokartitis", group: "Herz, Kreislauf & Gefäße" },
  { k: "Extrasystolen", v: "Zusätzliche Herzschläge außerhalb des normalen Rhythmus, die Patienten oft als „Herzstolpern“ beschreiben. Meist harmlos, aber häufiger Grund für Ruhe- oder Langzeit-EKG in der Praxis.", syn: "Herzstolpern, Extraschläge, Palpitationen, Extrasystole, Extrasystolie, VES (ventrikuläre Extrasystolen), SVES (supraventrikuläre Extrasystolen), Extrasystoolen, Extrasystholen", group: "Herz, Kreislauf & Gefäße" },
  { k: "Herzgeräusch", v: "Zusätzliches Geräusch beim Abhören des Herzens, das auf einen Herzklappenfehler hinweisen kann, bei Kindern aber oft harmlos ist. Häufiger Grund für eine Überweisung zur Echokardiographie (Herzultraschall).", syn: "Systolikum, Diastolikum, Strömungsgeräusch, Nebengeräusch, akzidentelles Herzgeräusch, Vitium (Herzklappenfehler), Herzgeräusche, Hertzgeräusch", group: "Herz, Kreislauf & Gefäße" },
  { k: "Herzinfarkt (Myokardinfarkt)", v: "Absterben von Herzmuskelgewebe durch den akuten Verschluss eines Herzkranzgefäßes; typisch sind starker Brustschmerz mit Ausstrahlung in Arm, Kiefer oder Rücken, oft mit Luftnot und Kaltschweißigkeit. Notfall, bei dem in der Praxis sofort der Rettungsdienst alarmiert wird.", syn: "Myokardinfarkt, akutes Koronarsyndrom, ACS, STEMI, NSTEMI, Infarkt, Vorderwandinfarkt, Hinterwandinfarkt, Herzanfall, Herzattacke, Herzinfarckt", group: "Herz, Kreislauf & Gefäße" },
  { k: "Herzinsuffizienz", v: "Pumpschwäche des Herzens, bei der der Körper nicht mehr ausreichend mit Blut versorgt wird; typisch sind Luftnot, Leistungsknick und Wassereinlagerungen in den Beinen. Häufige Dauerdiagnose mit regelmäßigen Kontrollen in der Hausarztpraxis.", syn: "Herzschwäche, Herzmuskelschwäche, Pumpschwäche, Linksherzinsuffizienz, Rechtsherzinsuffizienz, globale Herzinsuffizienz, kardiale Insuffizienz, NYHA-Stadium, Herzinsufizienz, Herzinsuffiziens", group: "Herz, Kreislauf & Gefäße" },
  { k: "Herzkatheter (Koronarangiographie)", v: "Untersuchung, bei der ein dünner Schlauch über eine Arterie an Handgelenk oder Leiste zum Herzen geführt wird, um die Herzkranzgefäße mit Kontrastmittel darzustellen. Befunde davon tauchen häufig in Arztbriefen und Entlassbriefen auf.", syn: "Herzkatheteruntersuchung, Koronarangiographie, Koronarangiografie, Linksherzkatheter, Coro, Katheteruntersuchung, Herzkateter, Herzkatether", group: "Herz, Kreislauf & Gefäße" },
  { k: "Herzschrittmacher", v: "Unter die Haut implantiertes Gerät, das bei zu langsamem Herzschlag elektrische Impulse abgibt. Schrittmacherträger kommen regelmäßig zur Kontrolle; der Schrittmacherausweis ist z. B. vor MRT-Terminen wichtig.", syn: "Schrittmacher, Pacemaker, Einkammerschrittmacher, Zweikammerschrittmacher, Schrittmacherkontrolle, ICD (implantierbarer Defibrillator, verwandt), Herzschritmacher, Schrittmacheraggregat", group: "Herz, Kreislauf & Gefäße" },
  { k: "Hypotonie", v: "Zu niedriger Blutdruck (etwa unter 100/60 mmHg), der sich mit Schwindel, Müdigkeit oder Schwarzwerden vor den Augen beim Aufstehen zeigen kann. Meist harmlos, wird aber vor allem bei älteren Patienten wegen Sturzgefahr ernst genommen.", syn: "niedriger Blutdruck, Blutdruckabfall, Hypotension, Hypotonus, orthostatische Hypotonie, Orthostase, Kreislaufschwäche, Hipotonie, Hypothonie", group: "Herz, Kreislauf & Gefäße" },
  { k: "Kardiomyopathie", v: "Sammelbegriff für Erkrankungen des Herzmuskels selbst, etwa eine krankhafte Erweiterung oder Verdickung der Herzwände. Kann zu Herzschwäche und Rhythmusstörungen führen und wird meist kardiologisch mitbetreut.", syn: "Herzmuskelerkrankung, dilatative Kardiomyopathie, DCM, hypertrophe Kardiomyopathie, HCM, HOCM, Cardiomyopathie, Kardiomyopatie, Kardiomüopathie", group: "Herz, Kreislauf & Gefäße" },
  { k: "Klappeninsuffizienz", v: "Schlussunfähigkeit (Undichtigkeit) einer Herzklappe, sodass Blut zurückfließt und das Herz mehr Arbeit leisten muss. Ausmaß und Verlauf werden mit der Echokardiographie (Herzultraschall) kontrolliert.", syn: "undichte Herzklappe, Herzklappenundichtigkeit, Mitralinsuffizienz, Aorteninsuffizienz, Trikuspidalinsuffizienz, Herzklappeninsuffizienz, Klappenschwäche, Klappeninsufizienz", group: "Herz, Kreislauf & Gefäße" },
  { k: "Klappenstenose", v: "Verengung einer Herzklappe, durch die das Herz gegen erhöhten Widerstand pumpen muss; häufigste Form beim älteren Menschen ist die Aortenklappenstenose. Wird oft über ein Herzgeräusch entdeckt und per Herzultraschall beurteilt.", syn: "Herzklappenverengung, Aortenklappenstenose, Aortenstenose, Mitralstenose, Pulmonalstenose, Klappenverengung, Herzklappenstenose, Klappenstenoose", group: "Herz, Kreislauf & Gefäße" },
  { k: "Myokarditis", v: "Entzündung des Herzmuskels, meist durch Viren ausgelöst; kann sich nach Infekten mit Leistungsknick, Herzstolpern oder Luftnot zeigen. Wichtiger Grund, warum bei fieberhaften Infekten auf Herzbeschwerden geachtet wird.", syn: "Herzmuskelentzündung, Myocarditis, Miokarditis, Myokardit, Herzentzündung, Myokarditiss", group: "Herz, Kreislauf & Gefäße" },
  { k: "Perikarditis", v: "Entzündung des Herzbeutels, also der Hülle um das Herz, häufig nach Virusinfekten. Typisch sind atemabhängige, oft lageabhängige Brustschmerzen und Veränderungen im EKG.", syn: "Herzbeutelentzündung, Pericarditis, Perikarderguss (verwandt), Perikardit, Pericarditis sicca, Perrikarditis", group: "Herz, Kreislauf & Gefäße" },
  { k: "Periphere arterielle Verschlusskrankheit (pAVK)", v: "Verengung der Beinarterien durch Gefäßverkalkung; typisch sind belastungsabhängige Wadenschmerzen, die zum Stehenbleiben zwingen („Schaufensterkrankheit“). In der Praxis Anlass für Pulsstatus und Knöchel-Arm-Index-Messung (ABI).", syn: "Schaufensterkrankheit, Claudicatio intermittens, Raucherbein, AVK, Durchblutungsstörung der Beine, PAVK, Verschlusskrankheit", group: "Herz, Kreislauf & Gefäße" },
  { k: "Stent", v: "Kleines Metallgitterröhrchen, das ein verengtes Gefäß – meist ein Herzkranzgefäß – dauerhaft offen hält. Wird in der Regel während einer Herzkatheteruntersuchung eingesetzt; danach nehmen Patienten oft gerinnungshemmende Medikamente.", syn: "Gefäßstütze, Koronarstent, Stentimplantation, medikamentenbeschichteter Stent, DES, Stent-Einlage, Stend, Stänt", group: "Herz, Kreislauf & Gefäße" },
  { k: "Synkope", v: "Kurzzeitige Bewusstlosigkeit durch vorübergehend verminderte Hirndurchblutung, meist mit raschem vollständigem Erwachen. Häufiger Abklärungsanlass in der Praxis mit EKG, Blutdruckmessung und je nach Befund Überweisung.", syn: "Ohnmacht, Kreislaufkollaps, Kollaps, kurze Bewusstlosigkeit, vasovagale Synkope, orthostatische Synkope, Sinkope, Syncope, Synkoppe", group: "Herz, Kreislauf & Gefäße" },
  { k: "Thrombose", v: "Verschluss eines Gefäßes durch ein Blutgerinnsel, am häufigsten in den tiefen Beinvenen; typisch sind einseitige Schwellung, Schmerz und Überwärmung des Beins. Gefürchtete Folge ist die Lungenembolie, weshalb der Verdacht dringlich abgeklärt wird.", syn: "Blutgerinnsel, Thrombus, tiefe Beinvenenthrombose, TVT, Venenthrombose, Phlebothrombose, Beinvenenthrombose, Trombose, Thrombosis", group: "Herz, Kreislauf & Gefäße" },
  { k: "Varizen (Krampfadern)", v: "Erweiterte, geschlängelte oberflächliche Venen, meist an den Beinen; sie können schwere Beine, Schwellungen und Hautveränderungen verursachen. Häufiges Thema in der Praxis, oft mit Überweisung zum Phlebologen (Venenspezialist).", syn: "Krampfadern, Varikose, Varikosis, Varize, Besenreiser (verwandt), Venenleiden, Waritzen, Varitzen, Krampfader", group: "Herz, Kreislauf & Gefäße" },
  { k: "Vorhofflimmern", v: "Häufigste anhaltende Herzrhythmusstörung mit unregelmäßigem, oft zu schnellem Puls; im EKG gut erkennbar. Wichtig, weil das Schlaganfallrisiko steigt und Betroffene deshalb meist gerinnungshemmende Medikamente erhalten.", syn: "Absolute Arrhythmie, Flimmerarrhythmie, VHF, AFib, Vorhof-Flimmern, unregelmäßiger Puls, Vorhofflattern (verwandt), Vorhoffflimmern, Vorhofflimern", group: "Herz, Kreislauf & Gefäße" },

  // ===== Atemwege & HNO =====
  { k: "Allergische Rhinitis (Heuschnupfen)", v: "Allergisch bedingte Entzündung der Nasenschleimhaut mit Niesattacken, Fließschnupfen und oft juckenden, tränenden Augen; Auslöser sind z. B. Pollen, Hausstaubmilben oder Tierhaare. In der Hausarztpraxis häufig Ausgangspunkt für Allergietests und ggf. eine Hyposensibilisierung.", syn: "Heuschnupfen, Pollenallergie, allergischer Schnupfen, Rhinitis allergica, Pollinosis, allergische Rhinokonjunktivitis, Rinitis, Rhinits", group: "Atemwege & HNO" },
  { k: "Asthma bronchiale", v: "Chronisch-entzündliche Erkrankung der Atemwege, bei der sich die Bronchien anfallsweise verengen – mit Atemnot, pfeifender Atmung und Husten. In der Hausarztpraxis sehr häufig, u. a. im Rahmen des DMP Asthma mit regelmäßigen Lungenfunktionskontrollen.", syn: "Asthma, Bronchialasthma, allergisches Asthma, Belastungsasthma, asthmatische Erkrankung, Astma, Asma, Asthma bronchial", group: "Atemwege & HNO" },
  { k: "Bronchitis", v: "Entzündung der Schleimhaut der Bronchien (Äste der Luftröhre), meist durch Viren, mit Husten und Auswurf. Einer der häufigsten Beratungsanlässe und AU-Gründe in der Hausarztpraxis, vor allem in der Erkältungssaison.", syn: "akute Bronchitis, chronische Bronchitis, Bronchialkatarrh, Entzündung der Bronchien, Bronschitis, Brochitis, Bronchitits", group: "Atemwege & HNO" },
  { k: "Emphysem (Lungenemphysem)", v: "Dauerhafte Überblähung der Lunge mit Zerstörung der Lungenbläschen, meist durch langjähriges Rauchen und häufig Teil der COPD; führt zu zunehmender Atemnot. Der Begriff taucht oft in Röntgen- und Lungenfacharzt-Befunden auf.", syn: "Lungenemphysem, Lungenüberblähung, Blählunge, überblähte Lunge, Emphysema, Emfysem, Emphysehm", group: "Atemwege & HNO" },
  { k: "Epistaxis (Nasenbluten)", v: "Blutung aus der Nase, meist aus einem gut durchbluteten Gefäßgeflecht im vorderen Nasenabschnitt (Locus Kiesselbachi); häufig harmlos, unter blutverdünnenden Medikamenten aber teils hartnäckig. Regelmäßiger Akutanlass am Empfang der Hausarztpraxis.", syn: "Nasenbluten, Nasenblutung, Epistaxis anterior, Blutung aus der Nase, Epitaxis, Epistaxsis, Epistachsis", group: "Atemwege & HNO" },
  { k: "Hyposensibilisierung", v: "Behandlung von Allergien, bei der der Körper durch regelmäßige Gabe des Allergens (als Spritze oder als Tropfen/Tablette) über Jahre daran gewöhnt wird. In der Hausarztpraxis werden die Spritzen oft verabreicht; anschließend bleibt der Patient zur Nachbeobachtung etwa 30 Minuten in der Praxis.", syn: "spezifische Immuntherapie, SIT, Allergie-Immuntherapie, AIT, Desensibilisierung, Allergie-Impfung (umgangssprachlich), SCIT, SLIT, Hyposensibilisation, Hypersensibilisierung (Falschschreibung)", group: "Atemwege & HNO" },
  { k: "Hörsturz", v: "Plötzliche, meist einseitige Hörminderung ohne erkennbare äußere Ursache, oft begleitet von Druckgefühl im Ohr oder Ohrgeräuschen. Patienten melden sich meist als Akutfall; in der Regel wird zeitnah zum HNO-Arzt überwiesen.", syn: "akuter Hörverlust, plötzlicher Hörverlust, akute Innenohrschwerhörigkeit, Ohrinfarkt (umgangssprachlich), Hoersturz, Hörstürz, Hörsturtz", group: "Atemwege & HNO" },
  { k: "Inhalativa (inhalative Medikamente)", v: "Sammelbegriff für Medikamente zum Einatmen, z. B. bronchienerweiternde oder kortisonhaltige Sprays und Pulver, vor allem bei Asthma und COPD. Die richtige Inhalationstechnik wird in der Praxis oft geschult, häufig durch die MFA.", syn: "Inhalatoren, Asthmaspray, Sprays, Dosieraerosol, Pulverinhalator, Turbohaler, Diskus, Respimat, inhalative Therapie, Inhalativum, Inhalanda", group: "Atemwege & HNO" },
  { k: "Laryngitis (Kehlkopfentzündung)", v: "Entzündung der Kehlkopfschleimhaut, meist im Rahmen eines Atemwegsinfekts oder nach starker Stimmbelastung, mit Heiserkeit bis hin zum Stimmverlust. Bei länger anhaltender Heiserkeit wird meist zum HNO-Arzt überwiesen.", syn: "Kehlkopfentzündung, Laryngitis acuta, Larynxentzündung, Stimmbandentzündung, Laringitis, Larynghitis, Larüngitis", group: "Atemwege & HNO" },
  { k: "Otitis media (Mittelohrentzündung)", v: "Entzündung des Mittelohrs hinter dem Trommelfell, meist bei Kindern im Rahmen eines Infekts, mit Ohrenschmerzen und oft Fieber. Häufiger Grund für kurzfristige Termine; der Arzt beurteilt das Trommelfell mit dem Ohrspiegel (Otoskop).", syn: "Mittelohrentzündung, akute Mittelohrentzündung, Otitis media acuta, Ohrentzündung, Ottitis media, Otitismedia, Otitis", group: "Atemwege & HNO" },
  { k: "Pertussis (Keuchhusten)", v: "Hochansteckende bakterielle Infektion der Atemwege mit wochenlang anhaltenden, stakkatoartigen Hustenanfällen; für Säuglinge besonders gefährlich. Der Nachweis ist meldepflichtig, und die Impfung gehört zum Standardimpfkalender – daher auch bei der Impfberatung in der Praxis relevant.", syn: "Keuchhusten, Stickhusten, 100-Tage-Husten, Bordetella pertussis, Pertusis, Pertussiss, Keuchusten", group: "Atemwege & HNO" },
  { k: "Pleuraerguss", v: "Flüssigkeitsansammlung zwischen Lungenfell und Rippenfell (Pleura), z. B. bei Herzschwäche, Lungenentzündung oder Tumorerkrankungen; führt oft zu Atemnot. Taucht häufig in Röntgen- oder Ultraschallbefunden auf.", syn: "Erguss im Brustkorb, Flüssigkeit im Pleuraspalt, Wasser in der Lunge (umgangssprachlich), Pleura-Erguss, Pleuraerguß, Pleuraergus", group: "Atemwege & HNO" },
  { k: "Pneumonie (Lungenentzündung)", v: "Entzündung des Lungengewebes, meist durch Bakterien wie Pneumokokken, mit Fieber, Husten und Atemnot. Wird in der Praxis oft per Abhören, Labor und Röntgenüberweisung abgeklärt; besonders bei älteren und chronisch kranken Patienten bedeutsam.", syn: "Lungenentzündung, Bronchopneumonie, Lobärpneumonie, ambulant erworbene Pneumonie, CAP, Pneumonia, Pnemonie, Pneumoni, Pneunomie", group: "Atemwege & HNO" },
  { k: "Pseudokrupp", v: "Virusbedingte Entzündung des Kehlkopfs bei Klein- und Vorschulkindern mit bellendem Husten, Heiserkeit und pfeifendem Einatmen, typischerweise nachts. Häufiger Grund für besorgte Elternanrufe und dringliche Termine in der Praxis.", syn: "Krupphusten, Kruppsyndrom, stenosierende Laryngitis, Laryngitis subglottica, subglottische Laryngitis, Pseudo-Krupp, Pseudocroup, Pseudokrup", group: "Atemwege & HNO" },
  { k: "Schlafapnoe (Schlafapnoe-Syndrom)", v: "Wiederholte Atemaussetzer im Schlaf, meist durch einen Verschluss der oberen Atemwege, mit lautem Schnarchen und ausgeprägter Tagesmüdigkeit. Die Abklärung startet oft beim Hausarzt und läuft über eine ambulante Schlafmessung (Polygraphie) bzw. das Schlaflabor.", syn: "obstruktive Schlafapnoe, OSAS, Schlafapnoesyndrom, Atemaussetzer im Schlaf, Schnarchkrankheit (umgangssprachlich), Schlaf-Apnoe, Schlafapnö, Schlafapnoö", group: "Atemwege & HNO" },
  { k: "Sinusitis (Nasennebenhöhlenentzündung)", v: "Entzündung der Schleimhaut in den Nasennebenhöhlen, meist im Rahmen eines Erkältungsinfekts, mit Druckschmerz im Gesicht, verstopfter Nase und Kopfschmerzen. Sehr häufiger Beratungsanlass in der Hausarztpraxis.", syn: "Nasennebenhöhlenentzündung, Nebenhöhlenentzündung, Rhinosinusitis, Kieferhöhlenentzündung, Stirnhöhlenentzündung, Sinusitis maxillaris, Sinusitis frontalis, Sinositis, Sinusites, Sinnusitis", group: "Atemwege & HNO" },
  { k: "Spirometrie (Lungenfunktionsprüfung)", v: "Messung von Lungenvolumen und Atemstrom, bei der der Patient über ein Mundstück in ein Messgerät atmet; Standarduntersuchung bei Asthma und COPD. Wird in der Hausarztpraxis häufig von der MFA durchgeführt, z. B. im Rahmen der DMP-Kontrollen.", syn: "Lungenfunktion, Lungenfunktionstest, kleine Lungenfunktion, Lufu, Spiro, Spirometrie-Untersuchung, Spirometry, Spyrometrie", group: "Atemwege & HNO" },
  { k: "Tinnitus", v: "Wahrnehmung von Ohrgeräuschen wie Pfeifen, Rauschen oder Summen ohne äußere Schallquelle; kann akut oder chronisch sein. Patienten sprechen ihn oft beim Hausarzt an; zur weiteren Abklärung erfolgt meist eine Überweisung zum HNO-Arzt.", syn: "Ohrgeräusche, Ohrensausen, Ohrenklingeln, Ohrenpfeifen, Tinnitus aurium, Tinitus, Tinnitis, Tinnutus", group: "Atemwege & HNO" },
  { k: "Tonsillitis (Mandelentzündung)", v: "Entzündung der Gaumenmandeln mit Halsschmerzen, Schluckbeschwerden und häufig Fieber; Auslöser sind Viren oder Bakterien (v. a. Streptokokken). In der Praxis oft Anlass für einen Streptokokken-Schnelltest, der meist von der MFA durchgeführt wird.", syn: "Mandelentzündung, Angina tonsillaris, Angina, eitrige Angina, Streptokokken-Angina, Tonsilitis, Tonsillits, Tonzillitis", group: "Atemwege & HNO" },
  { k: "Zerumen (Ohrenschmalz)", v: "Natürliches Sekret des äußeren Gehörgangs, das diesen reinigt und schützt; ein verhärteter Pfropf kann den Gehörgang verschließen und zu Hörminderung oder Druckgefühl führen. Die Ohrspülung zur Entfernung ist eine typische, oft an die MFA delegierte Leistung in der Hausarztpraxis.", syn: "Ohrenschmalz, Cerumen, Ohrschmalzpfropf, Zeruminalpfropf, Cerumen obturans, Ohrpfropf, Ceruminalpfropf, Zerumem", group: "Atemwege & HNO" },

  // ===== Verdauung & Stoffwechsel =====
  { k: "Adipositas (Fettleibigkeit)", v: "Krankhaftes Übergewicht ab einem Body-Mass-Index (BMI) von 30; wichtiger Risikofaktor für Diabetes, Bluthochdruck sowie Gelenk- und Herz-Kreislauf-Erkrankungen. In der Praxis relevant bei Beratung, Check-up und DMP-Programmen.", syn: "Fettleibigkeit, Fettsucht, starkes Übergewicht, Obesitas, BMI, Adipositas Grad I bis III, Adiposität, Adipositass", group: "Verdauung & Stoffwechsel" },
  { k: "Appendizitis (Blinddarmentzündung)", v: "Entzündung des Wurmfortsatzes (Appendix) am Blinddarm, typisch mit Schmerzen, die vom Nabel in den rechten Unterbauch wandern, oft mit Fieber und Übelkeit. In der Praxis ein Notfallverdacht, der meist eine rasche Klinikeinweisung nach sich zieht.", syn: "Blinddarmentzündung, Wurmfortsatzentzündung, Appendicitis, Appendix, Blinddarm, Blinddarmreizung, Apendizitis, Appendezitis", group: "Verdauung & Stoffwechsel" },
  { k: "Cholezystitis (Gallenblasenentzündung)", v: "Entzündung der Gallenblase, meist als Folge von Gallensteinen, mit Schmerzen im rechten Oberbauch und häufig Fieber. In der Hausarztpraxis wichtiger Abklärungsgrund mit Ultraschall und Laborwerten.", syn: "Gallenblasenentzündung, Cholecystitis, akute Cholezystitis, Gallenentzündung, Kolezystitis, Cholezystitiss, Cholezystektomie (operative Gallenblasenentfernung)", group: "Verdauung & Stoffwechsel" },
  { k: "Cholezystolithiasis (Gallensteine)", v: "Steinbildung in der Gallenblase, die oft lange keine Beschwerden macht; klemmt ein Stein ein, kommt es zur heftigen, wellenartigen Gallenkolik im rechten Oberbauch. Häufiger Zufallsbefund bei der Ultraschalluntersuchung.", syn: "Gallensteine, Gallensteinleiden, Cholelithiasis, Gallenkolik, Gallensteinkolik, Konkremente, Steinleiden, Choledocholithiasis (Stein im Gallengang), Kolelithiasis", group: "Verdauung & Stoffwechsel" },
  { k: "Diabetes mellitus Typ 2 (Zuckerkrankheit)", v: "Chronische Stoffwechselerkrankung mit dauerhaft erhöhtem Blutzucker, weil das körpereigene Insulin nicht mehr ausreichend wirkt (Insulinresistenz). Eine der häufigsten Erkrankungen in der Hausarztpraxis, meist im DMP betreut und über Blutzucker- und HbA1c-Werte kontrolliert.", syn: "Zuckerkrankheit, Typ-2-Diabetes, Diabetes Typ II, Altersdiabetes (veraltet), Insulinresistenz, Blutzuckerkrankheit, Diabetis, Diabethes", group: "Verdauung & Stoffwechsel" },
  { k: "Divertikulitis (Divertikelentzündung)", v: "Entzündung von Ausstülpungen der Dickdarmwand (Divertikel), meist im linken Unterbauch im S-förmigen Darmabschnitt (Sigma). Häufig bei älteren Patienten; typisch sind linksseitige Unterbauchschmerzen, Fieber und erhöhte Entzündungswerte im Labor.", syn: "Divertikelentzündung, Sigmadivertikulitis, Divertikel, Divertikulose (Ausstülpungen ohne Entzündung), Diverticulitis, Divertikulits, Divertikulitiss", group: "Verdauung & Stoffwechsel" },
  { k: "Fettleber (Steatosis hepatis)", v: "Vermehrte Einlagerung von Fett in den Leberzellen, meist durch Übergewicht, Diabetes oder Alkohol. Häufiger Zufallsbefund bei Ultraschall oder erhöhten Leberwerten; kann in eine Leberentzündung übergehen.", syn: "Steatosis hepatis, Leberverfettung, Steatose, nichtalkoholische Fettleber, NAFLD, MASLD, alkoholische Fettleber, Steatohepatitis (Fettleberentzündung), Fettleberhepatitis", group: "Verdauung & Stoffwechsel" },
  { k: "Gastritis (Magenschleimhautentzündung)", v: "Entzündung der Magenschleimhaut, z. B. durch das Bakterium Helicobacter pylori, Schmerzmittel, Stress oder Autoimmunprozesse. Häufiger Grund für Oberbauchschmerzen in der Hausarztpraxis; die Abklärung erfolgt oft per Magenspiegelung.", syn: "Magenschleimhautentzündung, Magenentzündung, akute Gastritis, chronische Gastritis, Typ-A-Gastritis, Typ-B-Gastritis, Typ-C-Gastritis, Gastrittis, Gastritiss, Kastritis", group: "Verdauung & Stoffwechsel" },
  { k: "Gastroskopie (Magenspiegelung)", v: "Endoskopische Untersuchung von Speiseröhre, Magen und Zwölffingerdarm, meist bei Sodbrennen, Oberbauchschmerzen, Schluckbeschwerden oder Blutungsverdacht. Patienten müssen nüchtern erscheinen; die Praxis organisiert Überweisung und Befundrücklauf.", syn: "Magenspiegelung, ÖGD, Ösophago-Gastro-Duodenoskopie, Gastro, Gastroscopie, Speiseröhren- und Magenspiegelung, Kastroskopie", group: "Verdauung & Stoffwechsel" },
  { k: "Helicobacter pylori", v: "Bakterium, das die Magenschleimhaut besiedelt und Magenschleimhautentzündungen sowie Magen- und Zwölffingerdarmgeschwüre verursachen kann. Der Nachweis erfolgt per Atemtest, Stuhltest oder Magenspiegelung; häufiger Begriff in Arztbriefen und Befunden.", syn: "Helicobacter, H. pylori, HP, Magenkeim, Magenbakterium, HP-Eradikation (Keimbeseitigung), Helicobacter-Atemtest, Heliobacter, Helikobakter, Helicobakter", group: "Verdauung & Stoffwechsel" },
  { k: "Hepatitis (Leberentzündung)", v: "Entzündung der Leber durch Viren (Hepatitis A bis E), Alkohol, Medikamente oder Autoimmunprozesse. In der Praxis relevant bei erhöhten Leberwerten, bei der Impfberatung (Hepatitis A/B) und weil Virushepatitiden meldepflichtig sind.", syn: "Leberentzündung, Virushepatitis, Hepatitis A, Hepatitis B, Hepatitis C, Leberwerte, Hepatits, Heppatitis, Hepatitis-Impfung", group: "Verdauung & Stoffwechsel" },
  { k: "Hyperthyreose (Schilddrüsenüberfunktion)", v: "Überfunktion der Schilddrüse mit zu viel Schilddrüsenhormon; typisch sind Herzrasen, Gewichtsabnahme, innere Unruhe und Schwitzen. Fällt im Praxisalltag oft über einen erniedrigten TSH-Wert im Labor auf.", syn: "Schilddrüsenüberfunktion, Überfunktion der Schilddrüse, Morbus Basedow, Schilddrüsenautonomie, Hyperthyreoidismus, TSH erniedrigt, Hypertyreose, Hyperthreose", group: "Verdauung & Stoffwechsel" },
  { k: "Hypothyreose (Schilddrüsenunterfunktion)", v: "Unterfunktion der Schilddrüse mit zu wenig Schilddrüsenhormon; typisch sind Müdigkeit, Gewichtszunahme, Frieren und Antriebslosigkeit. Häufige Ursache ist die Autoimmunerkrankung Hashimoto; die Kontrolle läuft über den TSH-Wert.", syn: "Schilddrüsenunterfunktion, Unterfunktion der Schilddrüse, Hashimoto-Thyreoiditis, Hypothyreoidismus, TSH erhöht, Hypotyreose, Hypothreose", group: "Verdauung & Stoffwechsel" },
  { k: "Hämorrhoiden (Hämorrhoidalleiden)", v: "Krankhaft vergrößerte Gefäßpolster am Übergang von Enddarm zu After, die jucken, nässen oder hellrot bluten können. Häufiger, oft schambesetzter Beratungsanlass; Blut im Stuhl muss trotzdem immer ärztlich abgeklärt werden.", syn: "Hämorrhoidalleiden, Hämoriden, Hämorriden, Hemorrhoiden, Haemorrhoiden, vergrößerte Gefäßpolster am After, Blut im Stuhl, Analbeschwerden", group: "Verdauung & Stoffwechsel" },
  { k: "Ikterus (Gelbsucht)", v: "Gelbfärbung von Haut und Augenweiß durch erhöhtes Bilirubin (Gallenfarbstoff) im Blut, z. B. bei Leber- oder Gallenwegserkrankungen. Ein Ikterus ist ein Symptom, keine eigene Krankheit, und muss immer abgeklärt werden.", syn: "Gelbsucht, Gelbfärbung von Haut und Augen, Sklerenikterus, Bilirubinerhöhung, Icterus, Ikteruss, Gelbverfärbung", group: "Verdauung & Stoffwechsel" },
  { k: "Ileus (Darmverschluss)", v: "Unterbrechung der Darmpassage, entweder durch ein Hindernis (mechanischer Ileus) oder eine Darmlähmung (paralytischer Ileus), mit Erbrechen, Bauchschmerzen und Stuhlverhalt. Akuter Notfall, der eine sofortige Klinikeinweisung erfordert.", syn: "Darmverschluss, mechanischer Ileus, paralytischer Ileus, Darmlähmung, Subileus (unvollständiger Darmverschluss), Illeus, Ileuss", group: "Verdauung & Stoffwechsel" },
  { k: "Koloskopie (Darmspiegelung)", v: "Endoskopische Untersuchung des Dickdarms mit einem beweglichen Schlauch mit Kamera, auch als Vorsorgeuntersuchung zur Darmkrebsfrüherkennung. In der Praxis häufige Aufgabe: Überweisung ausstellen, über die Abführ-Vorbereitung informieren und Befunde nachhalten.", syn: "Darmspiegelung, Kolo, Kolonoskopie, Coloskopie, Colonoskopie, Vorsorgekoloskopie, Darmkrebsvorsorge, Polypenabtragung, Darmspiegelung Vorbereitung", group: "Verdauung & Stoffwechsel" },
  { k: "Laktoseintoleranz (Milchzuckerunverträglichkeit)", v: "Unverträglichkeit von Milchzucker durch einen Mangel am Verdauungsenzym Laktase, mit Blähungen, Bauchschmerzen und Durchfall nach Milchprodukten. Der Nachweis erfolgt meist über einen H2-Atemtest; häufiges Beratungsthema in der Praxis.", syn: "Milchzuckerunverträglichkeit, Laktosemalabsorption, Laktasemangel, Milchunverträglichkeit, H2-Atemtest, Lactoseintoleranz, Laktose-Intoleranz, Lactose", group: "Verdauung & Stoffwechsel" },
  { k: "Metabolisches Syndrom", v: "Kombination aus bauchbetontem Übergewicht, Bluthochdruck, erhöhtem Blutzucker und Fettstoffwechselstörung, die zusammen das Risiko für Herzinfarkt, Schlaganfall und Diabetes deutlich erhöhen. Zentrales Thema bei Check-up-Untersuchungen und in der DMP-Betreuung.", syn: "Wohlstandssyndrom, tödliches Quartett, Insulinresistenz-Syndrom, Syndrom X, Stoffwechselsyndrom, metabolische Syndrom", group: "Verdauung & Stoffwechsel" },
  { k: "Pankreatitis (Bauchspeicheldrüsenentzündung)", v: "Entzündung der Bauchspeicheldrüse, häufig ausgelöst durch Gallensteine oder Alkohol; typisch sind gürtelförmig ausstrahlende Oberbauchschmerzen. Die akute Form ist ein Notfall; im Labor ist vor allem der Lipase-Wert erhöht.", syn: "Bauchspeicheldrüsenentzündung, akute Pankreatitis, chronische Pankreatitis, Pancreatitis, Pankreas (Bauchspeicheldrüse), Lipase-Erhöhung, Pankreatits, Pankreatitiss", group: "Verdauung & Stoffwechsel" },
  { k: "Podagra (akuter Gichtanfall der Großzehe)", v: "Akuter Gichtanfall am Großzehengrundgelenk mit plötzlichen, sehr heftigen Schmerzen, Rötung und Schwellung, ausgelöst durch Harnsäurekristalle im Gelenk. Klassischer Akuttermin in der Hausarztpraxis; im Labor wird meist die Harnsäure kontrolliert.", syn: "Gichtanfall, akuter Gichtanfall, Gicht, Arthritis urica, Hyperurikämie (erhöhte Harnsäure), Zipperlein (umgangssprachlich), Potagra, Podraga", group: "Verdauung & Stoffwechsel" },
  { k: "Refluxkrankheit (Sodbrennen)", v: "Rückfluss von saurem Mageninhalt in die Speiseröhre, der Sodbrennen und saures Aufstoßen verursacht und die Schleimhaut reizen kann. Sehr häufiger Beratungsanlass; bei anhaltenden Beschwerden wird meist eine Magenspiegelung veranlasst.", syn: "Sodbrennen, Reflux, gastroösophageale Refluxkrankheit, GERD, Refluxösophagitis, saures Aufstoßen, Speiseröhrenentzündung, Refluks, Reflux-Krankheit", group: "Verdauung & Stoffwechsel" },
  { k: "Reizdarmsyndrom (Colon irritabile)", v: "Funktionelle Darmstörung mit Bauchschmerzen, Blähungen, Durchfall und/oder Verstopfung, ohne dass eine organische Ursache gefunden wird. Die Diagnose wird erst nach Ausschluss anderer Erkrankungen gestellt, daher gehören dazu oft mehrere Abklärungstermine.", syn: "Reizdarm, Colon irritabile, irritables Darmsyndrom, RDS, IBS, nervöser Darm, funktionelle Darmbeschwerden, Reitzdarm", group: "Verdauung & Stoffwechsel" },
  { k: "Struma (Kropf)", v: "Vergrößerung der Schilddrüse, häufig durch Jodmangel; sie kann mit oder ohne Knoten auftreten und am Hals tastbar oder sichtbar sein. Die Abklärung erfolgt meist mit dem TSH-Wert im Blut und einer Ultraschalluntersuchung.", syn: "Kropf, Schilddrüsenvergrößerung, Struma nodosa (mit Knoten), Struma diffusa, Jodmangelstruma, Schilddrüsenknoten, Struhma", group: "Verdauung & Stoffwechsel" },
  { k: "Ulkus (Magen-/Zwölffingerdarmgeschwür)", v: "Ein Ulkus ist ein tiefer Substanzdefekt der Magen- oder Zwoelffingerdarmwand, der ueber die Schleimhaut hinaus mindestens in die darunterliegende Submukosa reicht. Bleibt der Defekt auf die oberflaechliche Schleimhaut beschraenkt, spricht man dagegen von einer Erosion.", syn: "Geschwür, Magengeschwür, Ulcus ventriculi, Zwölffingerdarmgeschwür, Ulcus duodeni, peptisches Ulkus, Ulkuskrankheit, Ulzera, Ulcus, Ulkuss", group: "Verdauung & Stoffwechsel" },
  { k: "Zöliakie (Glutenunverträglichkeit)", v: "Autoimmunerkrankung, bei der Gluten (Klebereiweiß in Weizen, Roggen, Gerste) die Dünndarmschleimhaut schädigt; Folgen sind u. a. Durchfall, Blähungen und Nährstoffmangel. Abklärung über Antikörper im Blut und eine Gewebeprobe aus dem Dünndarm.", syn: "Glutenunverträglichkeit, glutensensitive Enteropathie, einheimische Sprue, Gluten, Transglutaminase-Antikörper, Zoeliakie, Zölliakie, Cöliakie, Coeliakie", group: "Verdauung & Stoffwechsel" },

  // ===== Nerven & Psyche =====
  { k: "Angststörung", v: "Übermäßige, anhaltende Angst ohne entsprechende reale Gefahr; Formen sind u. a. die generalisierte Angststörung, die Panikstörung mit plötzlichen Panikattacken und Phobien. Patienten stellen sich oft zuerst mit körperlichen Beschwerden wie Herzrasen, Engegefühl oder Atemnot vor.", syn: "generalisierte Angststörung, GAS, Panikstörung, Panikattacke, Panikanfall, Phobie, soziale Phobie, Agoraphobie, Platzangst, Angstattacke, Herzangst, Angsstörung", group: "Nerven & Psyche" },
  { k: "Burnout", v: "Zustand tiefer körperlicher und seelischer Erschöpfung infolge lang anhaltender (meist beruflicher) Überlastung. Burnout ist keine eigenständige Krankheitsdiagnose, sondern wird im ICD-10 unter Z73 (Probleme mit Bezug auf Schwierigkeiten bei der Lebensbewältigung) verschlüsselt; das ist z. B. für AU-Bescheinigungen relevant.", syn: "Burn-out, Burnout-Syndrom, Ausgebranntsein, Erschöpfungssyndrom, chronische Erschöpfung, Überlastungssyndrom, ausgebrannt, Bornout, Burn out", group: "Nerven & Psyche" },
  { k: "Demenz", v: "Fortschreitender Verlust geistiger Fähigkeiten wie Gedächtnis, Orientierung und Urteilsvermögen; die häufigste Form ist die Alzheimer-Krankheit. In der Hausarztpraxis werden zur Einschätzung oft Testverfahren wie MMST, DemTect oder Uhrentest durchgeführt, häufig durch die MFA.", syn: "Alzheimer, Morbus Alzheimer, Alzheimer-Krankheit, Alzheimer-Demenz, vaskuläre Demenz, dementielles Syndrom, Altersdemenz, Gedächtnisstörung, MMST, DemTect, Uhrentest, Demens", group: "Nerven & Psyche" },
  { k: "Depression", v: "Psychische Erkrankung mit gedrückter Stimmung, Interessenverlust und Antriebsmangel über mindestens zwei Wochen, oft begleitet von Schlafstörungen und Konzentrationsproblemen. Wird sehr häufig zuerst in der Hausarztpraxis erkannt, u. a. mit Fragebögen wie dem PHQ-9.", syn: "depressive Episode, depressive Störung, Major Depression, Depressionen, Schwermut, Melancholie, Winterdepression, gedrückte Stimmung, PHQ-9, Depri", group: "Nerven & Psyche" },
  { k: "Epilepsie", v: "Erkrankung des Gehirns mit wiederkehrenden Krampfanfällen, die durch plötzliche, übermäßige Entladungen von Nervenzellen entstehen; Anfälle reichen von kurzen Bewusstseinspausen (Absencen) bis zu Krämpfen des ganzen Körpers (Grand mal). In der Praxis relevant u. a. bei Medikamenten-Rezepten, Blutspiegelkontrollen und Fragen zur Fahrtauglichkeit.", syn: "Krampfleiden, Anfallsleiden, epileptischer Anfall, Krampfanfall, Grand-mal-Anfall, fokaler Anfall, Absence, Fallsucht, zerebrales Anfallsleiden, Epilepsi", group: "Nerven & Psyche" },
  { k: "Fazialisparese", v: "Meist einseitige Lähmung des Gesichtsnervs (Nervus facialis) mit hängendem Mundwinkel, herabhängender Wange und unvollständigem Lidschluss. In der Praxis wichtig, weil sie rasch von einem Schlaganfall abgegrenzt werden muss; oft findet sich keine Ursache (idiopathische bzw. Bell-Parese).", syn: "Gesichtslähmung, Gesichtsnervenlähmung, Fazialislähmung, Facialisparese, Bell-Parese, Bell-Lähmung, idiopathische Fazialisparese, hängender Mundwinkel, Faszialisparese, Fazialis", group: "Nerven & Psyche" },
  { k: "Insomnie", v: "Ein- oder Durchschlafstörung mit nicht erholsamem Schlaf und Beeinträchtigung am Tag (Müdigkeit, Konzentrationsprobleme), die über Wochen anhält. Einer der häufigsten Beratungsanlässe in der Hausarztpraxis, oft in Verbindung mit Stress, Depression oder Schmerzen.", syn: "Schlafstörung, Schlaflosigkeit, Einschlafstörung, Durchschlafstörung, Ein- und Durchschlafstörung, nicht erholsamer Schlaf, Insomnia, Imsomnie, Insomie", group: "Nerven & Psyche" },
  { k: "Migräne", v: "Anfallsartiger, oft einseitiger und pulsierender Kopfschmerz, häufig mit Übelkeit sowie Licht- und Lärmempfindlichkeit, teils mit Vorboten (Aura, z. B. Sehstörungen). In der Hausarztpraxis ein sehr häufiger Beratungsanlass, oft mit Kopfschmerztagebuch dokumentiert.", syn: "Migraine, Migräneanfall, Migräneattacke, Hemikranie, Migräne mit Aura, Migräne ohne Aura, einseitiger Kopfschmerz, Migrene, Mikräne", group: "Nerven & Psyche" },
  { k: "Neuralgie", v: "Anfallsartiger, blitzartig einschießender Schmerz im Versorgungsgebiet eines einzelnen Nervs, z. B. Trigeminusneuralgie im Gesicht oder Post-Zoster-Neuralgie nach einer Gürtelrose. Der Begriff taucht häufig in Befunden und Diagnoselisten auf.", syn: "Nervenschmerz, Nervenschmerzen, Trigeminusneuralgie, Post-Zoster-Neuralgie, Interkostalneuralgie, Gesichtsschmerz, Neuralgien, Nevralgie, Neuralgie im Gesicht", group: "Nerven & Psyche" },
  { k: "Parkinson-Krankheit (Morbus Parkinson)", v: "Langsam fortschreitende Gehirnerkrankung durch Mangel am Botenstoff Dopamin, typisch sind Zittern in Ruhe (Tremor), Muskelsteifheit (Rigor), verlangsamte Bewegungen und kleinschrittiger Gang. Patienten werden meist gemeinsam von Hausarzt und Neurologen betreut.", syn: "Morbus Parkinson, Parkinson, Parkinson-Syndrom, idiopathisches Parkinson-Syndrom, IPS, Schüttellähmung, Paralysis agitans, Parkinsonismus, Parkison", group: "Nerven & Psyche" },
  { k: "Polyneuropathie", v: "Erkrankung vieler peripherer Nerven (der Nervenbahnen außerhalb von Gehirn und Rückenmark) mit Kribbeln, Taubheit, Brennen oder Gangunsicherheit, meist zuerst an Füßen und Händen. Häufige Ursachen sind Diabetes und Alkohol; in der Praxis z. B. beim Stimmgabel- und Monofilament-Test im Rahmen der Diabetes-Kontrollen relevant.", syn: "PNP, periphere Neuropathie, diabetische Polyneuropathie, Nervenschädigung, Polyneuropathien, Polineuropathie, Polyneurophatie, Polyneuropatie", group: "Nerven & Psyche" },
  { k: "Restless-Legs-Syndrom", v: "Missempfindungen und starker Bewegungsdrang in den Beinen, die vor allem abends und in Ruhe auftreten und sich durch Bewegung bessern; dadurch häufig gestörter Schlaf. In der Praxis oft Anlass für Blutuntersuchungen (z. B. Eisenwerte), da ein Eisenmangel beteiligt sein kann.", syn: "RLS, Syndrom der unruhigen Beine, unruhige Beine, Restless Legs, Restless-Leg-Syndrom, Willis-Ekbom-Krankheit, Bewegungsdrang der Beine, Restless Legs Syndrom", group: "Nerven & Psyche" },
  { k: "Schlaganfall (Apoplex)", v: "Plötzliche Durchblutungsstörung oder Blutung im Gehirn mit akuten Ausfällen wie halbseitiger Lähmung, hängendem Mundwinkel, Sprach- oder Sehstörungen. Gilt als Notfall; in der Praxis wichtig beim Telefon-Triage-Erkennen typischer Warnzeichen (z. B. FAST-Schema).", syn: "Apoplex, Apoplexie, Hirninfarkt, Insult, zerebraler Insult, Hirnschlag, Gehirnschlag, Stroke, ischämischer Schlaganfall, Hirnblutung, Appoplex, Apolex", group: "Nerven & Psyche" },
  { k: "Schwindel (Vertigo)", v: "Gefühl von Drehen, Schwanken oder Unsicherheit, ausgelöst z. B. durch das Gleichgewichtsorgan im Innenohr, den Kreislauf oder Nervenerkrankungen. Häufige Formen sind Drehschwindel, Schwankschwindel und der gutartige Lagerungsschwindel; ein sehr häufiger Vorstellungsgrund besonders bei älteren Patienten.", syn: "Vertigo, Drehschwindel, Schwankschwindel, Lagerungsschwindel, benigner paroxysmaler Lagerungsschwindel, BPLS, Schwindelattacke, Gleichgewichtsstörung, Wertigo", group: "Nerven & Psyche" },
  { k: "Somatisierung", v: "Körperliche Beschwerden wie Schmerzen, Herz- oder Magen-Darm-Symptome, für die sich keine ausreichende organische Ursache findet und bei denen seelische Belastungen eine wichtige Rolle spielen. Betroffene sind häufige Praxisbesucher, oft mit wechselnden Beschwerdebildern und vielen Voruntersuchungen.", syn: "somatoforme Störung, Somatisierungsstörung, funktionelle Beschwerden, psychosomatische Beschwerden, psychosomatisch, körperliche Beschwerden ohne Befund, Somatisation, somatoform", group: "Nerven & Psyche" },
  { k: "Spannungskopfschmerz", v: "Cephalgie/Zephalgie/Kephalgie ist der unspezifische Oberbegriff fuer Kopfschmerzen aller Art und nicht mit dem Spannungskopfschmerz gleichzusetzen. Als echte Synonyme taugen nur 'Kopfschmerz vom Spannungstyp', 'Spannungskopfschmerzen' bzw. 'Spannungszephalgie'.", syn: "Kopfschmerz vom Spannungstyp, Spannungskopfschmerzen, Cephalgie, Zephalgie, Kephalgie, Kopfschmerz beidseitig, Spannungszephalgie", group: "Nerven & Psyche" },
  { k: "Transitorische ischämische Attacke (TIA)", v: "Vorübergehende Durchblutungsstörung des Gehirns mit schlaganfallähnlichen Symptomen, die sich meist innerhalb von Minuten bis Stunden vollständig zurückbilden. Sie gilt als wichtiges Warnsignal für einen drohenden Schlaganfall und wird daher dringlich abgeklärt.", syn: "TIA, Mini-Schlaganfall, kleiner Schlaganfall, transiente ischämische Attacke, vorübergehende Durchblutungsstörung des Gehirns, Streifung, transitorisch-ischämische Attacke", group: "Nerven & Psyche" },

  // ===== Haut, Allergie & Infektionen =====
  { k: "Abszess", v: "Abgekapselte Eiteransammlung im Gewebe, die als schmerzhafte, geroetete und ueberwaermte Schwellung auffaellt. Haeufiger Vorstellungsgrund in der Hausarztpraxis, oft im Rahmen eines kleinen Eingriffs (Inzision) versorgt.", syn: "Eiterbeule, Eiteransammlung, Abscessus, Abzess, Absess, Abszess, Abszeess, Eiterherd, abgekapselter Eiter", group: "Haut, Allergie & Infektionen" },
  { k: "Anaphylaxie (anaphylaktischer Schock)", v: "Schwerste, rasch verlaufende allergische Reaktion des ganzen Koerpers mit Hautausschlag, Atemnot und Kreislaufversagen, die lebensbedrohlich sein kann. In der Hausarztpraxis ein Notfall, zum Beispiel nach Insektenstich, Nahrungsmittel oder Medikament.", syn: "anaphylaktischer Schock, allergischer Schock, Anaphylaxie, schwere allergische Reaktion, anaphylaktische Reaktion, Anafylaxie, Anaphylaxis, Allergieschock, anaphylaktoide Reaktion", group: "Haut, Allergie & Infektionen" },
  { k: "Antibiotikaresistenz", v: "Faehigkeit von Bakterien, gegen ein oder mehrere Antibiotika unempfindlich zu werden, sodass diese nicht mehr wirken. Wichtiges Thema in der Hausarztpraxis, da unnoetiger oder falscher Antibiotikaeinsatz Resistenzen foerdert.", syn: "Antibiotika-Resistenz, resistente Keime, resistente Bakterien, Multiresistenz, multiresistente Erreger, MRE, Resistenz, Antibiotikaresistenzen, Antibiotika Resistenz", group: "Haut, Allergie & Infektionen" },
  { k: "Borreliose (Lyme-Borreliose)", v: "Durch Zecken uebertragene bakterielle Infektion; ein fruehes Zeichen ist die sich ringfoermig ausbreitende Roetung um den Stich (Wanderroete). Haeufiger Beratungsanlass nach Zeckenstich in der Hausarztpraxis.", syn: "Lyme-Borreliose, Lyme-Krankheit, Borrelien, Borrelia burgdorferi, Wanderroete, Erythema migrans, Boreliose, Borreliose, Borelliose, Zeckenborreliose, Boreliosse", group: "Haut, Allergie & Infektionen" },
  { k: "Ekzem", v: "Sammelbegriff fuer eine nicht ansteckende, entzuendliche Hautveraenderung mit Roetung, Juckreiz, Naessen oder Schuppung. In der Hausarztpraxis einer der haeufigsten Hautvorstellungsgruende, oft ausgeloest durch Kontakt mit Reizstoffen oder Allergenen.", syn: "Dermatitis, Kontaktekzem, Kontaktdermatitis, allergisches Ekzem, Hautausschlag, Exzem, Eksem, Ekzeem, Ekzhem", group: "Haut, Allergie & Infektionen" },
  { k: "Erysipel (Wundrose)", v: "Akute, sich flaechig ausbreitende bakterielle Infektion der Haut (meist durch Streptokokken) mit scharf begrenzter Roetung, Ueberwaermung und oft Fieber, haeufig am Unterschenkel oder im Gesicht. In der Hausarztpraxis ein dringender Vorstellungsgrund, da eine rasche aerztliche Abklaerung wichtig ist.", syn: "Wundrose, Rotlauf, Erysipelas, Erysipel, Errysipel, Erysipl, Erisipel, Streptokokken-Hautinfektion", group: "Haut, Allergie & Infektionen" },
  { k: "FSME (Fruehsommer-Meningoenzephalitis)", v: "Durch Zecken uebertragene Virusinfektion, die eine Entzuendung von Hirnhaeuten und Gehirn ausloesen kann; in bestimmten Regionen (Risikogebieten) verbreitet. In der Hausarztpraxis vor allem als Impfthema relevant.", syn: "Fruehsommer-Meningoenzephalitis, Zeckenimpfung, FSME-Impfung, Hirnhautentzuendung durch Zecken, Fruehsommermeningoenzephalitis, Zeckenenzephalitis, FSME-Virus, F.S.M.E.", group: "Haut, Allergie & Infektionen" },
  { k: "Furunkel", v: "Ein Furunkel ist die tiefe, eitrige Entzuendung eines einzelnen Haarbalgs. Die Follikulitis ist die oberflaechlichere Entzuendung des Haarfollikels (moegliche Vorstufe) und der Karbunkel eine Ansammlung mehrerer zusammenfliessender Furunkel; beide sind abzugrenzende Krankheitsbilder, keine Synonyme.", syn: "Haarbalgentzuendung, Eiterbeule, Furunkulose, Karbunkel, Follikulitis, Furunculus, Furunkl, Furonkel, Furunckel", group: "Haut, Allergie & Infektionen" },
  { k: "Grippaler Infekt (Erkaeltung)", v: "Harmlosere Infektion der oberen Atemwege durch verschiedene Erkaeltungsviren mit Schnupfen, Husten und Halsweh, meist ohne hohes Fieber. Wird oft mit der echten Grippe (Influenza) verwechselt, ist aber deutlich milder; sehr haeufiger Vorstellungsgrund.", syn: "Erkaeltung, Verkuehlung, grippaler Infekt, Erkaeltungskrankheit, banaler Infekt, common cold, Katarrh, grippaler Infeckt, grippaler Effekt", group: "Haut, Allergie & Infektionen" },
  { k: "Herpes simplex (Lippenherpes / Fieberblaeschen)", v: "Durch Herpes-simplex-Viren verursachte, wiederkehrende Blaeschen, meist an den Lippen (Typ 1) oder im Genitalbereich (Typ 2). Anders als die Guertelrose tritt es oft an derselben Stelle immer wieder auf; haeufiger, meist harmloser Vorstellungsgrund.", syn: "Lippenherpes, Fieberblaeschen, Herpesblaeschen, Herpes labialis, Herpes genitalis, HSV, HSV-1, HSV-2, Herpes-simplex-Virus, Herpes Simplex, Herpessimplex", group: "Haut, Allergie & Infektionen" },
  { k: "Herpes zoster (Guertelrose)", v: "Schmerzhafter, meist einseitiger und guertelfoermiger Hautausschlag mit Blaeschen, verursacht durch die Reaktivierung des Windpockenvirus im Koerper. Nicht zu verwechseln mit Lippen- oder Genitalherpes (Herpes simplex); in der Hausarztpraxis wichtig wegen Impfangebot und moeglicher Nervenschmerzen als Folge.", syn: "Guertelrose, Zoster, Varizella-Zoster-Virus, VZV, Gesichtsrose, Kopfrose, Herpes Zoster, Guertel-Rose, Guertelrose Herpes, Zooster, Zoster Herpes", group: "Haut, Allergie & Infektionen" },
  { k: "Influenza (echte Grippe)", v: "Durch Influenzaviren ausgeloeste, oft ploetzlich beginnende Infektion mit hohem Fieber, Gliederschmerzen und starkem Krankheitsgefuehl; verlaeuft meist schwerer als eine Erkaeltung. In der Hausarztpraxis besonders im Winter und als jaehrliches Impfthema wichtig.", syn: "echte Grippe, Grippe, Virusgrippe, Influenca, Influensa, Grippevirus, saisonale Grippe, Influenza-Impfung, Inflenza", group: "Haut, Allergie & Infektionen" },
  { k: "MRSA (Methicillin-resistenter Staphylococcus aureus)", v: "Ein Hautbakterium (Staphylococcus aureus), das gegen viele gaengige Antibiotika unempfindlich geworden ist und vor allem in Kliniken und Pflegeeinrichtungen eine Rolle spielt. In der Hausarztpraxis relevant bei Wundinfektionen, Sanierung und Hygienemassnahmen.", syn: "Methicillin-resistenter Staphylococcus aureus, multiresistenter Staphylococcus aureus, Krankenhauskeim, Staphylokokken, Staph aureus, MRSA-Keim, ORSA, MERSA, EMRSA", group: "Haut, Allergie & Infektionen" },
  { k: "Mykose (Pilzinfektion)", v: "Infektion von Haut, Naegeln oder Schleimhaeuten durch Pilze, zum Beispiel Fusspilz, Nagelpilz oder Hautpilz. Sehr haeufiger Vorstellungsgrund; die Lokalisation wird oft mit lateinischen Begriffen wie Tinea pedis (Fuss) benannt.", syn: "Pilzinfektion, Pilzerkrankung, Hautpilz, Fusspilz, Nagelpilz, Tinea, Tinea pedis, Onychomykose, Dermatomykose, Candidose, Soor, Mikose, Mykoze", group: "Haut, Allergie & Infektionen" },
  { k: "Neurodermitis (atopisches Ekzem)", v: "Chronische, in Schueben verlaufende, nicht ansteckende Hauterkrankung mit trockener, stark juckender Haut, haeufig in Ellenbeugen und Kniekehlen. Beginnt oft im Kindesalter und gehoert zum atopischen Formenkreis (Neigung zu Allergien).", syn: "atopisches Ekzem, atopische Dermatitis, endogenes Ekzem, Neurodermitis constitutionalis, Neurodermatitis, Neurodermitis atopica, Nerodermitis, Neuro-Dermitis, Neurodermities", group: "Haut, Allergie & Infektionen" },
  { k: "Prick-Test (Allergietest)", v: "Der Prick-Test dient dem Nachweis von Soforttyp-Allergien (Typ I) durch Auftropfen und oberflaechliches Anritzen der Haut. Der Epikutantest (Pflaster-/Patch-Test) ist kein Synonym, sondern ein anderes Verfahren zur Abklaerung von Kontaktallergien vom Spaettyp (Typ IV); der Intrakutantest prueft zwar denselben Soforttyp, ist aber eine eigene Technik (Injektion in die Haut) und damit ebenfalls kein Synonym.", syn: "Pricktest, Allergietest, Hauttest, Prick-Testung, Hautpricktest, Allergie-Test, Prik-Test, Prick Test, Intrakutantest, Epikutantest", group: "Haut, Allergie & Infektionen" },
  { k: "Psoriasis (Schuppenflechte)", v: "Chronisch-entzuendliche, nicht ansteckende Hauterkrankung mit scharf begrenzten, geroeteten und silbrig schuppenden Stellen, typisch an Ellenbogen, Knien und Kopfhaut. Kann auch die Gelenke betreffen (Psoriasisarthritis) und wird in der Hausarztpraxis oft langfristig mitbetreut.", syn: "Schuppenflechte, Psoriasis vulgaris, Soriasis, Psoriase, Psoriasisarthritis, Psoriasis-Arthritis, Schuppen-Flechte, Psoriasys", group: "Haut, Allergie & Infektionen" },
  { k: "Rhinitis allergica (Heuschnupfen)", v: "Allergische Entzuendung der Nasenschleimhaut mit Niesen, Fliessschnupfen und juckenden, traenenden Augen, meist ausgeloest durch Pollen, Hausstaubmilben oder Tierhaare. Sehr haeufiger Vorstellungsgrund, oft verbunden mit einer Allergietestung.", syn: "Heuschnupfen, allergischer Schnupfen, Pollenallergie, Rhinitis allergica, Pollinosis, Heufieber, allergische Rhinitis, Rinitis allergica, Rhinitis allergika", group: "Haut, Allergie & Infektionen" },
  { k: "Scharlach (Scarlatina)", v: "Durch bestimmte Streptokokken ausgeloeste Infektion mit Halsentzuendung, hohem Fieber, feinfleckigem Hautausschlag und typischer Himbeerzunge, meist bei Kindern. Haeufig in Kitas und Schulen; relevant wegen der Ansteckungsgefahr.", syn: "Scarlatina, Scharlachfieber, Streptokokken-Scharlach, Scarlach, Scharlak, Schalach, Himbeerzunge, Scarlatine, Scharlach Kinder", group: "Haut, Allergie & Infektionen" },
  { k: "Skabies (Kraetze)", v: "Ansteckende Hauterkrankung durch Kraetzmilben, die sich in die oberste Hautschicht bohren und starken, nachts betonten Juckreiz mit kleinen Gaengen und Blaeschen verursachen. In der Hausarztpraxis besonders relevant bei Ausbruechen in Gemeinschaftseinrichtungen.", syn: "Kraetze, Scabies, Kraetzmilbe, Milbenbefall, Sarcoptes scabiei, Skabies, Skabis, Kraetzemilbe, Kraetze Milben, Scabis", group: "Haut, Allergie & Infektionen" },
  { k: "Streptokokken-Angina (Angina tonsillaris)", v: "Bakterielle Mandelentzuendung durch Streptokokken mit Halsschmerzen, Fieber und eitrigen Belaegen auf den Mandeln, meist ohne Husten oder Schnupfen. Haeufiger Vorstellungsgrund; ein Schnelltest hilft, sie von einer viralen Halsentzuendung zu unterscheiden.", syn: "Angina tonsillaris, Mandelentzuendung, eitrige Angina, Streptokokkenangina, Tonsillitis, A-Streptokokken, Streptokokken-Angine, Strepptokokken, Streptokoken-Angina", group: "Haut, Allergie & Infektionen" },
  { k: "Urtikaria (Nesselsucht)", v: "Juckender Hautausschlag mit fluechtigen Quaddeln, aehnlich wie nach Beruehrung mit Brennnesseln; kann durch Allergien, Infekte, Medikamente oder Kaelte ausgeloest werden. Haeufiger Vorstellungsgrund, meist harmlos, gelegentlich aber Warnzeichen einer allergischen Reaktion.", syn: "Nesselsucht, Nesselfieber, Quaddeln, Urticaria, Urtikarie, Urticaria factitia, Urtikaria, Nessel-Sucht, Urtikharia", group: "Haut, Allergie & Infektionen" },
  { k: "Zeckenstich (Zeckenbiss)", v: "Einstich einer Zecke in die Haut, der Krankheiten wie Borreliose oder FSME uebertragen kann. Sehr haeufiger Vorstellungsgrund im Sommerhalbjahr, meist zur Entfernung der Zecke und zur Beratung ueber Warnzeichen.", syn: "Zeckenbiss, Zecke, Zeckenstich, Zeckenentfernung, Holzbock, Ixodes, Zeckenbiss, Zekenstich, Zeckenstisch, Zeckenbiss entfernen", group: "Haut, Allergie & Infektionen" },

  // ===== Augen & Sehen =====
  { k: "Amblyopie (Schwachsichtigkeit)", v: "Sehschwäche eines Auges, die in der frühen Kindheit entsteht, wenn das Gehirn ein Auge nicht richtig nutzt — etwa durch Schielen oder unbehandelte Fehlsichtigkeit. In der Praxis wichtig bei Kinder-Vorsorgeuntersuchungen (U-Untersuchungen), da sie nur im Kindesalter gut behandelbar ist, z. B. durch Abkleben des starken Auges.", syn: "Schwachsichtigkeit, schwaches Auge, faules Auge, Amblyopi, Ambliopie, Amplyopie, Okklusionsbehandlung, Augenpflaster, Abkleben des Auges, Schielen, Strabismus", group: "Augen & Sehen" },
  { k: "Diabetische Retinopathie", v: "Schädigung der kleinen Netzhautgefäße durch langjährigen Diabetes mellitus, die lange ohne Beschwerden verläuft und unbehandelt das Sehvermögen bedroht. In der Hausarztpraxis wichtig, weil Diabetiker regelmäßig zur Augenhintergrund-Kontrolle an den Augenarzt überwiesen werden (z. B. im Rahmen des DMP Diabetes).", syn: "Retinopathie, Retinopathia diabetica, Netzhautschaden bei Diabetes, diabetischer Augenschaden, Zucker im Auge, Augenhintergrunduntersuchung, Funduskontrolle, Fundusuntersuchung, DMP Diabetes Augenarzt", group: "Augen & Sehen" },
  { k: "Diplopie (Doppelbilder)", v: "Sehen von Doppelbildern, weil beide Augen nicht mehr exakt zusammenarbeiten, etwa durch eine Augenmuskellähmung. Plötzlich aufgetretene Doppelbilder sind ein Warnsymptom (u. a. für Schlaganfall oder Nervenschädigung) und müssen bei Terminvergabe und Triage in der Hausarztpraxis ernst genommen werden.", syn: "Doppelbilder, Doppeltsehen, doppelt sehen, Doppelsehen, Diplopi, Diploie, Bilder verschwimmen doppelt, Augenmuskellähmung, Schielen beim Erwachsenen", group: "Augen & Sehen" },
  { k: "Fremdkörpergefühl im Auge", v: "Gefühl, als sei etwas im Auge — verursacht durch einen tatsächlichen Fremdkörper (z. B. Staub, Metallsplitter beim Flexen), eine oberflächliche Hornhautverletzung oder auch trockene Augen. In der Hausarztpraxis häufiges Anliegen; bei Verdacht auf festsitzende oder eingedrungene Fremdkörper und bei starken Schmerzen erfolgt die Weiterleitung zum Augenarzt.", syn: "Fremdkörper im Auge, Sandkorngefühl, etwas im Auge, Splitter im Auge, Hornhautfremdkörper, Hornhauterosion, Erosio corneae, Kratzen im Auge, Augenreiben, Metallsplitter Auge", group: "Augen & Sehen" },
  { k: "Gerstenkorn (Hordeolum)", v: "Akute, meist bakterielle Entzündung einer Drüse am Augenlid, die sich als schmerzhaftes, gerötetes und oft eitriges Knötchen am Lidrand zeigt. Kommt in der Hausarztpraxis häufig vor und heilt in der Regel von selbst ab.", syn: "Hordeolum, Gerstenkorn am Auge, Hordeolum externum, Hordeolum internum, eitriges Knötchen am Lid, Lidranddrüsenentzündung, Gerstenkorn Augenlid, Urseli", group: "Augen & Sehen" },
  { k: "Glaukom (Grüner Star)", v: "Erkrankung des Sehnervs, häufig mit erhöhtem Augeninnendruck, die unbehandelt schleichend zu Gesichtsfeldausfällen bis zur Erblindung führen kann. In der Hausarztpraxis wichtig bei der Medikamentenanamnese (manche Mittel sind bei Glaukom ungeeignet) und als Notfall beim akuten Glaukomanfall: plötzlich hartes, rotes, schmerzhaftes Auge mit Übelkeit.", syn: "Grüner Star, gruener Star, Glaucom, Glaukoma, erhöhter Augeninnendruck, Augendruck, Glaukomanfall, akuter Glaukomanfall, Engwinkelglaukom, Offenwinkelglaukom, Sehnervschaden", group: "Augen & Sehen" },
  { k: "Hagelkorn (Chalazion)", v: "Derbe, meist schmerzlose Schwellung am Augenlid durch eine verstopfte Talgdrüse (Meibom-Drüse), oft als Folge einer abgelaufenen Entzündung. Anders als das Gerstenkorn typischerweise ohne Rötung und Schmerz; bildet es sich nicht zurück, erfolgt die Überweisung zum Augenarzt.", syn: "Chalazion, Kalazion, Chalacion, Schalazion, Knoten am Augenlid, verstopfte Meibom-Drüse, Meibomdrüse, chronische Liddrüsenentzündung, Hagelkorn am Lid", group: "Augen & Sehen" },
  { k: "Katarakt (Grauer Star)", v: "Trübung der Augenlinse, meist altersbedingt, die zu langsam zunehmendem verschwommenem oder blendempfindlichem Sehen führt. In der Hausarztpraxis häufig Thema bei älteren Patienten, etwa vor der Katarakt-Operation (z. B. OP-Vorbereitung, Befunde, Fahrtauglichkeit). Nicht verwechseln mit Katarrh (Schleimhautentzündung).", syn: "Grauer Star, grauer Star, Cataract, Catarakt, Katarrakt, Linsentrübung, getrübte Linse, Star-Operation, Kataraktoperation, Kunstlinse", group: "Augen & Sehen" },
  { k: "Konjunktivitis (Bindehautentzündung)", v: "Entzündung der Bindehaut des Auges mit Rötung, Brennen, Tränen und oft morgens verklebten Lidern. Häufiger Vorstellungsgrund in der Hausarztpraxis; Auslöser können Viren, Bakterien, Allergien oder Reizungen sein — manche Formen sind sehr ansteckend.", syn: "Bindehautentzündung, rote Augen, Conjunctivitis, Konjunctivitis, Konjunktivits, Bindehautreizung, allergische Konjunktivitis, virale Konjunktivitis, bakterielle Konjunktivitis, gerötetes Auge, verklebte Augen", group: "Augen & Sehen" },
  { k: "Makuladegeneration (AMD)", v: "Die AMD ist eine degenerative Erkrankung der Makula (Ablagerungen/Drusen und Zelluntergang am Ort des schärfsten Sehens), nicht eine \"Verkalkung\" der Netzhaut. \"Netzhautverkalkung\" ist ein laienhafter Fehlbegriff und sollte nicht als Synonym geführt werden.", syn: "AMD, altersbedingte Makuladegeneration, altersabhängige Makuladegeneration, Maculadegeneration, Makula, Macula, gelber Fleck, trockene AMD, feuchte AMD, Netzhautverkalkung, IVOM-Spritzen", group: "Augen & Sehen" },
  { k: "Netzhautablösung (Warnzeichen)", v: "Ablösung der Netzhaut von ihrer Unterlage — ein augenärztlicher Notfall, der unbehandelt zur Erblindung des Auges führen kann. Warnzeichen, die am Telefon oder an der Anmeldung hellhörig machen sollten: plötzliche Lichtblitze, ein Schwarm dunkler Punkte (Rußregen) oder ein Schatten/Vorhang im Gesichtsfeld — solche Patienten gehören umgehend zum Augenarzt.", syn: "Amotio retinae, Ablatio retinae, Amotio, Ablatio, Netzhautabhebung, Lichtblitze, Rußregen, Mouches volantes, fliegende Mücken, schwarze Punkte, Schatten im Gesichtsfeld, aufsteigende Wand, Vorhang vor dem Auge", group: "Augen & Sehen" },
  { k: "Sicca-Syndrom (Trockenes Auge)", v: "Benetzungsstörung des Auges durch zu wenig oder zu schnell verdunstende Tränenflüssigkeit, mit Brennen, Fremdkörpergefühl und paradoxerweise oft auch tränenden Augen. Sehr häufiges Thema in der Hausarztpraxis, z. B. bei Bildschirmarbeit, im Alter, bei bestimmten Medikamenten oder Rheumaerkrankungen (Sjögren-Syndrom).", syn: "trockenes Auge, trockene Augen, Keratoconjunctivitis sicca, Sicca Syndrom, Sikka-Syndrom, Zicka-Syndrom, Benetzungsstörung, Tränenersatzmittel, künstliche Tränen, Office-Eye-Syndrom, Bildschirmauge", group: "Augen & Sehen" },
  { k: "Uveitis", v: "Entzündung der mittleren Augenhaut (Uvea, u. a. Regenbogenhaut und Aderhaut) mit Symptomen wie Augenschmerz, Rötung, Lichtscheu und Sehverschlechterung. In der Hausarztpraxis relevant, weil sie mit rheumatischen und anderen entzündlichen Allgemeinerkrankungen zusammenhängen kann und zügig augenärztlich abgeklärt werden muss.", syn: "Uveítis, Uveitis anterior, Iritis, Iridozyklitis, Regenbogenhautentzündung, Aderhautentzündung, Entzündung im Augeninneren, mittlere Augenhaut", group: "Augen & Sehen" },
  { k: "Visus (Sehschärfe)", v: "Maß für die Sehschärfe eines Auges, angegeben als Zahl (z. B. Visus 1,0 entspricht normaler Sehschärfe). In der Hausarztpraxis wird der Visus mit Sehtafeln geprüft, etwa bei Vorsorgeuntersuchungen von Kindern, Gutachten oder Führerschein-Sehtests.", syn: "Sehschärfe, Sehstärke, Sehleistung, Sehtest, Visusprüfung, Visusbestimmung, Sehprobentafel, Sehzeichentafel, Augentest, Visus 1,0, Wiesus", group: "Augen & Sehen" },

  // ===== Kinder & Jugendliche =====
  { k: "Adenoide (Rachenmandel-Vergrößerung, \"Polypen\")", v: "Vergrößerte Rachenmandel hinter der Nase, umgangssprachlich \"Polypen\": führt bei Kindern zu Mundatmung, Schnarchen, näselnder Sprache und häufigen Mittelohrentzündungen. Abklärung erfolgt beim HNO-Arzt, ggf. mit operativer Entfernung (Adenotomie); mit echten Nasenpolypen Erwachsener nicht identisch.", syn: "Polypen, kindliche Polypen, adenoide Vegetationen, Rachenmandel, Rachenmandelhyperplasie, Adenotomie, Wucherungen Nasenrachen", group: "Kinder & Jugendliche" },
  { k: "ADHS (Aufmerksamkeitsdefizit-Hyperaktivitätsstörung)", v: "Entwicklungsstörung mit Unaufmerksamkeit, Impulsivität und häufig Hyperaktivität; die Diagnose stellen meist Kinder- und Jugendpsychiater oder spezialisierte Ärzte im Schulalter. Praxisrelevant, weil oft verordnete Stimulanzien (z. B. Methylphenidat) unter das Betäubungsmittelgesetz fallen und ein BtM-Rezept erfordern.", syn: "Aufmerksamkeitsdefizit-Hyperaktivitätsstörung, ADS, ADHD, AD(H)S, hyperkinetische Störung, Aufmerksamkeitsstörung, Hyperaktivität, Zappelphilipp, Methylphenidat", group: "Kinder & Jugendliche" },
  { k: "Antipyrese (Fiebersenkung)", v: "Sammelbegriff für fiebersenkende Maßnahmen: Medikamente (Antipyretika, bei Kindern meist als Saft oder Zäpfchen) sowie Hausmittel wie Wadenwickel. Bei Kindern richtet sich die Dosierung streng nach dem Körpergewicht und wird ärztlich festgelegt — häufiges Thema bei Elternanfragen am Telefon.", syn: "Fiebersenkung, Antipyretika, Antipyretikum, fiebersenkende Mittel, Fieberzäpfchen, Fiebersaft, Zäpfchen, Wadenwickel", group: "Kinder & Jugendliche" },
  { k: "Aphthen", v: "Gewoehnliche wiederkehrende Aphthen heissen \"chronisch rezidivierende\" bzw. \"habituelle Aphthen\" und sind nicht ansteckend. \"Stomatitis aphthosa\" (= Mundfaeule) ist die ansteckende HSV-1-Primaerinfektion und darf nicht als Synonym der harmlosen Aphthen gefuehrt werden.", syn: "Aphte, Aphten, Afte, Aften, Stomatitis aphthosa, Mundbläschen, Mundgeschwür, habituelle Aphthen", group: "Kinder & Jugendliche" },
  { k: "Dreimonatskoliken (Säuglingskoliken)", v: "Anfallsartige Schrei- und Unruhephasen mit Blähbauch bei ansonsten gesunden Säuglingen, typisch in den ersten drei bis vier Lebensmonaten. Häufiger Beratungsanlass erschöpfter Eltern; wichtig ist der ärztliche Ausschluss anderer Ursachen.", syn: "Säuglingskoliken, Koliken, Dreimonatskolik, 3-Monats-Koliken, Trimenonkoliken, Blähungskoliken, Schreibaby, Schreikind, Regulationsstörung", group: "Kinder & Jugendliche" },
  { k: "Dreitagefieber (Exanthema subitum)", v: "Harmlose Viruserkrankung (humanes Herpesvirus 6) bei Säuglingen und Kleinkindern: etwa drei Tage hohes Fieber, danach beim Entfiebern ein feiner rosa Hautausschlag. Häufiger Grund für besorgte Elternanrufe, auch weil beim raschen Fieberanstieg Fieberkrämpfe auftreten können.", syn: "Exanthema subitum, Roseola infantum, Sechste Krankheit, 3-Tage-Fieber, Drei-Tage-Fieber, HHV-6, humanes Herpesvirus 6", group: "Kinder & Jugendliche" },
  { k: "Enuresis (Bettnässen)", v: "Wiederholtes Einnässen ab einem Alter, in dem Kinder üblicherweise trocken sind (etwa ab 5 Jahren), meist nachts (Enuresis nocturna). Häufig entwicklungsbedingt; in der Praxis werden organische Ursachen wie Harnwegsinfekt oder Diabetes u. a. per Urinprobe ausgeschlossen.", syn: "Bettnässen, Bettnaessen, Einnässen, nächtliches Einnässen, Enuresis nocturna, Enuresis diurna, Inkontinenz Kind", group: "Kinder & Jugendliche" },
  { k: "Gedeihstörung", v: "Unzureichende Gewichts- oder Größenzunahme eines Säuglings oder Kindes, erkennbar am Abflachen oder Abknicken der Perzentilenkurve. Kann viele Ursachen haben (Ernährung, chronische Erkrankungen, seelische Belastung) und muss ärztlich abgeklärt werden.", syn: "Failure to thrive, Dystrophie, Wachstumsstörung, mangelnde Gewichtszunahme, Untergewicht Kind, Gedeihstoerung", group: "Kinder & Jugendliche" },
  { k: "Hand-Fuß-Mund-Krankheit", v: "Ansteckende Viruserkrankung (meist Coxsackie-Viren) mit schmerzhaften Bläschen im Mund sowie an Handflächen und Fußsohlen, vor allem bei Kita-Kindern im Sommer und Herbst. Verläuft in der Regel harmlos und heilt von selbst ab.", syn: "Hand-Mund-Fuß-Krankheit, HFMK, Hand Fuss Mund, Coxsackie-Virus, Enterovirus, falsche Maul- und Klauenseuche", group: "Kinder & Jugendliche" },
  { k: "Impetigo contagiosa (Borkenflechte)", v: "Hochansteckende bakterielle Hautinfektion (Staphylo- oder Streptokokken) mit nässenden Bläschen und honiggelben Krusten, meist im Gesicht von Kindern. Wegen der Ansteckungsgefahr dürfen betroffene Kinder in der Regel erst nach Abheilung bzw. begonnener Behandlung wieder in Kita oder Schule.", syn: "Borkenflechte, Grindflechte, Eiterflechte, Pustelflechte, Schmierflechte, Impetigo, Impetigo kontagiosa", group: "Kinder & Jugendliche" },
  { k: "J1 (Jugendgesundheitsuntersuchung)", v: "Vorsorgeuntersuchung für Jugendliche von 12 bis 14 Jahren: geprüft werden u. a. Wachstum, Impfstatus, Pubertätsentwicklung und seelische Gesundheit. Die J1 ist Kassenleistung; die spätere J2 (16–17 Jahre) übernehmen nur manche Krankenkassen.", syn: "Jugendgesundheitsuntersuchung, J 1, Jugenduntersuchung, Jugendvorsorge, Jugendcheck, J2", group: "Kinder & Jugendliche" },
  { k: "Meningismus (Nackensteifigkeit)", v: "Schmerzhafte Nackensteifigkeit beim Beugen des Kopfes zur Brust — Warnzeichen einer Hirnhautentzündung (Meningitis); geprüft wird u. a. mit Kernig- und Brudzinski-Zeichen. Ein Kind mit hohem Fieber, Erbrechen, Lichtscheu und Nackensteife ist ein Notfall und muss sofort dem Arzt vorgestellt werden.", syn: "Nackensteifigkeit, Nackensteife, Meningitiszeichen, Meningismuszeichen, Kernig-Zeichen, Brudzinski-Zeichen, Hirnhautentzündung, Meningitisverdacht", group: "Kinder & Jugendliche" },
  { k: "Milchschorf", v: "Milchschorf ist ein oft juckendes, entzuendliches Ekzem und moegliche Fruehform der Neurodermitis. Kopfgneis (seborrhoisches Saeuglingsekzem, \"cradle cap\") ist eine davon getrennte, harmlose, nicht juckende, fettig-gelbliche Verkrustung der Kopfhaut. Beide sind keine Synonyme, sondern gerade zu unterscheiden.", syn: "Crusta lactea, Kopfgneis, Gneis, Säuglingsekzem, atopisches Ekzem Säugling, Milchschorf Baby", group: "Kinder & Jugendliche" },
  { k: "Neugeborenengelbsucht (Neugeborenenikterus)", v: "Gelbfärbung von Haut und Augen bei Neugeborenen durch den Blutabbaustoff Bilirubin; in den ersten Lebenstagen meist harmlos und vorübergehend. Bei ausgeprägten oder anhaltenden Verläufen wird der Bilirubinwert kontrolliert, ggf. erfolgt eine Lichttherapie (Fototherapie) in der Klinik.", syn: "Neugeborenenikterus, Icterus neonatorum, Ikterus, Hyperbilirubinämie, Gelbsucht Baby, physiologischer Ikterus, Fototherapie", group: "Kinder & Jugendliche" },
  { k: "Perzentilen (Wachstumskurven)", v: "Die 50. Perzentile ist der Median: Die Haelfte der gleichaltrigen Kinder liegt darueber, die andere Haelfte darunter. Sie markiert den mittleren (typischen) Wert, ist aber nicht per Definition der rechnerische Durchschnitt/Mittelwert.", syn: "Perzentile, Perzentilenkurve, Perzentilkurve, Wachstumskurve, Somatogramm, Percentile, Normkurve", group: "Kinder & Jugendliche" },
  { k: "Ringelröteln (Erythema infectiosum)", v: "Viruserkrankung durch Parvovirus B19 mit girlandenförmigem Ausschlag an Armen und Beinen und typisch geröteten Wangen (\"Ohrfeigengesicht\"); nicht identisch mit Röteln. Wichtig für die Praxis: Kontakt kann für Schwangere ohne Immunschutz gefährlich für das ungeborene Kind sein.", syn: "Erythema infectiosum, Fünfte Krankheit, Parvovirus B19, Ohrfeigenkrankheit, Ringel-Röteln, Ringelrötheln", group: "Kinder & Jugendliche" },
  { k: "Soor (Mundsoor)", v: "Pilzinfektion der Mundschleimhaut (Hefepilz Candida) mit weißlichen, abwischbaren Belägen, besonders häufig bei Säuglingen; im Windelbereich spricht man von Windelsoor. Bei Erwachsenen tritt Soor z. B. nach Antibiotika oder unter kortisonhaltigen Asthmasprays auf.", syn: "Mundsoor, Mundpilz, Candidose, Kandidose, Candidiasis, Candida albicans, Windelsoor, Soorbeläge, Mundsohr", group: "Kinder & Jugendliche" },
  { k: "U-Untersuchungen (U1–U9)", v: "Gesetzlich vorgesehene Früherkennungsuntersuchungen für Kinder von der Geburt (U1) bis zum Vorschulalter (U9), dokumentiert im gelben Kinderuntersuchungsheft. In der Hausarztpraxis wichtig für Terminplanung, Erinnerung der Eltern und Abrechnung, wenn die Praxis Kinder mitbetreut.", syn: "Vorsorgeuntersuchung, Früherkennungsuntersuchung Kinder, Kindervorsorge, U1, U2, U3, U4, U5, U6, U7, U7a, U8, U9, Gelbes Heft, U-Heft, Kinderuntersuchungsheft", group: "Kinder & Jugendliche" },
  { k: "Windpocken (Varizellen)", v: "Hochansteckende Viruserkrankung (Varizella-Zoster-Virus) mit Fieber und stark juckenden Bläschen in verschiedenen Stadien nebeneinander (\"Sternenhimmel\"). Verdachtsfälle sollten wegen der Ansteckungsgefahr nicht ins volle Wartezimmer; das Virus bleibt im Körper und kann später Gürtelrose auslösen.", syn: "Varizellen, Varicella, Varizella-Zoster-Virus, VZV, Wasserpocken, Spitzblattern, Schafblattern, Feuchtblattern, wilde Blattern", group: "Kinder & Jugendliche" },

  // ===== Urologie, Gynäkologie & Hormone =====
  { k: "Belastungsinkontinenz (Stressinkontinenz)", v: "Urinverlust bei körperlicher Belastung wie Husten, Niesen oder Heben, weil der Blasenverschluss (Beckenboden und Schließmuskel) nicht ausreichend hält. Kommt besonders häufig bei Frauen nach Geburten oder in den Wechseljahren vor.", syn: "Stressinkontinenz, Stress-Inkontinenz, Belastungs-Inkontinenz, Urinverlust beim Husten, Beckenbodenschwäche, Belastungsinkontinez", group: "Urologie, Gynäkologie & Hormone" },
  { k: "Benigne Prostatahyperplasie (gutartige Prostatavergrößerung)", v: "Gutartige Vergrößerung der Vorsteherdrüse (Prostata) bei älteren Männern, die zu abgeschwächtem Harnstrahl, nächtlichem Wasserlassen und Restharngefühl führen kann. Häufiger Diktat- und Befundbegriff, oft abgekürzt als BPH oder BPS (benignes Prostatasyndrom).", syn: "BPH, Prostatahyperplasie, Prostatavergrößerung, benignes Prostatasyndrom, BPS, Prostataadenom, gutartige Prostatavergrößerung, Prostatahüperplasie", group: "Urologie, Gynäkologie & Hormone" },
  { k: "Dranginkontinenz (überaktive Blase)", v: "Plötzlicher, kaum unterdrückbarer Harndrang mit unwillkürlichem Urinverlust, weil sich der Blasenmuskel ungewollt zusammenzieht. Taucht in Befunden oft zusammen mit den Begriffen Reizblase oder überaktive Blase (OAB) auf.", syn: "Urge-Inkontinenz, Urgeinkontinenz, überaktive Blase, Reizblase, OAB, imperativer Harndrang, Dranginkontinez", group: "Urologie, Gynäkologie & Hormone" },
  { k: "Endometriose", v: "Chronische Erkrankung, bei der gebärmutterschleimhautähnliches Gewebe außerhalb der Gebärmutter wächst und starke, oft zyklusabhängige Unterbauchschmerzen verursachen kann. Wird in der Hausarztpraxis häufig von Patientinnen genannt oder steht in gynäkologischen Befundberichten.", syn: "Endometriose-Herde, Endometriosis, Endometroise, Endomitriose, zyklusabhängige Unterbauchschmerzen, schmerzhafte Regelblutung, Dysmenorrhoe", group: "Urologie, Gynäkologie & Hormone" },
  { k: "Gestationsdiabetes (Schwangerschaftsdiabetes)", v: "Erstmals in der Schwangerschaft auftretende Blutzuckererhöhung, die meist über einen Zuckerbelastungstest (oGTT) entdeckt wird und sich nach der Geburt oft wieder normalisiert. Betroffene Frauen haben später ein erhöhtes Risiko für Typ-2-Diabetes, daher sind Nachkontrollen in der Hausarztpraxis üblich.", syn: "Schwangerschaftsdiabetes, Gestationsdiabetes mellitus, GDM, Schwangerschaftszucker, Zuckerbelastungstest, oGTT, Gestationsdiabethes", group: "Urologie, Gynäkologie & Hormone" },
  { k: "Harninkontinenz (Blasenschwäche)", v: "Unwillkürlicher Urinverlust; Oberbegriff für verschiedene Formen wie Belastungs-, Drang- und Mischinkontinenz. In der Hausarztpraxis häufiges, oft schambesetztes Thema, das bei der Anamnese und bei Verordnungen von Hilfsmitteln (z. B. Vorlagen) auftaucht.", syn: "Inkontinenz, Blasenschwäche, unwillkürlicher Urinabgang, Urininkontinenz, Mischinkontinenz, Inkontinez, Harninkontinez", group: "Urologie, Gynäkologie & Hormone" },
  { k: "Hormonstatus", v: "Laboruntersuchung mehrerer Hormonwerte im Blut (z. B. Östrogen, FSH, LH, Testosteron, Schilddrüsenwerte), etwa bei Wechseljahresbeschwerden, Zyklusstörungen oder Kinderwunsch. Für die MFA wichtig: Viele Werte sind zyklusabhängig, daher gehört der Zyklustag mit auf den Laborauftrag.", syn: "Hormonprofil, Hormonwerte, Hormonspiegel, Hormonuntersuchung, Hormonlabor, Hormondiagnostik, FSH, LH, Östradiol, Testosteron", group: "Urologie, Gynäkologie & Hormone" },
  { k: "Hypoglykämie (Unterzuckerung)", v: "Zu niedriger Blutzucker (meist unter etwa 70 mg/dl bzw. 3,9 mmol/l) mit Zittern, Schwitzen und Heißhunger bis hin zu Bewusstlosigkeit; betrifft vor allem Diabetiker unter Insulin oder bestimmten Tabletten. In der Praxis ein Notfallstichwort, bei dem sofort ärztliche Hilfe geholt wird.", syn: "Unterzuckerung, Unterzucker, Hypo, niedriger Blutzucker, Hypoglycämie, Hypoglykemie, Hüpoglykämie", group: "Urologie, Gynäkologie & Hormone" },
  { k: "Hämaturie (Blut im Urin)", v: "Blut im Urin – entweder sichtbar (Makrohämaturie) oder nur im Teststreifen bzw. Mikroskop nachweisbar (Mikrohämaturie). Häufiger Befund im Urinstatus, der ärztlich abgeklärt wird, etwa bei Infekt, Steinen oder zum Ausschluss eines Tumors.", syn: "Blut im Urin, Mikrohämaturie, Makrohämaturie, Erythrozyten im Urin, Hematurie, Hämathurie, Hämaturi", group: "Urologie, Gynäkologie & Hormone" },
  { k: "Insulinresistenz", v: "Verminderte Ansprechbarkeit der Körperzellen auf das blutzuckersenkende Hormon Insulin; gilt als Vorstufe und Kernmechanismus des Typ-2-Diabetes und ist oft mit Übergewicht verbunden. Taucht in Befunden häufig zusammen mit Begriffen wie Prädiabetes oder metabolisches Syndrom auf.", syn: "Prädiabetes, metabolisches Syndrom, gestörte Glukosetoleranz, Insulinresistenz-Syndrom, Insulinresistens, Vorstufe Diabetes", group: "Urologie, Gynäkologie & Hormone" },
  { k: "Klimakterium (Wechseljahre)", v: "Hormonelle Übergangsphase der Frau rund um die letzte Regelblutung (Menopause), oft mit Hitzewallungen, Schlafstörungen und Stimmungsschwankungen. Häufiger Beratungsanlass in der Hausarztpraxis, teils mit Bestimmung eines Hormonstatus.", syn: "Wechseljahre, Menopause, Perimenopause, Postmenopause, klimakterische Beschwerden, Wechseljahresbeschwerden, Hitzewallungen, Klimaktherium", group: "Urologie, Gynäkologie & Hormone" },
  { k: "Menstruationszyklus (Zyklus)", v: "Regelmäßiger, hormonell gesteuerter Ablauf zwischen zwei Regelblutungen, im Durchschnitt etwa 28 Tage mit Eisprung ungefähr in der Zyklusmitte. Der Zyklustag ist in der Praxis wichtig für Hormonabnahmen und die Einordnung von Zyklusstörungen.", syn: "Zyklus, Regelblutung, Menstruation, Periode, Monatsblutung, Regel, Mens, Zyklusstörung, Zyklusstörungen, Eisprung, Ovulation", group: "Urologie, Gynäkologie & Hormone" },
  { k: "Nephrolithiasis (Nierensteine)", v: "Steinbildung in Niere oder Harnwegen; wandert ein Stein in den Harnleiter, kann er eine sehr schmerzhafte Nierenkolik (wellenartige Flankenschmerzen) auslösen. Kommt in der Praxis bei akuten Schmerzen oder als Zufallsbefund im Ultraschall vor.", syn: "Nierensteine, Nierenstein, Harnsteine, Urolithiasis, Nierenkolik, Harnleiterstein, Ureterstein, Steinleiden, Nefrolithiasis", group: "Urologie, Gynäkologie & Hormone" },
  { k: "PSA-Wert (prostataspezifisches Antigen)", v: "Blutwert (ein Eiweiß aus der Prostata), der bei Prostatavergrößerung, Entzündung oder Prostatakrebs erhöht sein kann. Wird in der Praxis als Laborwert zur Früherkennung oder Verlaufskontrolle angefordert; als reine Früherkennung ohne Verdacht meist eine Selbstzahlerleistung (IGeL).", syn: "PSA, prostataspezifisches Antigen, Prostatawert, Prostata-Wert, PSA-Test, PSA-Screening, PSA-Bestimmung", group: "Urologie, Gynäkologie & Hormone" },
  { k: "Pyelonephritis (Nierenbeckenentzündung)", v: "Bakterielle Entzündung von Nierenbecken und Nierengewebe, oft als aufgestiegener Harnwegsinfekt, typisch mit Fieber und Flankenschmerz (Schmerz seitlich im Rücken). Gilt als ernster als eine einfache Blasenentzündung und wird in der Praxis zügig ärztlich abgeklärt.", syn: "Nierenbeckenentzündung, oberer Harnwegsinfekt, aufsteigender Harnwegsinfekt, Nierenentzündung, Pyelonephritits, Pyelonefritis, Pülonephritis", group: "Urologie, Gynäkologie & Hormone" },
  { k: "Schilddrüsenknoten (Struma nodosa)", v: "Knotige Veränderung in der Schilddrüse, häufig als Zufallsbefund im Ultraschall; in der Szintigrafie unterscheidet man u. a. \"kalte\" und \"heiße\" Knoten. In Deutschland sehr häufig und meist gutartig; kontrolliert wird per Ultraschall und Laborwerten (z. B. TSH).", syn: "Struma nodosa, Knotenstruma, Struma, Kropf, kalter Knoten, heißer Knoten, Schilddrüsenvergrößerung, Schilddrüsenkonten, Schilddrüsen-Knoten", group: "Urologie, Gynäkologie & Hormone" },
  { k: "Unerfüllter Kinderwunsch (Infertilität)", v: "Wenn trotz regelmäßigem ungeschütztem Verkehr über etwa ein Jahr keine Schwangerschaft eintritt. In der Hausarztpraxis meist Anlass für erste Basisuntersuchungen (z. B. Hormonstatus) und die Überweisung an Gynäkologie, Urologie oder ein Kinderwunschzentrum.", syn: "Kinderwunsch, Infertilität, Sterilität, Unfruchtbarkeit, Fertilitätsstörung, Kinderwunschbehandlung, Kinderwunschzentrum, Infertillität", group: "Urologie, Gynäkologie & Hormone" },
  { k: "Zystitis (Blasenentzündung)", v: "Entzündung der Harnblase, meist durch Bakterien, mit Brennen beim Wasserlassen und häufigem Harndrang. Einer der häufigsten Infekte in der Hausarztpraxis; zur Abklärung wird in der Regel ein Urinstatus (Urin-Schnelltest) gemacht.", syn: "Blasenentzündung, Harnwegsinfekt, Harnwegsinfektion, HWI, unterer Harnwegsinfekt, Cystitis, Zystitits, Cystits, Blaseninfekt, Urozystitis, Blasenkatarrh", group: "Urologie, Gynäkologie & Hormone" },

  // ===== Krebs & Vorsorge =====
  { k: "Benigne / maligne (gutartig / bösartig)", v: "Benigne bedeutet gutartig – eine Wucherung wächst meist langsam und verdrängt Gewebe, streut aber nicht. Maligne bedeutet bösartig – das Gewebe wächst zerstörend ein und kann Absiedlungen (Metastasen) bilden; diese Unterscheidung (Dignität) steht oft im Befund nach einer Gewebeuntersuchung.", syn: "gutartig, bösartig, benign, malign, benigne, maligne, benigne Neubildung, maligne Neubildung, bening (falsch), maligene (falsch), gut- und bösartig, Dignität", group: "Krebs & Vorsorge" },
  { k: "Check-up 35 (Gesundheitsuntersuchung)", v: "Der Check-up 35 ist die gesetzliche Gesundheitsuntersuchung zur Früherkennung von Herz-Kreislauf-, Nieren- und Stoffwechselerkrankungen (u. a. Diabetes), auf die gesetzlich Versicherte ab 35 Jahren alle drei Jahre Anspruch haben. Er ist keine reine Krebsvorsorge, wird in der Praxis aber oft mit Vorsorgeterminen kombiniert.", syn: "Check up 35, Checkup 35, Check-up, Gesundheitsuntersuchung, Gesundheits-Check-up, Gesundheitscheck, GU, Vorsorgeuntersuchung, Ganzkörper-Check", group: "Krebs & Vorsorge" },
  { k: "Chemotherapie", v: "Die Chemotherapie ist eine medikamentöse Krebsbehandlung mit zellwachstumshemmenden Wirkstoffen (Zytostatika), die sich schnell teilende Zellen angreifen. In der Hausarztpraxis geht es meist um Begleitfragen wie Nebenwirkungen oder Blutbildkontrollen zwischen den Behandlungszyklen.", syn: "Chemo, Zytostatika, Zytostatikatherapie, zytostatische Therapie, systemische Therapie, Chemozyklus, Chemotheraphie (falsch), Chemoterapie (falsch)", group: "Krebs & Vorsorge" },
  { k: "Darmkrebsvorsorge (iFOBT / Koloskopie)", v: "Zur Darmkrebsfrüherkennung gehören der immunologische Stuhltest auf verborgenes Blut (iFOBT) und ab bestimmten Altersgrenzen die Darmspiegelung (Koloskopie). Der iFOBT wird häufig in der Hausarztpraxis ausgegeben und ausgewertet.", syn: "Darmkrebsfrüherkennung, Darmkrebsvorsorge, iFOBT, iFOB, FIT, FOBT, immunologischer Stuhltest, Stuhltest auf Blut, Blut-im-Stuhl-Test, Hämoccult, Koloskopie, Darmspiegelung, Vorsorgekoloskopie", group: "Krebs & Vorsorge" },
  { k: "Hautkrebsscreening", v: "Das Hautkrebsscreening ist eine gesetzliche Früherkennungsuntersuchung, bei der die gesamte Haut auf verdächtige Veränderungen abgesucht wird; gesetzlich Versicherte haben ab 35 Jahren alle zwei Jahre Anspruch darauf. Es wird von dafür geschulten Haus- oder Hautärzten durchgeführt.", syn: "Hautkrebs-Screening, Hautscreening, Hautkrebsvorsorge, Muttermalkontrolle, Hautcheck, Melanom-Früherkennung, Hautkrebsvorsorgeuntersuchung, Hautkrebsscrening (falsch)", group: "Krebs & Vorsorge" },
  { k: "Immuntherapie", v: "Die Immuntherapie ist eine Krebsbehandlung, die das körpereigene Abwehrsystem gegen Tumorzellen aktiviert oder unterstützt (z. B. mit sogenannten Checkpoint-Inhibitoren). Sie ist ein neueres Verfahren und wird bei bestimmten Krebsarten eingesetzt.", syn: "Immunonkologie, immunonkologische Therapie, Checkpoint-Inhibitor, Checkpoint-Hemmer, Immuncheckpoint, Antikörpertherapie, Immuntheraphie (falsch)", group: "Krebs & Vorsorge" },
  { k: "Karzinom", v: "Ein Karzinom ist ein bösartiger Tumor, der aus Deck- oder Drüsengewebe (Epithel) entsteht – die häufigste Krebsform, z. B. Brust-, Darm- oder Lungenkarzinom. Es ist von den selteneren Sarkomen (aus Binde- und Stützgewebe) abzugrenzen.", syn: "Carcinom, Karzinome, Ca, CA, Krebs, epithelialer Tumor, Adenokarzinom, Plattenepithelkarzinom, Karcinom (falsch), Carzinom (falsch)", group: "Krebs & Vorsorge" },
  { k: "Krebsnachsorge", v: "Die Nachsorge umfasst regelmäßige Kontrolluntersuchungen nach einer Krebsbehandlung, um ein Wiederauftreten (Rezidiv) frühzeitig zu erkennen und Therapiefolgen zu betreuen. In der Hausarztpraxis werden dafür oft Termine, Befunde und der Nachsorgepass koordiniert.", syn: "Nachsorge, Tumornachsorge, onkologische Nachsorge, Nachsorgeuntersuchung, Kontrolluntersuchung, Follow-up, Nachsorgepass, Nachsorgetermin", group: "Krebs & Vorsorge" },
  { k: "Mammographie-Screening", v: "Das Mammographie-Screening ist eine Röntgen-Reihenuntersuchung der Brust zur Früherkennung von Brustkrebs; gesetzlich versicherte Frauen werden in einem festgelegten Altersfenster regelmäßig eingeladen. Die Einladung kommt über eine zentrale Stelle, nicht über die Hausarztpraxis.", syn: "Mammographie, Mammografie, Mammographie-Screening, Mammografie-Screening, Brustkrebs-Screening, Brustkrebsfrüherkennung, Mammascreening, Röntgen der Brust, Mamographie (falsch)", group: "Krebs & Vorsorge" },
  { k: "Metastase (Tochtergeschwulst)", v: "Eine Metastase ist eine Absiedlung (Tochtergeschwulst) bösartiger Zellen, die sich vom ursprünglichen Tumor über Blut- oder Lymphbahnen an einer anderen Stelle im Körper angesiedelt hat. In Befunden erscheint sie oft als 'M' der TNM-Einteilung oder z. B. als 'ossäre' (Knochen) oder 'hepatische' (Leber) Metastase.", syn: "Metastasen, Tochtergeschwulst, Absiedlung, Filia, Filiae, Fernmetastase, Sekundärtumor, metastasiert, Metastasierung, Metastse (falsch), Methastase (falsch)", group: "Krebs & Vorsorge" },
  { k: "Palliativ vs. kurativ", v: "Kurativ bedeutet, dass eine Behandlung auf Heilung abzielt; palliativ bedeutet, dass eine Heilung nicht mehr möglich ist und die Behandlung Beschwerden lindert sowie die Lebensqualität erhält. Diese Unterscheidung prägt das weitere Vorgehen und die Wortwahl in Arztbriefen.", syn: "palliativ, kurativ, Palliativmedizin, Palliativversorgung, Palliativtherapie, Palliation, kurative Therapie, lindernd, lebensverlängernd, paliativ (falsch), kurrativ (falsch), Hospiz", group: "Krebs & Vorsorge" },
  { k: "PSA-Test", v: "Der PSA-Test misst das prostataspezifische Antigen im Blut, das bei Prostatakrebs, aber auch bei gutartigen Veränderungen erhöht sein kann. Er wird zur Früherkennung meist als Selbstzahlerleistung (IGeL) angeboten und dient außerdem der Verlaufskontrolle.", syn: "PSA, PSA-Wert, PSA-Bestimmung, prostataspezifisches Antigen, Prostatawert, Prostata-Screening, Prostatakrebs-Früherkennung, PSA Test, PSE (falsch)", group: "Krebs & Vorsorge" },
  { k: "Remission / Rezidiv (Rückfall)", v: "Remission bedeutet den Rückgang oder das Verschwinden von Krankheitszeichen – bei vollständiger (kompletter) Remission ist kein Tumor mehr nachweisbar, was aber nicht automatisch dauerhafte Heilung heißt. Ein Rezidiv ist das Wiederauftreten (der Rückfall) der Erkrankung; das Rezidivrisiko bestimmt Umfang und Dauer der Nachsorge.", syn: "Remission, komplette Remission, Vollremission, Teilremission, tumorfrei, Rezidiv, Rückfall, Wiederauftreten, Rezidivrisiko, Rezidivierung, Rezediv (falsch), Remmission (falsch)", group: "Krebs & Vorsorge" },
  { k: "Sarkom", v: "Ein Sarkom ist ein selten auftretender bösartiger Tumor, der aus Binde-, Stütz-, Fett- oder Muskelgewebe entsteht (z. B. an Knochen oder Muskel). Im Gegensatz zum häufigen Karzinom geht es nicht vom Deckgewebe (Epithel) aus.", syn: "Sarkome, Sarcom, Weichteilsarkom, Knochensarkom, Osteosarkom, mesenchymaler Tumor, Sakom (falsch), Sarkohm (falsch)", group: "Krebs & Vorsorge" },
  { k: "Staging und Grading (TNM-Klassifikation)", v: "Staging beschreibt die Ausbreitung eines Tumors (Größe, befallene Lymphknoten, Metastasen), meist über die TNM-Einteilung; Grading beschreibt, wie stark sich die Krebszellen vom normalen Gewebe unterscheiden (G1 bis G4). Beide Angaben stehen im Befund und bestimmen das weitere Vorgehen.", syn: "Staging, Grading, TNM, TNM-Klassifikation, Tumorstadium, Stadieneinteilung, UICC-Stadium, Differenzierungsgrad, G1, G2, G3, G4, Steging (falsch), Greding (falsch)", group: "Krebs & Vorsorge" },
  { k: "Strahlentherapie (Radiotherapie)", v: "Die Strahlentherapie behandelt Tumoren mit gezielter energiereicher Strahlung, um Krebszellen zu zerstören oder am Wachstum zu hindern. Sie wird oft ergänzend zu Operation oder Chemotherapie eingesetzt; in der Praxis kommen häufig Fragen zu Hautreaktionen im Bestrahlungsfeld vor.", syn: "Radiotherapie, Bestrahlung, Radiatio, Strahlenbehandlung, Bestrahlungstherapie, Radiation, Strahlentherpie (falsch), Radioterapie (falsch)", group: "Krebs & Vorsorge" },
  { k: "Tumor (Neoplasie)", v: "Ein Tumor ist eine Gewebeneubildung (Geschwulst), die gut- oder bösartig sein kann; das Wort allein sagt noch nichts über die Bösartigkeit aus. Neoplasie ist der medizinische Fachausdruck für eine solche Neubildung.", syn: "Neoplasie, Neoplasma, Geschwulst, Neubildung, Gewebeneubildung, Raumforderung, Tumore, Tumormasse, Tumór (falsch), Neoplasi (falsch)", group: "Krebs & Vorsorge" },
  { k: "Tumormarker", v: "Tumormarker sind Eiweißstoffe im Blut, deren Wert bei bestimmten Krebsarten erhöht sein kann; sie dienen vor allem der Verlaufs- und Nachsorgekontrolle, nicht der sicheren Diagnosestellung. Bekannte Beispiele sind PSA, CEA oder CA 125.", syn: "Krebsmarker, Verlaufsmarker, Marker, CEA, CA 19-9, CA 125, CA 15-3, PSA, AFP, Tumormaker (falsch)", group: "Krebs & Vorsorge" },
  { k: "Zervix-Screening (PAP-Abstrich)", v: "Beim Zervix-Screening wird zur Früherkennung von Gebärmutterhalskrebs ein Abstrich vom Muttermund entnommen (PAP-Abstrich), je nach Alter ergänzt durch einen HPV-Test. Das Ergebnis wird in PAP-Gruppen (z. B. PAP I bis V) angegeben; die Untersuchung erfolgt meist beim Frauenarzt.", syn: "Zervix-Screening, Zervixkarzinom-Screening, Gebärmutterhalskrebs-Vorsorge, PAP, PAP-Abstrich, Pap-Abstrich, PAP-Test, Papabstrich, Papanicolaou, Zervixabstrich, Krebsabstrich, HPV-Test, Ko-Testung", group: "Krebs & Vorsorge" },

  // ===== Geriatrie & Pflege =====
  { k: "Aspirationspneumonie", v: "Lungenentzündung, die entsteht, wenn Speichel, Nahrung oder Mageninhalt in die Atemwege gelangen — typisch bei Schluckstörungen, etwa nach Schlaganfall, bei Demenz oder Bettlägerigkeit. Häufige und ernste Komplikation bei Pflegeheimbewohnern und geriatrischen Patienten.", syn: "Aspiration, Verschlucken, Schluckstörung, Dysphagie, Lungenentzündung durch Verschlucken, Aspirationspneunomie, Aspirationspneumonie nach Schlaganfall", group: "Geriatrie & Pflege" },
  { k: "Dekubitus (Wundliegen)", v: "Druckgeschwür der Haut und des darunterliegenden Gewebes durch anhaltenden Druck, meist über Knochenvorsprüngen wie Steißbein oder Ferse bei bettlägerigen oder immobilen Patienten. In der Hausarztpraxis häufig bei Hausbesuchen und Wundversorgung; wird in Kategorien/Grade 1 bis 4 eingeteilt.", syn: "Druckgeschwür, Wundliegegeschwür, Dekubitalulkus, Dekubitalgeschwür, Druckulkus, Decubitus, Dekupitus, Dekubitis, Decubitis, wundgelegen", group: "Geriatrie & Pflege" },
  { k: "Delir (akuter Verwirrtheitszustand)", v: "Plötzlich auftretende Verwirrtheit mit gestörter Aufmerksamkeit und wechselndem Bewusstsein, oft ausgelöst durch Infekte, Flüssigkeitsmangel, Medikamente oder einen Krankenhausaufenthalt. Anders als eine Demenz beginnt das Delir akut und ist meist rückbildungsfähig — bei älteren Patienten ein Warnzeichen, das rasch ärztlich abgeklärt werden muss.", syn: "Delirium, Durchgangssyndrom, akute Verwirrtheit, Verwirrtheitszustand, hyperaktives Delir, hypoaktives Delir, Dellir, Delier", group: "Geriatrie & Pflege" },
  { k: "Frailty (Gebrechlichkeit)", v: "Alterssyndrom aus ungewolltem Gewichtsverlust, Schwäche, Erschöpfung, langsamem Gang und geringer körperlicher Aktivität. Gebrechliche Patienten sind deutlich anfälliger für Stürze, Komplikationen und Krankenhausaufenthalte, was bei Therapieentscheidungen berücksichtigt wird.", syn: "Gebrechlichkeit, Frailty-Syndrom, Altersgebrechlichkeit, Fragilität, Frailty Syndrom, Frailität, Freilty", group: "Geriatrie & Pflege" },
  { k: "Geriatrisches Assessment", v: "Strukturierte Untersuchung älterer Patienten mit standardisierten Tests zu Beweglichkeit, Sturzrisiko, Gedächtnis, Alltagsfähigkeiten und Ernährung, z. B. Timed-up-and-go, Uhrentest oder Barthel-Index. In der Hausarztpraxis eine abrechenbare Leistung, bei der MFA Testteile häufig selbst durchführen.", syn: "geriatrisches Basisassessment, hausärztlich-geriatrisches Basisassessment, Alters-Assessment, Barthel-Index, Timed-up-and-go, Uhrentest, Geriatrie-Check, Assessment", group: "Geriatrie & Pflege" },
  { k: "Hausnotruf", v: "Notrufsystem für zu Hause: Per Knopfdruck am Armband oder an der Halskette wird eine Notrufzentrale alarmiert, die Hilfe organisiert — wichtig für alleinlebende, sturzgefährdete Ältere. Bei vorhandenem Pflegegrad übernimmt die Pflegekasse auf Antrag die Grundkosten; die Praxis bescheinigt oft die Notwendigkeit.", syn: "Notrufknopf, Notrufarmband, Seniorennotruf, Hausnotrufsystem, Funkfinger, Notrufkette, Hausnotrufgerät", group: "Geriatrie & Pflege" },
  { k: "Immobilität (Bettlägerigkeit)", v: "Stark eingeschränkte oder aufgehobene Fähigkeit, sich selbstständig zu bewegen, bis hin zur dauerhaften Bettlägerigkeit. Erhöht das Risiko für Dekubitus, Thrombosen, Lungenentzündung und Muskelabbau und ist ein wichtiges Kriterium etwa für Hausbesuche und Verordnungen.", syn: "Bettlägerigkeit, eingeschränkte Mobilität, Mobilitätsverlust, Immobilisation, immobil, gehunfähig, Bewegungseinschränkung, Mobilität", group: "Geriatrie & Pflege" },
  { k: "Kurzzeitpflege", v: "Zeitlich befristete vollstationäre Pflege für meist wenige Wochen, etwa nach einem Krankenhausaufenthalt oder wenn die häusliche Versorgung vorübergehend nicht möglich ist. Der Anspruch läuft über die Pflegeversicherung; die Praxis unterstützt oft mit Attesten und Berichten.", syn: "Kurzzeitpflegeplatz, vorübergehende stationäre Pflege, Übergangspflege, Kurzeitpflege, Pflege nach Krankenhaus", group: "Geriatrie & Pflege" },
  { k: "Medizinischer Dienst (MD)", v: "Begutachtungsdienst der gesetzlichen Kranken- und Pflegekassen, der u. a. Pflegegrade, Hilfsmittel und Arbeitsunfähigkeit prüft; bis 2020 hieß er MDK, bei Privatversicherten übernimmt Medicproof die Pflegebegutachtung. Die Praxis wird regelmäßig um Befundberichte für MD-Gutachten gebeten.", syn: "MDK, Medizinischer Dienst der Krankenversicherung, MD-Gutachten, Pflegebegutachtung, Pflegegutachten, Medicproof, Medizinischer Dienst Bund", group: "Geriatrie & Pflege" },
  { k: "MMST (Mini-Mental-Status-Test)", v: "Kurzer standardisierter Test (maximal 30 Punkte) zur orientierenden Prüfung von Gedächtnis, Orientierung, Sprache und Rechnen bei Verdacht auf eine Demenz. Wird in der Hausarztpraxis oft von MFA mit durchgeführt; verwandte Tests sind Uhrentest, DemTect und MoCA.", syn: "Mini-Mental-Test, MMSE, Mini Mental State Examination, Mini-Mental-Status, Demenztest, Demenz-Screening, kognitives Screening, Minimentaltest", group: "Geriatrie & Pflege" },
  { k: "Patientenverfügung", v: "Schriftliche Festlegung, welche medizinischen Maßnahmen jemand in bestimmten Situationen wünscht oder ablehnt (z. B. Wiederbelebung, künstliche Ernährung), falls er sich selbst nicht mehr äußern kann. Sie ist für Ärzte verbindlich und sollte in der Patientenakte vermerkt sein.", syn: "Patiententestament, Patientenwille, Behandlungswünsche, Verfügung über medizinische Maßnahmen, Patientenverfuegung, Patienten-Verfügung", group: "Geriatrie & Pflege" },
  { k: "Pflegegrad", v: "Einstufung der Pflegebedürftigkeit durch die Pflegeversicherung in fünf Grade, von Grad 1 (geringe) bis Grad 5 (schwerste Beeinträchtigung der Selbstständigkeit); hat 2017 die früheren Pflegestufen abgelöst. Die Hausarztpraxis erstellt dafür häufig Befundberichte für die Begutachtung.", syn: "Pflegestufe, Pflegegrad 1 bis 5, Pflegeeinstufung, Pflegebedürftigkeit, Pflegegradantrag, Höherstufung, Pflegegrat", group: "Geriatrie & Pflege" },
  { k: "Polypharmazie", v: "Dauerhafte gleichzeitige Einnahme vieler Medikamente, häufig definiert ab fünf Wirkstoffen, wodurch bei älteren Patienten das Risiko für Wechsel- und Nebenwirkungen steigt. In der Hausarztpraxis Anlass für regelmäßige Medikationspläne und Medikationschecks.", syn: "Multimedikation, Polymedikation, Vielfachmedikation, viele Medikamente gleichzeitig, Polypharmacie, Poly-Pharmazie", group: "Geriatrie & Pflege" },
  { k: "Priscus-Liste", v: "Liste von Wirkstoffen, die für ältere Menschen potenziell ungeeignet sind, weil Risiken wie Stürze oder Verwirrtheit den Nutzen überwiegen können. Dient dem Arzt als Orientierung beim Überprüfen der Medikation älterer Patienten.", syn: "PRISCUS-Liste, Priscusliste, Priskus-Liste, PIM-Liste, potenziell inadäquate Medikation, ungeeignete Medikamente im Alter", group: "Geriatrie & Pflege" },
  { k: "Sarkopenie", v: "Altersbedingter Verlust an Muskelmasse und Muskelkraft, der zu Schwäche, Gangunsicherheit und erhöhtem Sturzrisiko führt. Spielt in der Hausarztpraxis bei der Beurteilung von Gebrechlichkeit, Ernährung und Sturzgefahr älterer Patienten eine Rolle.", syn: "Muskelschwund im Alter, altersbedingter Muskelabbau, Muskelverlust, Sarcopenie, Sakropenie, Sarkophenie", group: "Geriatrie & Pflege" },
  { k: "Sturzprophylaxe (Sturzrisiko)", v: "Alle Maßnahmen, die Stürze bei älteren Patienten verhindern sollen, z. B. Prüfung sturzfördernder Medikamente, Sehhilfen, Beseitigung von Stolperfallen sowie Kraft- und Gleichgewichtstraining. Das Sturzrisiko wird in der Praxis u. a. im geriatrischen Assessment mit Tests wie dem Timed-up-and-go erfasst.", syn: "Sturzrisiko, Sturzgefahr, Sturzneigung, Fallneigung, Sturzprävention, Fallprophylaxe, Stürze im Alter, Sturzanamnese", group: "Geriatrie & Pflege" },
  { k: "Tagespflege", v: "Tagespflege ist teilstationaer: Betreuung nur tagsueber, abends und nachts wohnt die Person zu Hause. Vollstationaere Einrichtungen wie Pflegeheim/Seniorenheim/Altenheim sind das Kontrastkonzept und kein Synonym der Tagespflege.", syn: "teilstationäre Pflege, Tagesbetreuung, Seniorentagespflege, Tagespflegeeinrichtung, Pflegeheim, vollstationäre Pflege, Seniorenheim, Altenheim", group: "Geriatrie & Pflege" },
  { k: "Verhinderungspflege", v: "Leistung der Pflegekasse, die zeitweise eine Ersatzpflege bezahlt, wenn die private Pflegeperson — meist Angehörige — wegen Urlaub oder Krankheit ausfällt. In der Praxis wird dafür gelegentlich eine ärztliche Bescheinigung angefragt.", syn: "Ersatzpflege, Urlaubspflege, Vertretungspflege, Verhinderungspflegegeld, Verhinderunspflege, Verhinderungs-Pflege", group: "Geriatrie & Pflege" },
  { k: "Vorsorgevollmacht", v: "Dokument, mit dem eine Person für den Fall der eigenen Entscheidungsunfähigkeit einen Bevollmächtigten benennt, der z. B. über Gesundheitsfragen mitentscheiden darf — für die Praxis wichtig, um zu wissen, wer für einen nicht mehr einwilligungsfähigen Patienten sprechen darf. Die verwandte Betreuungsverfügung schlägt dem Betreuungsgericht eine Wunschperson als rechtlichen Betreuer vor, falls keine Vollmacht besteht.", syn: "Betreuungsverfügung, Generalvollmacht, Vollmacht für Gesundheitsangelegenheiten, Bevollmächtigter, gesetzlicher Betreuer, rechtliche Betreuung, Vorsorge-Vollmacht", group: "Geriatrie & Pflege" },

  // ===== Notfall & Leitsymptome =====
  { k: "ABCDE-Schema", v: "Merkschema zur strukturierten Beurteilung von Notfallpatienten: A wie Atemweg, B wie Beatmung/Atmung, C wie Kreislauf (Circulation), D wie neurologischer Zustand (Disability), E wie Ganzkörperuntersuchung (Exposure). Taucht in Notfallprotokollen und Fortbildungen auf und hilft, im Notfall nichts Wichtiges zu übersehen.", syn: "ABCDE, cABCDE, Airway Breathing Circulation Disability Exposure, strukturierte Notfalluntersuchung, Notfallschema, ABC-Schema", group: "Notfall & Leitsymptome" },
  { k: "Akutes Abdomen", v: "Sammelbegriff für plötzliche, heftige Bauchschmerzen mit hartem, druckschmerzhaftem Bauch und schlechtem Allgemeinzustand – mögliche Ursachen sind z. B. Blinddarmentzündung, Darmverschluss oder Magendurchbruch. Gilt bis zum Beweis des Gegenteils als Notfall mit sofortiger Arztvorstellung.", syn: "akuter Bauch, Bauchnotfall, brettharter Bauch, Abwehrspannung, Peritonitis-Zeichen, akute Bauchschmerzen", group: "Notfall & Leitsymptome" },
  { k: "Anaphylaktischer Schock", v: "Der anaphylaktische Schock (Kreislaufversagen, Blutdruckabfall) entspricht Grad III nach Ring und Messmer; Grad IV steht für den Herz-Kreislauf- bzw. Atemstillstand. Das Synonym sollte daher \"anaphylaktischer Schock Grad III\" lauten oder der Grad-Zusatz sollte entfallen.", syn: "Anaphylaxie, allergischer Schock, Allergieschock, anaphylaktische Reaktion, Anafylaxie, anaphylaktischer Schock Grad IV, Schockreaktion Allergie", group: "Notfall & Leitsymptome" },
  { k: "Apoplex-Warnzeichen (FAST-Test)", v: "Merkschema zum schnellen Erkennen eines Schlaganfalls: Face (hängender Mundwinkel), Arms (ein Arm sinkt ab), Speech (verwaschene Sprache), Time (sofort Notruf – Zeit ist Hirn). Meldet ein Anrufer solche plötzlichen Symptome, wird nicht einbestellt, sondern direkt der Notruf 112 veranlasst.", syn: "FAST, BE-FAST, Schlaganfall-Warnzeichen, Apoplex, Schlaganfall, Hirninfarkt, Stroke, hängender Mundwinkel, Sprachstörung plötzlich, Face Arms Speech Time", group: "Notfall & Leitsymptome" },
  { k: "Aspiration (Verschlucken in die Atemwege)", v: "Eindringen von Fremdkörpern, Nahrung oder Flüssigkeit in die Luftröhre statt in die Speiseröhre – typisch mit plötzlichem Husten, Würgen und ggf. Atemnot. Betrifft vor allem Kleinkinder und ältere Menschen mit Schluckstörungen; eine vollständige Verlegung der Atemwege ist ein akuter Notfall.", syn: "Verschlucken, Fremdkörperaspiration, Bolusaspiration, Bolusgeschehen, verschluckt, etwas in die Luftröhre bekommen, Aspirationspneumonie", group: "Notfall & Leitsymptome" },
  { k: "Dyspnoe (Atemnot)", v: "Subjektiv empfundene Atemnot oder Luftnot – von Kurzatmigkeit bei Belastung bis zu schwerer Ruheatemnot. Ein Leitsymptom mit vielen Ursachen (Herz, Lunge, Angst); akute, neu aufgetretene Atemnot ist am Empfang immer ein Warnsignal mit hoher Dringlichkeit.", syn: "Atemnot, Luftnot, Kurzatmigkeit, erschwerte Atmung, Belastungsdyspnoe, Ruhedyspnoe, Orthopnoe, Dyspnö, Dispnoe", group: "Notfall & Leitsymptome" },
  { k: "Exsikkose (Austrocknung)", v: "Austrocknung des Körpers durch zu geringe Trinkmenge oder Flüssigkeitsverlust (Fieber, Durchfall, Erbrechen, Hitze) – besonders gefährdet sind alte Menschen und Säuglinge. Typisch sind trockene Schleimhäute, stehende Hautfalten, Verwirrtheit und Kreislaufschwäche; ein häufiger Grund für Hausbesuche und Einweisungen.", syn: "Dehydratation, Dehydrierung, Austrocknung, Flüssigkeitsmangel, Volumenmangel, ausgetrocknet, Exsikose, Exikkose, stehende Hautfalten", group: "Notfall & Leitsymptome" },
  { k: "Fieberkrampf", v: "Krampfanfall bei Säuglingen und Kleinkindern im Rahmen von schnell steigendem Fieber, meist kurz und von selbst endend. Für Eltern sehr beängstigend und ein häufiger Grund für Notfallanrufe; jeder erste Fieberkrampf gehört ärztlich abgeklärt.", syn: "Fieberkrämpfe, febriler Krampfanfall, Infektkrampf, Krampfanfall bei Fieber, Fieberanfall Kind", group: "Notfall & Leitsymptome" },
  { k: "Glasgow Coma Scale (GCS)", v: "Punkteskala (3–15) zur Einschätzung des Bewusstseins anhand von Augenöffnen, sprachlicher Reaktion und Bewegung auf Ansprache oder Reiz. Taucht in Notfall- und Krankenhausbefunden auf; 15 bedeutet wach und voll orientiert, niedrige Werte stehen für zunehmende Bewusstseinsstörung bis Koma.", syn: "GCS, Glasgow-Koma-Skala, Koma-Skala, Bewusstseinsskala, Glascow Coma Scale, GCS-Wert", group: "Notfall & Leitsymptome" },
  { k: "Hyperventilation", v: "Zu schnelle und zu tiefe Atmung, meist durch Aufregung oder Angst, wodurch zu viel Kohlendioxid abgeatmet wird. Typisch sind Kribbeln um den Mund und in den Händen bis zur verkrampften \"Pfötchenstellung\"; sieht dramatisch aus, muss aber ärztlich von echter Atemnot abgegrenzt werden.", syn: "Hyperventilationssyndrom, Hyperventilationstetanie, Überatmung, zu schnelle Atmung, Pfötchenstellung, Kribbeln in den Händen, Hyperventilieren", group: "Notfall & Leitsymptome" },
  { k: "Hypoglykämischer Schock (schwere Unterzuckerung)", v: "Notfall bei Diabetikern, wenn der Blutzucker stark abfällt: Zittern, Schwitzen, Heißhunger und Verwirrtheit können bis zu Bewusstlosigkeit und Krampfanfall führen. In der Praxis wichtig, weil verwirrte oder auffällig veränderte Diabetes-Patienten immer an eine Unterzuckerung denken lassen sollten (Blutzuckermessung).", syn: "Hypoglykämie, Unterzuckerung, Unterzucker, Zuckerschock, hypoglykämisches Koma, Hypo, niedriger Blutzucker", group: "Notfall & Leitsymptome" },
  { k: "Intoxikation (Vergiftung)", v: "Schädigung des Körpers durch Gifte, Medikamente in Überdosis, Alkohol, Drogen oder Chemikalien – versehentlich (häufig bei Kindern) oder absichtlich. Bei entsprechenden Anrufen sind Substanz, Menge und Zeitpunkt wichtige Angaben; Giftnotrufzentralen beraten rund um die Uhr, bei bedrohlichen Symptomen gilt der Notruf 112.", syn: "Vergiftung, Überdosierung, Medikamentenvergiftung, Alkoholintoxikation, Intox, Giftnotruf, Giftinformationszentrum, Tablettenintoxikation", group: "Notfall & Leitsymptome" },
  { k: "Kolik", v: "Wellenartig an- und abschwellender, krampfartiger Schmerz, meist durch ein verstopftes Hohlorgan – typisch Gallenkolik (Gallensteine) oder Nierenkolik (Harnsteine). Patienten sind oft unruhig und wälzen sich vor Schmerzen; solche Anrufe oder Vorstellungen sind dringlich.", syn: "Kolikschmerz, kolikartige Schmerzen, Gallenkolik, Nierenkolik, krampfartige Bauchschmerzen, wellenförmige Schmerzen, Kollik", group: "Notfall & Leitsymptome" },
  { k: "Lungenembolie", v: "Verschluss einer Lungenarterie durch ein verschlepptes Blutgerinnsel, meist aus einer Beinvenenthrombose. Warnzeichen sind plötzliche Atemnot, atemabhängiger Brustschmerz, Herzrasen und ggf. ein geschwollenes Bein – ein lebensbedrohlicher Notfall, der sofortiges ärztliches Handeln erfordert.", syn: "LE, Lungenarterienembolie, Pulmonalembolie, Embolie, Thromboembolie, Lungeninfarkt, Gerinnsel in der Lunge, Lungenembolie-Zeichen", group: "Notfall & Leitsymptome" },
  { k: "Notfallstufen in der Hausarztpraxis", v: "Praxisinterne Einteilung eingehender Anliegen nach Dringlichkeit – von \"sofortiger Notfall\" (Arzt unterbricht Sprechstunde, ggf. Notruf 112) über \"noch heute\" bis \"regulärer Termin\". Sie gibt MFA am Telefon und Empfang eine klare Handlungsgrundlage und sollte im Praxisteam schriftlich vereinbart sein.", syn: "Dringlichkeitsstufen, Notfallkategorien, Ersteinschätzung Praxis, Notfallmanagement Praxis, Abstufung Dringlichkeit, roter Patient", group: "Notfall & Leitsymptome" },
  { k: "Notruf 112", v: "Europaweit gültige, kostenlose Notrufnummer für lebensbedrohliche Notfälle wie Bewusstlosigkeit, schweren Brustschmerz, Atemnot oder Schlaganfallzeichen – abzugrenzen vom ärztlichen Bereitschaftsdienst 116117 für nicht lebensbedrohliche Fälle außerhalb der Sprechzeiten. Beim Absetzen helfen die W-Fragen: Wo, was, wie viele Betroffene, welche Verletzungen, warten auf Rückfragen.", syn: "Notruf, Notrufnummer, Rettungsdienst rufen, Rettungsleitstelle, Notarzt, 112, Abgrenzung 116117, W-Fragen Notruf", group: "Notfall & Leitsymptome" },
  { k: "Reanimation (Wiederbelebung)", v: "Maßnahmen bei Herz-Kreislauf-Stillstand: Herzdruckmassage und Beatmung, ergänzt durch den AED (automatisierter externer Defibrillator), der per Stromstoß bestimmte Herzrhythmusstörungen beenden kann. Jede Praxis sollte den Standort ihres AED und die Aufgabenverteilung im Notfall kennen.", syn: "Wiederbelebung, Herz-Lungen-Wiederbelebung, HLW, CPR, Herzdruckmassage, kardiopulmonale Reanimation, Rea, AED, Defibrillator, Defi, Laienreanimation", group: "Notfall & Leitsymptome" },
  { k: "Schock (Kreislaufschock)", v: "Lebensbedrohliches Kreislaufversagen, bei dem die Organe nicht mehr ausreichend durchblutet werden – mögliche Ursachen sind Blut-/Flüssigkeitsverlust, Herzversagen, schwere Allergie oder Sepsis. Warnzeichen sind blasse, kaltschweißige Haut, schneller flacher Puls, niedriger Blutdruck und Unruhe bis Bewusstseinstrübung.", syn: "Kreislaufschock, Kreislaufversagen, Volumenmangelschock, hypovolämischer Schock, kardiogener Schock, septischer Schock, Schockzeichen, Schocksymptome, Schockindex", group: "Notfall & Leitsymptome" },
  { k: "Sepsis (Blutvergiftung)", v: "Lebensbedrohliche Reaktion des Körpers auf eine Infektion, bei der Organe geschädigt werden – nicht der rote Strich am Arm, wie oft angenommen. Warnzeichen sind Fieber oder auffällig niedrige Temperatur, schnelle Atmung, schneller Puls, Verwirrtheit und starkes Krankheitsgefühl; solche Patienten haben in der Praxis höchste Dringlichkeit.", syn: "Blutvergiftung, septischer Schock, Septikämie, Urosepsis, SIRS, qSOFA, Sepsiszeichen, Sepis", group: "Notfall & Leitsymptome" },
  { k: "Stabile Seitenlage", v: "Lagerung für bewusstlose Personen, die noch normal atmen: Der Patient liegt auf der Seite mit überstrecktem Kopf, damit die Atemwege frei bleiben und Erbrochenes abfließen kann. In der Praxis relevant, wenn ein Patient z. B. nach einem Kollaps bewusstlos bleibt, bis der Rettungsdienst eintrifft.", syn: "Seitenlage, Seitenlagerung, Bewusstlosenlagerung, stabile Seitenlagerung, Recovery Position", group: "Notfall & Leitsymptome" },
  { k: "Thoraxschmerz (Brustschmerz)", v: "Schmerz im Brustkorb – ein Leitsymptom, hinter dem Harmloses (Muskelverspannung) ebenso stecken kann wie ein Herzinfarkt oder eine Lungenembolie. Meldet ein Patient akuten Brustschmerz, besonders mit Ausstrahlung in Arm oder Kiefer, Atemnot oder Kaltschweißigkeit, gilt das als Notfall und muss sofort ärztlich gemeldet werden.", syn: "Brustschmerz, Brustenge, Schmerzen im Brustkorb, retrosternaler Schmerz, Herzschmerzen, Angina pectoris, akutes Koronarsyndrom, ACS, Thorakalschmerz", group: "Notfall & Leitsymptome" },
  { k: "Triage (Ersteinschätzung)", v: "Systematische Einschätzung, wie dringlich ein Patient behandelt werden muss – am Telefon, am Empfang oder in der Notaufnahme. Für MFA zentral: Anhand von Warnsymptomen wird entschieden, ob sofort der Arzt geholt, ein Notfalltermin vergeben oder der Rettungsdienst alarmiert wird.", syn: "Ersteinschätzung, Sichtung, Dringlichkeitseinschätzung, Priorisierung, Manchester-Triage, Triagierung, Triage am Telefon", group: "Notfall & Leitsymptome" },
  { k: "Zyanose (Blaufärbung)", v: "Bläuliche Verfärbung von Haut, Lippen oder Nagelbetten durch Sauerstoffmangel im Blut. In der Praxis ein sichtbares Alarmzeichen, das häufig zusammen mit Atemnot auftritt und sofortige ärztliche Beurteilung erfordert.", syn: "Blaufärbung, blaue Lippen, Blausucht, Lippenzyanose, blaue Fingernägel, Cyanose, Zianose", group: "Notfall & Leitsymptome" },

  // ===== Labor & Diagnostik =====
  { k: "Abstrich (Probenentnahme von Schleimhaut/Wunde)", v: "Mit einem Tupfer wird Material von Haut, Schleimhaut oder einer Wunde entnommen, um Erreger nachzuweisen oder anzuzüchten. In der Praxis häufig bei Halsschmerzen, Infekten, Wunden oder für Erregertests (z. B. auf Bakterien oder Viren).", syn: "Abstrich, Wundabstrich, Rachenabstrich, Nasenabstrich, Nasopharyngealabstrich, Vaginalabstrich, Tupfer, Abstrichtupfer, Smear", group: "Labor & Diagnostik" },
  { k: "Biopsie (Gewebeprobe)", v: "Die Entnahme einer kleinen Gewebeprobe, die anschließend feingeweblich (histologisch) untersucht wird, um z. B. gut- von bösartigen Veränderungen zu unterscheiden. Wird zur Sicherung einer Diagnose bei auffälligen Befunden durchgeführt.", syn: "Biopsie, Gewebeprobe, Gewebeentnahme, Probeexzision, PE, Stanzbiopsie, Biopsi, Punktion Gewebe", group: "Labor & Diagnostik" },
  { k: "Blutkultur (Erregeranzucht aus Blut)", v: "Eine Blutentnahme in spezielle Flaschen, in denen Krankheitserreger angezüchtet werden, um eine Blutvergiftung (Sepsis) nachzuweisen und den passenden Erreger zu bestimmen. Wird bei hohem Fieber mit Verdacht auf Erreger im Blut abgenommen.", syn: "Blutkulturen, Blutkultur-Set, Erregeranzucht, bakterielle Blutkultur, Blutentnahme für Kultur, Blutkultur aerob anaerob", group: "Labor & Diagnostik" },
  { k: "BSG (Blutkörperchensenkungsgeschwindigkeit)", v: "Misst, wie schnell die roten Blutkörperchen in einem Röhrchen absinken; ein erhöhter Wert weist unspezifisch auf Entzündungen oder andere Erkrankungen hin. Wird in der Praxis als einfacher, günstiger Suchtest bei unklaren Beschwerden eingesetzt.", syn: "Blutsenkung, Blutkörperchensenkungsgeschwindigkeit, Senkung, BKS, Blutsenkungsreaktion, Erythrozytensedimentationsrate, ESR", group: "Labor & Diagnostik" },
  { k: "CRP (C-reaktives Protein)", v: "Ein Eiweiß im Blut, das bei Entzündungen und Infektionen ansteigt und deshalb als schneller Entzündungsmarker dient. In der Hausarztpraxis oft als Schnelltest bestimmt, um bakterielle von harmlosen Infekten zu unterscheiden.", syn: "C-reaktives Protein, CRP-Wert, Entzündungswert, C reaktives Protein, ZRP, CRB, hs-CRP, Akute-Phase-Protein", group: "Labor & Diagnostik" },
  { k: "CT (Computertomographie)", v: "Ein Röntgenverfahren, das mit Schnittbildern den Körper Schicht für Schicht detailliert darstellt und mehr zeigt als ein normales Röntgenbild. Wird häufig zur Abklärung von Verletzungen, Tumoren oder inneren Erkrankungen in Klinik oder Radiologie veranlasst.", syn: "CT, Computertomographie, Computer-Tomographie, CT-Untersuchung, Schnittbild, Komputertomographie, CAT-Scan", group: "Labor & Diagnostik" },
  { k: "D-Dimere (Gerinnungsspaltprodukt)", v: "Abbauprodukte von Blutgerinnseln, die im Blut ansteigen, wenn irgendwo im Körper ein Gerinnsel gebildet und aufgelöst wird. Werden vor allem zum Ausschluss einer Thrombose oder Lungenembolie bestimmt; ein normaler Wert macht ein Gerinnsel unwahrscheinlich.", syn: "D-Dimer, DDimere, D Dimere, Fibrinspaltprodukt, Gerinnungsspaltprodukt, D-Dimer-Wert", group: "Labor & Diagnostik" },
  { k: "Doppler (Doppler-Sonographie der Gefäße)", v: "Eine spezielle Ultraschalltechnik, die den Blutfluss in Gefäßen sicht- und hörbar macht. Wird genutzt, um Durchblutungsstörungen, Verengungen oder Thrombosen in Arterien und Venen zu beurteilen.", syn: "Doppler, Dopplersonographie, Doppler-Ultraschall, Farbdoppler, Duplex, Duplexsonographie, Dopler, Gefäßdoppler", group: "Labor & Diagnostik" },
  { k: "Elektrolyte (Blutsalze)", v: "Mineralstoffe wie Natrium, Kalium und Kalzium, die im Blut gelöst sind und für Nerven, Muskeln und den Wasserhaushalt wichtig sind. Werden bei Herzproblemen, Nierenerkrankungen, Wassertabletten oder Flüssigkeitsmangel kontrolliert.", syn: "Blutsalze, Elektrolyt, Natrium, Kalium, Kalzium, Calcium, Chlorid, Magnesium, Elektrolytwerte, Salze im Blut", group: "Labor & Diagnostik" },
  { k: "Ergometrie (Belastungs-EKG)", v: "Eine EKG-Untersuchung während körperlicher Belastung auf einem Fahrrad, um Herz und Kreislauf unter Anstrengung zu beurteilen. Dient dem Aufspüren von Durchblutungsstörungen des Herzens und der Kontrolle von Blutdruck und Herzrhythmus unter Belastung.", syn: "Belastungs-EKG, Belastungs EKG, Fahrrad-EKG, Ergometrie, Ergo, Fahrradergometrie, Belastungstest, Belastungs-Elektrokardiogramm", group: "Labor & Diagnostik" },
  { k: "Erythrozyten (rote Blutkörperchen)", v: "Die roten Blutkörperchen transportieren mit dem Hämoglobin den Sauerstoff durch den Körper. Zu wenige weisen auf eine Blutarmut (Anämie) hin, zu viele können andere Ursachen haben; sie sind fester Bestandteil des Blutbilds.", syn: "rote Blutkörperchen, Erytrozyten, Erys, Erythrozytenzahl, RBC, rote Blutzellen, Erythrozyt", group: "Labor & Diagnostik" },
  { k: "Ferritin (Eisenspeicherwert)", v: "Ferritin ist das Speichereiweiß für Eisen und zeigt an, wie gut die Eisenreserven des Körpers gefüllt sind. Niedrige Werte sprechen für Eisenmangel, häufige Ursache von Blutarmut und Müdigkeit; oft bei entsprechenden Beschwerden bestimmt.", syn: "Eisenspeicher, Feritin, Ferritinwert, Speichereisen, Eisenspeicherprotein, Ferretin", group: "Labor & Diagnostik" },
  { k: "Gamma-GT (Gamma-Glutamyltransferase)", v: "Ein Leberenzym, das besonders empfindlich auf Erkrankungen von Leber und Gallenwegen sowie auf Alkohol reagiert. Wird in der Praxis zusammen mit den anderen Leberwerten zur Abklärung von Leber- und Gallenproblemen bestimmt.", syn: "Gamma-Glutamyltransferase, GGT, y-GT, Gamma GT, GammaGT, Leberwert Gamma-GT, Gamma-Glutamyltranspeptidase", group: "Labor & Diagnostik" },
  { k: "GFR (glomeruläre Filtrationsrate)", v: "Ein aus dem Kreatinin berechneter Wert, der angibt, wie viel Blut die Nieren pro Minute reinigen; er beschreibt die Nierenfunktion genauer als Kreatinin allein. Wichtig zur Einstufung einer Nierenschwäche und für die Dosierung von Medikamenten.", syn: "glomeruläre Filtrationsrate, eGFR, GFR-Wert, Nierenfiltrationsrate, geschätzte GFR, glomeruläre Filtration", group: "Labor & Diagnostik" },
  { k: "Harnsäure (Gichtwert)", v: "Ein Abbauprodukt des Purinstoffwechsels; erhöhte Werte können zu Gicht mit schmerzhaften Gelenkentzündungen und zu Nierensteinen führen. Wird bei Gelenkbeschwerden oder zur Verlaufskontrolle einer Gicht bestimmt.", syn: "Gichtwert, Harnsaeure, Harnsäurewert, Urat, Harnsäure im Serum, Harnsäurespiegel", group: "Labor & Diagnostik" },
  { k: "Hämoglobin (roter Blutfarbstoff)", v: "Der eisenhaltige rote Blutfarbstoff in den Erythrozyten, der den Sauerstoff bindet und transportiert. Ein niedriger Hb-Wert zeigt eine Blutarmut (Anämie) an und ist ein häufig kontrollierter Laborwert in der Hausarztpraxis.", syn: "roter Blutfarbstoff, Haemoglobin, Hämoglobinwert, Hb, Hb-Wert, Blutfarbstoff, Hemoglobin", group: "Labor & Diagnostik" },
  { k: "INR / Quick (Gerinnungswert)", v: "Werte, die die Blutgerinnung messen und angeben, wie schnell das Blut gerinnt; INR und Quick sind zwei Ausdrucksweisen desselben Tests. Besonders wichtig bei Patienten unter blutverdünnenden Medikamenten wie Marcumar, die regelmäßig kontrolliert werden.", syn: "INR, Quick, Quickwert, Quick-Wert, Prothrombinzeit, Thromboplastinzeit, TPZ, INR-Wert, Gerinnung, Blutverdünnung", group: "Labor & Diagnostik" },
  { k: "Kreatinin (Nierenwert)", v: "Ein Abbauprodukt des Muskelstoffwechsels, das über die Nieren ausgeschieden wird und deshalb als Maß für die Nierenfunktion dient. Erhöhte Werte weisen auf eine eingeschränkte Nierenleistung hin; wichtiger Routinewert vor Medikamentengaben.", syn: "Nierenwert, Kreatinien, Creatinin, Kreatininwert, Krea, Kreatinin im Serum", group: "Labor & Diagnostik" },
  { k: "Leukozyten (weiße Blutkörperchen)", v: "Die weißen Blutkörperchen sind Teil der Immunabwehr und bekämpfen Krankheitserreger. Erhöhte Werte deuten meist auf Infektionen oder Entzündungen hin, sehr niedrige auf eine geschwächte Abwehr; sie werden im Blutbild bestimmt.", syn: "weiße Blutkörperchen, Leucozyten, Leukos, Leukozytenzahl, WBC, Leukozyt, weiße Blutzellen", group: "Labor & Diagnostik" },
  { k: "MRT (Magnetresonanztomographie)", v: "Ein bildgebendes Verfahren mit Magnetfeldern und Radiowellen ohne Röntgenstrahlung, das besonders gut Weichteile wie Gehirn, Gelenke oder Bandscheiben darstellt. Wird meist per Überweisung in eine radiologische Praxis veranlasst.", syn: "MRT, Magnetresonanztomographie, Kernspin, Kernspintomographie, MRI, Magnet-Resonanz-Tomographie, MRT-Untersuchung", group: "Labor & Diagnostik" },
  { k: "Röntgen (Röntgenuntersuchung)", v: "Ein bildgebendes Verfahren mit Röntgenstrahlen, das vor allem Knochen und die Lunge gut darstellt. Wird bei Verdacht auf Knochenbrüche, Lungenentzündung oder andere Veränderungen als schnelle Basisuntersuchung eingesetzt.", syn: "Röntgen, Roentgen, Röntgenbild, Röntgenaufnahme, X-Ray, Radiographie, Thorax-Röntgen, Röntgen-Thorax", group: "Labor & Diagnostik" },
  { k: "Screening (Vorsorge-/Früherkennungsuntersuchung)", v: "Eine systematische Untersuchung von Menschen ohne Beschwerden, um Krankheiten früh zu erkennen, etwa bei Krebs-, Blutzucker- oder Blutdruckvorsorge. In der Hausarztpraxis Teil der Gesundheitsuntersuchung und gesetzlicher Vorsorgeprogramme.", syn: "Screening, Früherkennung, Vorsorge, Reihenuntersuchung, Skrining, Vorsorgeuntersuchung, Früherkennungsuntersuchung, Screeningtest", group: "Labor & Diagnostik" },
  { k: "Sonographie (Ultraschalluntersuchung)", v: "Ein bildgebendes Verfahren, das mit Schallwellen Organe darstellt, ohne Strahlenbelastung und schmerzfrei. In der Hausarztpraxis oft zur Untersuchung von Bauchorganen, Schilddrüse oder Gefäßen eingesetzt.", syn: "Ultraschall, Sonografie, Sono, Sonographie, US-Untersuchung, Echographie, Ultraschalluntersuchung", group: "Labor & Diagnostik" },
  { k: "Thrombozyten (Blutplättchen)", v: "Blutplättchen sind für die Blutgerinnung und den Wundverschluss zuständig. Zu niedrige Werte erhöhen die Blutungsneigung, zu hohe das Thromboserisiko; sie werden im Blutbild mitbestimmt.", syn: "Blutplättchen, Trombozyten, Thrombos, Thrombozytenzahl, PLT, Blutplättchenzahl, Thrombozyt", group: "Labor & Diagnostik" },
  { k: "Transaminasen (Leberwerte GOT/GPT)", v: "Enzyme aus den Leberzellen (GOT/AST und GPT/ALT), die bei Leberschädigung vermehrt ins Blut übertreten und daher als Leberwerte kontrolliert werden. Erhöhungen können auf Leberentzündung, Fettleber oder Medikamentennebenwirkungen hinweisen.", syn: "Leberwerte, Transaminase, GOT, GPT, AST, ALT, ASAT, ALAT, Trans­aminasen, Leberenzyme", group: "Labor & Diagnostik" },
  { k: "Troponin (Herzinfarktmarker)", v: "Ein Eiweiß aus dem Herzmuskel, das bei Schädigung des Herzens ins Blut gelangt und deshalb der wichtigste Laborwert zum Nachweis eines Herzinfarkts ist. Bei akutem Brustschmerz meist im Krankenhaus, teils als Schnelltest in der Praxis bestimmt.", syn: "Herzmuskelmarker, Troponin T, Troponin I, hs-Troponin, Troponinwert, Tropanin, Herzinfarktwert", group: "Labor & Diagnostik" },
  { k: "Urinstatus (Urinuntersuchung)", v: "Eine Untersuchung des Urins mit Teststreifen und ggf. Mikroskop auf Zeichen wie Blut, Eiweiß, Zucker, Nitrit oder Entzündungszellen. In der Hausarztpraxis Standard bei Verdacht auf Harnwegsinfekt, Nieren- oder Zuckerkrankheit.", syn: "Urinstatus, Harnstatus, U-Status, Urinstreifentest, Teststreifen Urin, Urinsediment, Urinuntersuchung, Harnuntersuchung, Urin-Stix", group: "Labor & Diagnostik" },

  // ===== Medikamente & Wirkstoffgruppen =====
  { k: "ACE-Hemmer & Sartane", v: "Zwei eng verwandte Gruppen von Blutdrucksenkern: ACE-Hemmer (z. B. Ramipril, Enalapril; Endung „-pril\") und Sartane (z. B. Candesartan, Valsartan; Endung „-sartan\"), die zusätzlich Herz und Nieren schützen. Sartane werden oft gewählt, wenn ACE-Hemmer den typischen trockenen Reizhusten auslösen.", syn: "ACE-Hemmer, Ace Hemmer, ACE-Inhibitoren, Sartane, AT1-Blocker, AT1-Antagonisten, Angiotensin-Rezeptorblocker, Ramipril, Enalapril, Lisinopril, Candesartan, Valsartan, Losartan, Blutdrucksenker, -pril, -sartan", group: "Medikamente & Wirkstoffgruppen" },
  { k: "Analgetika (Schmerzmittel)", v: "Sammelbegriff für alle Medikamente gegen Schmerzen. Nach dem WHO-Stufenschema unterscheidet man Stufe 1 (Nicht-Opioide wie Ibuprofen oder Paracetamol), Stufe 2 (schwache Opioide wie Tramadol) und Stufe 3 (starke Opioide wie Morphin).", syn: "Analgetikum, Schmerzmittel, Schmerztabletten, WHO-Stufenschema, Analgetika-Stufen, Stufenschema, Stufentherapie, Analgesie, Analgeticum, Analgetika", group: "Medikamente & Wirkstoffgruppen" },
  { k: "Antihistaminika", v: "Medikamente gegen allergische Beschwerden wie Heuschnupfen, Nesselsucht oder Juckreiz, z. B. Cetirizin, Loratadin oder Desloratadin. Ältere Wirkstoffe machen müde und werden teils auch gegen Übelkeit oder als Schlafhilfe eingesetzt.", syn: "Antihistaminikum, Allergietabletten, H1-Blocker, Cetirizin, Loratadin, Desloratadin, Fexofenadin, Dimetinden, Fenistil, Antihistamin, Anti-Histaminika, Antihystaminika", group: "Medikamente & Wirkstoffgruppen" },
  { k: "Antikoagulanzien (Blutverdünner)", v: "Medikamente, die die Blutgerinnung hemmen, um Thrombosen, Lungenembolien und Schlaganfälle (z. B. bei Vorhofflimmern) zu verhindern. Man unterscheidet Vitamin-K-Antagonisten wie Phenprocoumon (Marcumar), bei denen regelmäßig der INR-/Quick-Wert in der Praxis kontrolliert wird, und die moderneren DOAK.", syn: "Blutverdünner, Gerinnungshemmer, Antikoagulation, Antikoagulantien, Vitamin-K-Antagonisten, VKA, Cumarine, Phenprocoumon, Marcumar, Falithrom, Warfarin, INR, Quick-Wert, Marcumar-Ausweis, Antikuagulanzien", group: "Medikamente & Wirkstoffgruppen" },
  { k: "Benzodiazepine", v: "Beruhigungs- und Schlafmittel wie Diazepam, Lorazepam (Tavor) oder Oxazepam mit hohem Abhängigkeitspotenzial, weshalb sie in der Regel nur kurzzeitig verordnet werden. Die verwandten Z-Substanzen (Zopiclon, Zolpidem) werden ähnlich eingestuft.", syn: "Benzos, Diazepam, Valium, Lorazepam, Tavor, Oxazepam, Bromazepam, Tranquilizer, Beruhigungsmittel, Schlafmittel, Z-Substanzen, Zopiclon, Zolpidem, Benzodiacepine, Benzodiazepin", group: "Medikamente & Wirkstoffgruppen" },
  { k: "Betablocker", v: "Medikamente wie Metoprolol, Bisoprolol oder Nebivolol, die Puls und Blutdruck senken und das Herz entlasten; die Wirkstoffnamen enden meist auf „-olol\". Standard bei Bluthochdruck, koronarer Herzkrankheit, Herzschwäche und Herzrhythmusstörungen.", syn: "Beta-Blocker, Betarezeptorenblocker, Metoprolol, Bisoprolol, Nebivolol, Carvedilol, Propranolol, Betablokker, Bethablocker, -olol", group: "Medikamente & Wirkstoffgruppen" },
  { k: "Bisphosphonate", v: "Medikamente gegen Osteoporose (Knochenschwund) wie Alendronsäure oder Risedronat, oft nur einmal wöchentlich eingenommen. Es gelten besondere Einnahmeregeln zum Schutz der Speiseröhre, und wegen seltener Nebenwirkungen am Kieferknochen wird die Behandlung häufig zahnärztlich begleitet.", syn: "Bisphosphonat, Biphosphonate, Bisfosfonate, Alendronsäure, Alendronat, Risedronat, Ibandronat, Zoledronat, Osteoporosemittel, Knochenmedikament", group: "Medikamente & Wirkstoffgruppen" },
  { k: "Chinolone (Fluorchinolone)", v: "Antibiotika-Gruppe mit Wirkstoffen wie Ciprofloxacin, Levofloxacin oder Moxifloxacin, die heute als Reserve für bestimmte, meist schwerere Infektionen gilt. Wegen möglicher Nebenwirkungen an Sehnen, Nerven und Gefäßen bestehen behördliche Anwendungsbeschränkungen.", syn: "Fluorchinolone, Gyrasehemmer, Ciprofloxacin, Cipro, Levofloxacin, Moxifloxacin, Norfloxacin, Chinolon-Antibiotika, Kinolone, Cinolone", group: "Medikamente & Wirkstoffgruppen" },
  { k: "Diuretika (Entwässerungsmittel)", v: "Medikamente wie Hydrochlorothiazid (HCT), Torasemid oder Spironolacton, die über die Niere Wasser und Salz ausschwemmen. Eingesetzt bei Bluthochdruck, Herzschwäche und Wassereinlagerungen (Ödemen); regelmäßige Laborkontrollen von Nierenwerten und Elektrolyten sind üblich.", syn: "Wassertabletten, Entwässerungstabletten, Diuretikum, HCT, Hydrochlorothiazid, Torasemid, Furosemid, Spironolacton, Schleifendiuretika, Thiazide, Diurethika, Entwässerung", group: "Medikamente & Wirkstoffgruppen" },
  { k: "DOAK (direkte orale Antikoagulanzien)", v: "Moderne „Blutverdünner\" in Tablettenform wie Apixaban (Eliquis), Rivaroxaban (Xarelto), Edoxaban (Lixiana) und Dabigatran (Pradaxa). Anders als bei Marcumar ist keine routinemäßige INR-Kontrolle nötig; wichtig ist die Angabe der Einnahme vor Operationen und Eingriffen.", syn: "NOAK, neue orale Antikoagulanzien, direkte orale Antikoagulantien, Apixaban, Eliquis, Rivaroxaban, Xarelto, Edoxaban, Lixiana, Dabigatran, Pradaxa, Doak, Doack", group: "Medikamente & Wirkstoffgruppen" },
  { k: "Glukokortikoide (Kortison)", v: "Stark entzündungshemmende Wirkstoffe wie Prednisolon, umgangssprachlich „Kortison\", als Tablette, Spritze, Salbe oder Inhalationsspray. In der Hausarztpraxis häufig bei Asthma/COPD, Hauterkrankungen, Allergien und rheumatischen Erkrankungen; bei längerer Anwendung sind Nebenwirkungen wie Gewichtszunahme oder Knochenschwund möglich.", syn: "Kortison, Cortison, Kortikoide, Corticosteroide, Glucocorticoide, Steroide, Prednisolon, Prednison, Dexamethason, Budesonid, Hydrocortison, Kortisonspritze, Kortisonsalbe", group: "Medikamente & Wirkstoffgruppen" },
  { k: "Insulin (Insulinarten)", v: "Hormonpräparat zum Spritzen, das bei Diabetes den Blutzucker senkt. Grob unterscheidet man kurzwirksames Insulin zu den Mahlzeiten, langwirksames Basal-/Verzögerungsinsulin und Mischinsulin; verordnet wird es meist als Pen mit zugehörigen Nadeln und Teststreifen.", syn: "Basalinsulin, Bolusinsulin, Mischinsulin, Verzögerungsinsulin, Normalinsulin, Humaninsulin, Insulinanaloga, Langzeitinsulin, Kurzzeitinsulin, Insulinpen, Pen, Inzulin", group: "Medikamente & Wirkstoffgruppen" },
  { k: "Kalziumantagonisten", v: "Blutdrucksenker wie Amlodipin oder Lercanidipin (Endung meist „-dipin\"), die die Blutgefäße erweitern. Eine typische Nebenwirkung sind geschwollene Knöchel (Beinödeme), die Patienten häufig in der Praxis berichten.", syn: "Calciumantagonisten, Kalziumkanalblocker, Calciumkanalblocker, Kalzium-Antagonist, Amlodipin, Lercanidipin, Nifedipin, Verapamil, Diltiazem, -dipin", group: "Medikamente & Wirkstoffgruppen" },
  { k: "Kontraindikation (Gegenanzeige)", v: "Umstand, bei dem ein Medikament oder eine Maßnahme nicht angewendet werden darf, z. B. bestimmte Vorerkrankungen, Allergien oder eine Schwangerschaft. Man unterscheidet absolute Kontraindikationen (Anwendung ausgeschlossen) und relative (nur nach ärztlicher Nutzen-Risiko-Abwägung).", syn: "Gegenanzeige, kontraindiziert, absolute Kontraindikation, relative Kontraindikation, Contraindikation, Kontraindikationen, KI", group: "Medikamente & Wirkstoffgruppen" },
  { k: "Makrolide", v: "Antibiotika-Gruppe mit Wirkstoffen wie Azithromycin, Clarithromycin oder Erythromycin, die oft als Alternative bei Penicillinallergie oder bei sogenannten atypischen Erregern eingesetzt wird. Sie haben viele Wechselwirkungen mit anderen Medikamenten, was bei der Verordnung geprüft wird.", syn: "Makrolid-Antibiotika, Azithromycin, Clarithromycin, Erythromycin, Roxithromycin, Macrolide, Makrolyde, Makrolid", group: "Medikamente & Wirkstoffgruppen" },
  { k: "Metamizol (Novaminsulfon)", v: "Metamizol (Wirkstoff = Metamizol, in Deutschland auch Novaminsulfon genannt) ist ein verschreibungspflichtiges, stark wirksames Schmerz- und Fiebermittel mit zusätzlich krampflösender Wirkung. Bekanntester Handelsname ist Novalgin; als Generika wird der Wirkstoff meist unter dem Namen \"Novaminsulfon\" plus Herstellerzusatz verkauft. Selten kann eine Agranulozytose auftreten.", syn: "Novaminsulfon, Novalgin, Novalgintropfen, Metamizol-Natrium, Dipyron, Metamisol, Metamizoltropfen, Novaminsulfon-Tropfen", group: "Medikamente & Wirkstoffgruppen" },
  { k: "Metformin", v: "Wichtigstes Tabletten-Basismedikament bei Typ-2-Diabetes; es senkt den Blutzucker, ohne selbst Unterzuckerungen auszulösen. Vor Untersuchungen mit Kontrastmittel oder bei schwerer Nierenschwäche wird es nach ärztlicher Anweisung pausiert — ein häufiges Thema bei der Terminplanung.", syn: "Biguanid, Metformin-Hydrochlorid, Glucophage, Siofor, orales Antidiabetikum, Diabetestabletten, Zuckertabletten, Metvormin, Medformin", group: "Medikamente & Wirkstoffgruppen" },
  { k: "Nebenwirkung (UAW)", v: "Unerwünschte Arzneimittelwirkung, die zusätzlich zur beabsichtigten Wirkung eines Medikaments auftritt, z. B. Übelkeit oder Hautausschlag. Schwerwiegende oder neue Nebenwirkungen werden in der Akte dokumentiert und können ärztlich an das BfArM bzw. die Arzneimittelkommission gemeldet werden.", syn: "UAW, unerwünschte Arzneimittelwirkung, Nebenwirkungen, Arzneimittelnebenwirkung, unerwünschte Wirkung, Unverträglichkeit, Nebenwirkungsmeldung", group: "Medikamente & Wirkstoffgruppen" },
  { k: "NSAR (nichtsteroidale Antirheumatika)", v: "Gruppe von Schmerz- und Entzündungshemmern wie Ibuprofen, Diclofenac oder Naproxen, in der Hausarztpraxis sehr häufig bei Gelenk-, Rücken- und Kopfschmerzen. Sie können Magen und Nieren belasten, weshalb oft zusätzlich ein Magenschutz (PPI) verordnet wird.", syn: "NSAID, nichtsteroidale Antiphlogistika, Ibuprofen, Ibu, Diclofenac, Naproxen, Entzündungshemmer, Rheumamittel, nicht-steroidale Antirheumatika, NSAR-Schmerzmittel, Ensar", group: "Medikamente & Wirkstoffgruppen" },
  { k: "Opioide", v: "Stark wirksame Schmerzmittel der WHO-Stufen 2 und 3 wie Tramadol, Tilidin, Morphin, Oxycodon oder Fentanyl. Viele unterliegen dem Betäubungsmittelgesetz und werden auf einem speziellen BtM-Rezept verordnet; typische Nebenwirkungen sind Müdigkeit, Übelkeit und Verstopfung.", syn: "Opiate, Morphin, Morphium, Tramadol, Tilidin, Oxycodon, Fentanyl, Hydromorphon, Fentanylpflaster, BtM, Betäubungsmittel, Opioid-Analgetika, Opioid", group: "Medikamente & Wirkstoffgruppen" },
  { k: "Paracetamol", v: "Schmerz- und fiebersenkender Wirkstoff (Stufe-1-Analgetikum), der nicht entzündungshemmend wirkt und als magenverträglich gilt. Häufig nachgefragt bei Kindern, Schwangeren und in der Selbstmedikation; bei Überdosierung kann er die Leber schwer schädigen.", syn: "PCM, Acetaminophen, ben-u-ron, Parazetamol, Paracetamin, Parcetamol, fiebersenkendes Mittel, Antipyretikum", group: "Medikamente & Wirkstoffgruppen" },
  { k: "Penicilline", v: "Älteste und in der Hausarztpraxis häufigste Antibiotika-Gruppe, z. B. Penicillin V, Amoxicillin oder Amoxicillin/Clavulansäure, eingesetzt u. a. bei Mandel-, Mittelohr- und Atemwegsinfektionen. Eine dokumentierte Penicillinallergie ist eine wichtige Information in der Patientenakte.", syn: "Penicillin, Penizillin, Penicillin V, Phenoxymethylpenicillin, Amoxicillin, Amoxi, Amoxiclav, Amoxicillin/Clavulansäure, Aminopenicilline, Betalaktam-Antibiotika, Penicillinallergie, Penecillin", group: "Medikamente & Wirkstoffgruppen" },
  { k: "Protonenpumpenhemmer (PPI)", v: "Magensäureblocker wie Pantoprazol oder Omeprazol, umgangssprachlich „Magenschutz\" genannt. Häufig verordnet bei Sodbrennen, Refluxkrankheit und Magengeschwüren oder begleitend zu magenreizenden Medikamenten wie NSAR.", syn: "PPI, Magenschutz, Säureblocker, Magensäureblocker, Pantoprazol, Pantozol, Omeprazol, Esomeprazol, Protonenpumpeninhibitor, Magentablette, Prasole", group: "Medikamente & Wirkstoffgruppen" },
  { k: "Retardpräparat (Retard/Depot)", v: "Arzneiform, die den Wirkstoff verzögert über viele Stunden freisetzt (Zusatz „retard\" auf der Packung), sodass seltener eingenommen werden muss. Depot-Präparate sind meist Spritzen mit Wirkdauer über Wochen; Retardtabletten dürfen in der Regel nicht geteilt oder gemörsert werden.", syn: "Retard, retardiert, Retardtablette, Retardkapsel, ret., Depot, Depotpräparat, Depotspritze, verzögerte Freisetzung, Langzeitwirkung", group: "Medikamente & Wirkstoffgruppen" },
  { k: "SSRI (Serotonin-Wiederaufnahmehemmer)", v: "SSRI (selektive Serotonin-Wiederaufnahmehemmer) sind z. B. Citalopram, Sertralin, Escitalopram, Fluoxetin oder Paroxetin. Venlafaxin und Duloxetin gehören dagegen zu den SNRI (Serotonin-Noradrenalin-Wiederaufnahmehemmer), einer eigenständigen Antidepressiva-Gruppe – SNRI/Venlafaxin sollten nicht als Synonym für SSRI geführt werden.", syn: "Serotonin-Wiederaufnahmehemmer, selektive Serotonin-Reuptake-Inhibitoren, Antidepressiva, Citalopram, Sertralin, Escitalopram, Fluoxetin, Paroxetin, SNRI, Venlafaxin, SSRIs, Essesri", group: "Medikamente & Wirkstoffgruppen" },
  { k: "Statine", v: "Cholesterinsenker wie Simvastatin, Atorvastatin oder Rosuvastatin, die zur Vorbeugung von Herzinfarkt und Schlaganfall eingesetzt werden. Gelegentlich verursachen sie Muskelschmerzen, was Patienten häufig in der Sprechstunde ansprechen.", syn: "CSE-Hemmer, Cholesterinsenker, Lipidsenker, Blutfettsenker, Simvastatin, Atorvastatin, Rosuvastatin, Pravastatin, Statin, Staline", group: "Medikamente & Wirkstoffgruppen" },
  { k: "Thrombozytenaggregationshemmer (ASS)", v: "Medikamente wie ASS 100 (Acetylsalicylsäure) oder Clopidogrel, die das Verklumpen der Blutplättchen hemmen und so Herzinfarkt und Schlaganfall vorbeugen. Nicht zu verwechseln mit Antikoagulanzien — beide Gruppen werden umgangssprachlich „Blutverdünner\" genannt.", syn: "ASS, ASS 100, Aspirin, Acetylsalicylsäure, Azetylsalizylsäure, Clopidogrel, Prasugrel, Ticagrelor, Plättchenhemmer, TAH, Aggregationshemmer, Trombozytenaggregationshemmer, Thrombozytenhemmer", group: "Medikamente & Wirkstoffgruppen" },
  { k: "Triptane", v: "Spezielle Migränemittel wie Sumatriptan oder Rizatriptan, die im akuten Anfall gegen Kopfschmerz und Begleitsymptome wie Übelkeit wirken. Sie helfen nur bei Migräne, nicht bei Spannungskopfschmerz, und dürfen bei bestimmten Herz-Kreislauf-Erkrankungen nicht eingesetzt werden.", syn: "Triptan, Sumatriptan, Rizatriptan, Zolmitriptan, Naratriptan, Migränemittel, Migränetabletten, Tryptane, Tripane", group: "Medikamente & Wirkstoffgruppen" },
  { k: "Wechselwirkung (Interaktion)", v: "Gegenseitige Beeinflussung von zwei oder mehr Medikamenten — oder von Medikamenten mit Lebensmitteln wie Grapefruit —, die die Wirkung verstärken oder abschwächen kann. Die Praxissoftware prüft bei der Verordnung automatisch auf relevante Interaktionen; ein aktueller Medikationsplan ist dafür wichtig.", syn: "Interaktion, Wechselwirkungen, Arzneimittelinteraktion, Arzneimittelwechselwirkung, Medikamenten-Wechselwirkung, Interaktionscheck, Interaktionsprüfung", group: "Medikamente & Wirkstoffgruppen" },

  // ===== Impfungen & Erreger =====
  { k: "Auffrischimpfung (Booster)", v: "Erneute Impfung nach abgeschlossener Grundimmunisierung, die den mit der Zeit nachlassenden Schutz wieder anhebt. In der Hausarztpraxis häufig z. B. bei Tetanus und Diphtherie im empfohlenen Abstand.", syn: "Booster, Boosterimpfung, Auffrischung, Auffrischungsimpfung, Nachimpfung, Wiederholungsimpfung, Booster-Impfung, Auffrischimfung", group: "Impfungen & Erreger" },
  { k: "Diphtherie", v: "Bakterielle Infektion, die vor allem Rachen und Kehlkopf befällt und durch ein Gift Herz und Nerven schädigen kann; typisch sind festhaftende Beläge im Hals. Der Schutz wird meist zusammen mit Tetanus aufgefrischt.", syn: "Diphtherie, Corynebacterium diphtheriae, Diphterie, Diphtherie-Impfung, echter Krupp, Diphtheria, Diptherie, Bräune, Diphterie", group: "Impfungen & Erreger" },
  { k: "Grundimmunisierung", v: "Erste, meist aus mehreren Dosen bestehende Impfserie, die einen belastbaren Grundschutz gegen einen Erreger aufbaut. Sie ist die Voraussetzung dafür, dass spätere Auffrischimpfungen zuverlässig wirken.", syn: "Grundschutz, Basisimmunisierung, Erstimpfung, Impfserie, Grundimpfung, primäre Immunisierung, Grundimunisierung", group: "Impfungen & Erreger" },
  { k: "Hepatitis A", v: "Durch Viren ausgelöste Leberentzündung, die über verunreinigte Nahrung, Wasser oder Schmierinfektion übertragen wird und meist ohne Dauerschäden ausheilt. Die Impfung hat vor allem als Reiseimpfung Bedeutung.", syn: "Hepatitis A, Hep A, HAV, Hepatitis-A-Virus, Reisehepatitis, Leberentzündung Typ A, Hepatitis-A-Impfung, Gelbsucht, Hepatits A", group: "Impfungen & Erreger" },
  { k: "Hepatitis B", v: "Durch Viren ausgelöste Leberentzündung, die über Blut und sexuelle Kontakte übertragen wird und chronisch werden sowie zu Leberzirrhose oder Leberkrebs führen kann. Die Impfung ist Teil der empfohlenen Standardimpfungen im Säuglingsalter.", syn: "Hepatitis B, Hep B, HBV, Hepatitis-B-Virus, Leberentzündung Typ B, Hepatitis-B-Impfung, Serumhepatitis, Gelbsucht, Hepatits B", group: "Impfungen & Erreger" },
  { k: "Herdenimmunität", v: "Schutz, der entsteht, wenn ein so großer Anteil der Bevölkerung immun ist, dass sich ein Erreger kaum noch ausbreiten kann und dadurch auch Ungeimpfte mitgeschützt werden. Wichtig etwa beim Masernschutz.", syn: "Gemeinschaftsschutz, Herdenschutz, Kollektivimmunität, Bevölkerungsimmunität, herd immunity, Herdimmunität", group: "Impfungen & Erreger" },
  { k: "HPV (Humane Papillomviren)", v: "Sexuell übertragbare Viren, von denen bestimmte Typen Gebärmutterhals- und andere Krebsarten sowie Genitalwarzen auslösen können. Die Impfung wird für Mädchen und Jungen möglichst vor dem ersten Sexualkontakt empfohlen.", syn: "HPV, Humane Papillomviren, humanes Papillomvirus, Papillomviren, HP-Viren, HPV-Impfung, Gebärmutterhalskrebs-Impfung, Papilloma, Gardasil, HPV Impfung", group: "Impfungen & Erreger" },
  { k: "Impfreaktion vs. Impfkomplikation", v: "Eine Impfreaktion ist eine erwartete, harmlose Begleiterscheinung wie Rötung, Schwellung oder leichtes Fieber, die von selbst abklingt; eine Impfkomplikation ist eine darüber hinausgehende, meldepflichtige Nebenwirkung. Die Unterscheidung ist für Dokumentation und Rückfragen von Patienten wichtig.", syn: "Impfreaktion, Impfnebenwirkung, Lokalreaktion, Impfkomplikation, Nebenwirkung Impfung, unerwünschte Impfnebenwirkung, Impffolgen, Impfschaden, Impfreation", group: "Impfungen & Erreger" },
  { k: "Inkubationszeit", v: "Zeitspanne zwischen der Ansteckung mit einem Erreger und dem Auftreten der ersten Krankheitszeichen. Sie hilft einzuschätzen, ab wann bei einem Verdachtsfall Symptome zu erwarten sind.", syn: "Inkubation, Ansteckungszeit, Latenzzeit, Zeit bis Krankheitsausbruch, Inkubationsphase, Inkubationszeit, Inkubatzionszeit", group: "Impfungen & Erreger" },
  { k: "Lebendimpfstoff", v: "Impfstoff mit abgeschwächten, aber noch vermehrungsfähigen Erregern, die eine milde, folgenlose Auseinandersetzung des Immunsystems auslösen. Er kommt z. B. bei Masern-Mumps-Röteln oder Windpocken zum Einsatz und ist bei Schwangeren und stark Abwehrgeschwächten meist nicht geeignet.", syn: "attenuierter Impfstoff, Lebendimpfung, Lebend-Impfstoff, abgeschwächter Impfstoff, Lebendvakzine, Lebendvirus-Impfstoff, Lebentimpfstoff", group: "Impfungen & Erreger" },
  { k: "Masern, Mumps, Röteln (MMR)", v: "Drei hochansteckende Viruserkrankungen, gegen die mit einem kombinierten Lebendimpfstoff geimpft wird; Masern können schwere Komplikationen, Röteln in der Schwangerschaft Fehlbildungen verursachen. Für Masern besteht in Deutschland eine Nachweispflicht nach dem Masernschutzgesetz.", syn: "MMR, MMR-Impfung, Masern, Mumps, Röteln, Morbilli, Parotitis epidemica, Ziegenpeter, Rubella, Rubeola, MMRV, Masern-Mumps-Röteln, Röteln", group: "Impfungen & Erreger" },
  { k: "Meningokokken", v: "Bakterien (Neisseria meningitidis), die eine schwere Hirnhautentzündung und Blutvergiftung verursachen können. Gegen mehrere Typen (z. B. B und C) gibt es Impfungen, die vor allem für Kinder und Jugendliche empfohlen werden.", syn: "Neisseria meningitidis, Meningokokken-Impfung, Meningokokken B, Meningokokken C, Meningokokken ACWY, Meningokokkeninfektion, Meningokoken, Menigokokken", group: "Impfungen & Erreger" },
  { k: "mRNA-Impfstoff", v: "Impfstoff, der dem Körper einen genetischen Bauplan (mRNA) liefert, sodass die Zellen selbst ein einzelnes Erregereiweiß bilden, gegen das das Immunsystem eine Abwehr aufbaut. Bekannt geworden vor allem durch die COVID-19-Impfung.", syn: "messenger-RNA-Impfstoff, RNA-Impfstoff, mRNA-Vakzine, Boten-RNA-Impfstoff, mRNA Impfung, m-RNA-Impfstoff, mRNS-Impfstoff, Comirnaty, Spikevax", group: "Impfungen & Erreger" },
  { k: "Pneumokokken", v: "Bakterien (Streptococcus pneumoniae), die Lungenentzündung, Mittelohr- und Hirnhautentzündung auslösen können. Die Impfung wird besonders für Säuglinge und ältere Menschen empfohlen.", syn: "Streptococcus pneumoniae, Pneumokokken-Impfung, Pneumokokkeninfektion, Pneumokoken, Pneumokokkus, Pneumococcus, Pneumokoken-Impfung", group: "Impfungen & Erreger" },
  { k: "RSV (Respiratorisches Synzytial-Virus)", v: "Weit verbreitetes Virus, das Atemwegsinfekte auslöst und bei Säuglingen sowie älteren Menschen schwere Verläufe verursachen kann. Zum Schutz gibt es Impfungen und für Säuglinge eine vorbeugende Antikörpergabe.", syn: "RSV, Respiratorisches Synzytial-Virus, RS-Virus, respiratory syncytial virus, RSV-Impfung, Synzytialvirus, RSV-Infektion, RS-Viren, RSV Virus", group: "Impfungen & Erreger" },
  { k: "STIKO (Ständige Impfkommission)", v: "Unabhängiges Expertengremium am Robert Koch-Institut, das die offiziellen Impfempfehlungen in Deutschland erarbeitet. Ihr jährlich aktualisierter Impfkalender ist die Grundlage für die Impfberatung in der Hausarztpraxis.", syn: "Ständige Impfkommission, Impfkommission, RKI-Impfkommission, Impfkalender, STIKO-Empfehlung, Stiko, Stico", group: "Impfungen & Erreger" },
  { k: "Tetanus (Wundstarrkrampf)", v: "Durch ein Bakteriengift ausgelöste Erkrankung, die über verschmutzte Wunden in den Körper gelangt und zu schmerzhaften Muskelkrämpfen führt. Der Impfschutz muss regelmäßig aufgefrischt werden und wird in der Praxis oft bei Verletzungen überprüft.", syn: "Tetanus, Wundstarrkrampf, Clostridium tetani, Starrkrampf, Tetanusimpfung, Tetanus-Auffrischung, Tetanusschutz, Tettanus, Tetanuns", group: "Impfungen & Erreger" },
  { k: "Titer", v: "Im Blut gemessene Menge an Antikörpern gegen einen bestimmten Erreger, die anzeigt, wie stark das Immunsystem geschützt ist. In der Praxis oft bestimmt, um zu prüfen, ob eine Impfung angeschlagen hat oder aufgefrischt werden sollte.", syn: "Antikörpertiter, Impftiter, Titerbestimmung, Antikörperspiegel, Serumtiter, Titerkontrolle, Titter, Tieter", group: "Impfungen & Erreger" },
  { k: "Totimpfstoff", v: "Impfstoff aus abgetöteten Erregern oder einzelnen Erregerbestandteilen, der sich im Körper nicht vermehren kann. Er gilt in der Regel als gut verträglich und macht häufig mehrere Impfdosen für einen sicheren Schutz nötig.", syn: "inaktivierter Impfstoff, Totimpfung, Tot-Impfstoff, inaktivierte Vakzine, Spaltimpfstoff, Subunit-Impfstoff, Konjugatimpfstoff, Totimfstoff, Totimpstoff", group: "Impfungen & Erreger" },
  { k: "Varizellen (Windpocken)", v: "Hochansteckende Viruserkrankung mit juckendem, bläschenförmigem Hautausschlag, ausgelöst durch das Varizella-Zoster-Virus. Nach durchgemachter Erkrankung bleibt das Virus im Körper und kann später eine Gürtelrose auslösen.", syn: "Varizellen, Windpocken, Varizella-Zoster-Virus, VZV, Feuchtblattern, Spitze Blattern, Wilde Blattern, Varizellen-Impfung, Varicellen, Varizelen", group: "Impfungen & Erreger" },

  // ===== Medizinische Wortbausteine =====
  { k: "-algie (Schmerz)", v: "Endung, die Schmerz in einer bestimmten Körperregion bezeichnet. Häufig genannt: Neuralgie (Nervenschmerz), Myalgie (Muskelschmerz), Arthralgie (Gelenkschmerz), Zephalgie (Kopfschmerz).", syn: "Schmerz, -dynie, Neuralgie, Myalgie, Arthralgie, Zephalgie, Fibromyalgie, -algien, algi, alkie, alghie", group: "Medizinische Wortbausteine" },
  { k: "-ektomie (operative Entfernung)", v: "Endung für die vollständige operative Entfernung eines Organs oder Körperteils, die in Operationsberichten und Überweisungen auftaucht. Beispiele: Appendektomie (Blinddarmentfernung), Tonsillektomie (Mandelentfernung), Hysterektomie (Gebärmutterentfernung), Cholezystektomie (Gallenblasenentfernung).", syn: "operative Entfernung, Resektion, Appendektomie, Tonsillektomie, Hysterektomie, Cholezystektomie, Mastektomie, -ektomien, ektonie, ektormie, ektomi", group: "Medizinische Wortbausteine" },
  { k: "-graphie / -grafie (bildgebende Aufzeichnung)", v: "Endung für ein bildgebendes oder aufzeichnendes Verfahren; das fertige Ergebnis heißt oft -gramm. Beispiele: Sonographie (Ultraschall), Mammographie (Röntgen der Brust), Angiographie (Gefäßdarstellung); als Ergebnis z. B. Elektrokardiogramm.", syn: "Bildgebung, Aufzeichnung, -grafie, -gramm, Sonographie, Mammographie, Radiographie, Angiographie, grafie, graphi, grafhie", group: "Medizinische Wortbausteine" },
  { k: "-itis (Entzündungsendung)", v: "Endung, die eine Entzündung eines Organs oder Gewebes bezeichnet; sie wird an den Namen des betroffenen Körperteils angehängt. In der Hausarztpraxis sehr häufig, z. B. Bronchitis (Bronchien), Gastritis (Magen), Otitis (Ohr) oder Arthritis (Gelenk).", syn: "Entzündung, -itiden (Mehrzahl), Bronchitis, Gastritis, Arthritis, Otitis, Sinusitis, Dermatitis, Tonsillitis, itis, ittis, ihtis, iitis", group: "Medizinische Wortbausteine" },
  { k: "-om (Geschwulst / Tumor)", v: "Die Endung -om bezeichnet meist eine echte Geschwulst/Gewebeneubildung, die gutartig oder bösartig sein kann, z. B. Lipom (gutartige Fettgeschwulst), Myom (gutartiger Muskelknoten der Gebärmutter), Adenom (Drüsengeschwulst), Fibrom (Bindegewebsgeschwulst) oder Karzinom (bösartiger Tumor). Wichtig als Ausnahme: Nicht jedes Wort auf -om ist ein Tumor – ein Hämatom ist keine Geschwulst, sondern lediglich ein Bluterguss (Blutansammlung im Gewebe); es sollte daher nicht als Beispiel für die Tumor-Bedeutung genannt werden.", syn: "Tumor, Geschwulst, Neubildung, Lipom, Myom, Karzinom, Hämatom, Melanom, Fibrom, Adenom, -ome (Mehrzahl), ohm, omm", group: "Medizinische Wortbausteine" },
  { k: "-ose (nicht-entzündlicher Zustand)", v: "Endung für einen krankhaften, meist nicht-entzündlichen Zustand oder eine schleichende Veränderung, häufig Verschleiß oder eine bestimmte Stoffwechsellage. Beispiele: Arthrose (Gelenkverschleiß), Arteriosklerose (Gefäßverkalkung), Thrombose (Blutgerinnsel), Osteoporose (Knochenschwund).", syn: "Arthrose, Arteriosklerose, Thrombose, Osteoporose, Skoliose, Neurose, -osen (Mehrzahl), ose, ohse, oose", group: "Medizinische Wortbausteine" },
  { k: "-pathie (Leiden / Erkrankung)", v: "Endung für eine Erkrankung oder ein Leiden eines Organs, oft ohne genaue Ursachenangabe. Beispiele aus der Praxis: Neuropathie (Nervenleiden), Nephropathie (Nierenerkrankung) oder Retinopathie (Netzhauterkrankung), häufig als Folge von Diabetes.", syn: "Leiden, Erkrankung, Neuropathie, Arthropathie, Nephropathie, Retinopathie, Kardiomyopathie, -pathien, pathi, patie, phatie", group: "Medizinische Wortbausteine" },
  { k: "-skopie (Spiegelung / Betrachtung)", v: "Endung für die Betrachtung von Körperhöhlen oder Organen mit einem optischen Gerät (Endoskop). In der Praxis vor allem bei Überweisungen relevant, z. B. Koloskopie (Darmspiegelung), Gastroskopie (Magenspiegelung) oder Bronchoskopie (Lungenspiegelung).", syn: "Spiegelung, Endoskopie, Koloskopie, Gastroskopie, Bronchoskopie, Arthroskopie, Zystoskopie, -skopien, skobie, scopie, skopei", group: "Medizinische Wortbausteine" },
  { k: "-tomie (Eröffnung / Schnitt)", v: "Endung für einen operativen Schnitt oder das Eröffnen eines Organs, ohne dieses zu entfernen (Unterschied zu -ektomie). Beispiele: Tracheotomie (Luftröhrenschnitt), Laparotomie (Bauchschnitt), Osteotomie (Knochendurchtrennung).", syn: "Schnitt, Eröffnung, Inzision, Tracheotomie, Laparotomie, Osteotomie, -tomien, tonie, thomie, tomi", group: "Medizinische Wortbausteine" },
  { k: "-ämie (Blut-Zustand)", v: "Endung, die einen Zustand des Blutes oder den Gehalt eines Stoffes im Blut beschreibt. Beispiele: Anämie (Blutarmut), Hyperglykämie (zu hoher Blutzucker), Leukämie (Blutkrebs), Bakteriämie (Bakterien im Blut).", syn: "Blutzustand, Anämie, Hyperglykämie, Hypoglykämie, Leukämie, Bakteriämie, Urämie, -ämien, emie, aemie, ähmie", group: "Medizinische Wortbausteine" },
  { k: "A- / An- (ohne / fehlend)", v: "Verneinende Vorsilbe mit der Bedeutung ohne, fehlend oder nicht vorhanden (An- steht vor Vokalen). Beispiele: Anämie (Blutarmut), Apnoe (Atemstillstand), asymptomatisch (ohne Beschwerden), Arrhythmie (unregelmäßiger Herzschlag).", syn: "A-, An-, ohne, fehlend, nicht, Anämie, Apnoe, asymptomatisch, Arrhythmie, Aphasie, Anurie, a-privativum", group: "Medizinische Wortbausteine" },
  { k: "akut / chronisch / rezidivierend (Krankheitsverlauf)", v: "Zeitliche Verlaufsbegriffe: akut heißt plötzlich auftretend, kurz und heftig, chronisch heißt dauerhaft und über lange Zeit bestehend, rezidivierend heißt immer wiederkehrend. Beschreiben in Diagnosen den Verlauf, z. B. akute gegen chronische Bronchitis.", syn: "akut, chronisch, rezidivierend, plötzlich, dauerhaft, wiederkehrend, subakut, Rezidiv, chron., rez., chronnisch, resedivierend", group: "Medizinische Wortbausteine" },
  { k: "bilateral / unilateral (beidseitig / einseitig)", v: "Lagebegriffe zur Seitigkeit: bilateral bedeutet beidseitig (beide Körperseiten betroffen), unilateral bedeutet einseitig (nur eine Seite). Häufig in Befunden, z. B. bilaterale Kniearthrose oder unilateraler Beinschmerz.", syn: "bilateral, unilateral, beidseitig, einseitig, beiderseits, beidseits, bds., bi-, uni-, bilaterahl, unilaterahl", group: "Medizinische Wortbausteine" },
  { k: "Dys- (Störung / Fehlfunktion)", v: "Vorsilbe für eine Störung, Fehlfunktion oder erschwerte Funktion. Häufig in der Praxis: Dysphagie (Schluckstörung), Dyspnoe (Atemnot), Dyspepsie (Verdauungsstörung), Dysurie (erschwertes oder schmerzhaftes Wasserlassen).", syn: "Dys-, Störung, Fehlfunktion, erschwert, gestört, Dysphagie, Dyspnoe, Dyspepsie, Dysurie, Dysfunktion, diss, düs", group: "Medizinische Wortbausteine" },
  { k: "Endo- (innen / innerhalb)", v: "Vorsilbe mit der Bedeutung innen oder innerhalb. Beispiele: Endokard (innere Herzhaut), Endometrium (Gebärmutterschleimhaut), Endoskopie (Betrachtung von innen), endokrin (Hormone nach innen abgebend).", syn: "Endo-, innen, innerhalb, Endokard, Endometrium, Endoskopie, endokrin, Endokarditis, ento, endoo", group: "Medizinische Wortbausteine" },
  { k: "Epi- (auf / über / darüber)", v: "Vorsilbe mit der Bedeutung auf, über oder darüberliegend. Beispiele: Epidermis (obere Hautschicht), Epikard (äußere Herzhaut), Epikondylitis (Sehnenreizung am Ellenbogen, Tennisarm), Epiglottis (Kehldeckel).", syn: "Epi-, auf, über, oberhalb, darüberliegend, Epidermis, Epikard, Epikondylitis, Epiglottis, eppi, äpi", group: "Medizinische Wortbausteine" },
  { k: "Hemi- (halb / halbseitig)", v: "Vorsilbe mit der Bedeutung halb oder eine Körperhälfte betreffend. Beispiele: Hemiparese (Halbseitenlähmung) und Hemiplegie (vollständige halbseitige Lähmung), häufig nach Schlaganfall; Hemikolektomie (Entfernung einer Darmhälfte).", syn: "Hemi-, halb, halbseitig, eine Körperhälfte, Hemiparese, Hemiplegie, Hemikranie, Hemikolektomie, hämi, hemmi", group: "Medizinische Wortbausteine" },
  { k: "Hyper- / Hypo- (zu viel / zu wenig)", v: "Gegensätzliche Vorsilben: Hyper- bedeutet zu viel, übermäßig oder gesteigert, Hypo- bedeutet zu wenig, vermindert oder unterhalb. Werden leicht verwechselt, z. B. Hypertonie (Bluthochdruck) gegen Hypotonie (niedriger Blutdruck) oder Hyperthyreose (Schilddrüsenüberfunktion) gegen Hypothyreose (Unterfunktion).", syn: "Hyper-, Hypo-, über-, unter-, zu viel, zu wenig, Hypertonie, Hypotonie, Hyperthyreose, Hypothyreose, Hyperglykämie, Hypoglykämie, hipo, hyppo, hiper", group: "Medizinische Wortbausteine" },
  { k: "Peri- (um herum)", v: "Vorsilbe mit der Bedeutung um etwas herum oder in der Umgebung von. Beispiele: Perikard (Herzbeutel, um das Herz), perianal (um den After herum), Perimenopause (Zeit um die Wechseljahre), Periost (Knochenhaut).", syn: "Peri-, um herum, umgebend, ringsum, Perikard, perianal, Perimenopause, Periost, Perikarditis, perri, peery", group: "Medizinische Wortbausteine" },
  { k: "Poly- / Oligo- (viel / wenig)", v: "Gegensätzliche Mengen-Vorsilben: Poly- bedeutet viel, viele oder mehrere, Oligo- bedeutet wenig oder spärlich. Beispiele: Polyurie (viel Wasserlassen) gegen Oligurie (verminderte Harnmenge), Polyarthritis (mehrere entzündete Gelenke), Oligomenorrhoe (seltene Regelblutung).", syn: "Poly-, Oligo-, viel, viele, mehrere, wenig, spärlich, Polyurie, Oligurie, Polyarthritis, Polyneuropathie, Oligomenorrhoe, poli, oligoo", group: "Medizinische Wortbausteine" },
  { k: "proximal / distal (rumpfnah / rumpffern)", v: "Richtungsbegriffe an den Gliedmaßen: proximal heißt zur Körpermitte bzw. zum Rumpf hin (nah), distal heißt vom Rumpf weg (fern, zur Hand oder zum Fuß hin). Beispiel: das Handgelenk liegt distal, die Schulter proximal.", syn: "proximal, distal, körpernah, rumpfnah, körperfern, rumpffern, zentral, peripher, proximahl, distahl, distall", group: "Medizinische Wortbausteine" },
  { k: "Sub- (unter / unterhalb)", v: "Vorsilbe mit der Bedeutung unter, unterhalb oder geringgradig. Beispiele: subkutan (unter der Haut, z. B. bei Spritzen), sublingual (unter der Zunge), subfebril (leicht erhöhte Temperatur), subakut (zwischen akut und chronisch).", syn: "Sub-, unter, unterhalb, geringgradig, subkutan, sublingual, subfebril, subakut, s.c., supp, subb", group: "Medizinische Wortbausteine" },
  { k: "Tachy- / Brady- (schnell / langsam)", v: "Gegensätzliche Vorsilben zur Geschwindigkeit: Tachy- bedeutet schnell, Brady- bedeutet langsam. Meist auf den Herzschlag bezogen, z. B. Tachykardie (zu schneller Puls) gegen Bradykardie (zu langsamer Puls); auch Tachypnoe (beschleunigte Atmung).", syn: "Tachy-, Brady-, schnell, langsam, Tachykardie, Bradykardie, Tachypnoe, tachi, tachü, bradi, bradükardie", group: "Medizinische Wortbausteine" },
  { k: "ventral / dorsal (bauchwärts / rückenwärts)", v: "Richtungsbegriffe am Körper: ventral heißt zum Bauch hin bzw. vorne, dorsal heißt zum Rücken hin bzw. hinten. An der Hand spricht man von palmar (Handfläche), am Fuß von plantar (Fußsohle); dienen der Lagebeschreibung in Befunden.", syn: "ventral, dorsal, bauchwärts, rückenwärts, vorne, hinten, anterior, posterior, palmar, plantar, ventrahl, dorsahl, dorsl", group: "Medizinische Wortbausteine" },

  // ===== Formulare & Verwaltung =====
  { k: "Blaues Rezept (Privatrezept)", v: "Rezeptformular für Privatversicherte sowie für Verordnungen, die die gesetzliche Kasse nicht übernimmt. Der Patient bezahlt zunächst selbst und kann das Rezept bei seiner privaten Versicherung einreichen; es ist in der Regel drei Monate gültig.", syn: "Privatrezept, blaues Rezeptformular, PKV-Rezept, Selbstzahlerrezept, Privatverordnung", group: "Formulare & Verwaltung" },
  { k: "Bonusheft", v: "Heft oder digitaler Nachweis, in dem regelmäßige Vorsorge- und Früherkennungstermine dokumentiert werden — am bekanntesten das zahnärztliche Bonusheft für einen höheren Zuschuss zum Zahnersatz. Auch für Bonusprogramme der Krankenkassen lässt sich die Teilnahme an Check-ups, Impfungen oder Krebsfrüherkennung in der Praxis abstempeln oder bestätigen.", syn: "Zahnarzt-Bonusheft, Bonusprogramm, Bonusheft Krankenkasse, Vorsorgenachweis, Stempelheft, Bonuspunkte", group: "Formulare & Verwaltung" },
  { k: "BtM-Rezept (Betäubungsmittelrezept)", v: "Gelbes, dreiteiliges Spezialrezept mit fortlaufender Nummer für Betäubungsmittel, zum Beispiel stark wirksame opioidhaltige Schmerzmittel. Es gelten strenge Regeln: kurze Gültigkeit von rund einer Woche, Teil III verbleibt zur Dokumentation in der Praxis, und die Formulare werden personenbezogen bei der Bundesopiumstelle bestellt und sicher verwahrt.", syn: "Betäubungsmittelrezept, BTM-Rezept, BtM, gelbes Rezept, Opiatrezept, Betäubungsmittelverordnung, BtMVV, Betäubungsmittel", group: "Formulare & Verwaltung" },
  { k: "Chronikerbescheinigung (Muster 55)", v: "Mit der Bescheinigung sinkt die Belastungsgrenze für Zuzahlungen von 2 % auf 1 % der jährlichen Bruttoeinnahmen zum Lebensunterhalt; sie wird für den Befreiungsantrag bei der Krankenkasse benötigt.", syn: "Muster 55, Chroniker-Bescheinigung, Bescheinigung chronische Erkrankung, Chronikerregelung, schwerwiegend chronisch krank, 1-Prozent-Regelung, § 62 SGB V", group: "Formulare & Verwaltung" },
  { k: "DSGVO in der Arztpraxis", v: "Die Datenschutz-Grundverordnung regelt den Umgang mit personenbezogenen Daten; Gesundheitsdaten sind dabei besonders geschützt. Für die Praxis bedeutet das unter anderem: Patienteninformation zur Datenverarbeitung, keine Auskünfte an Unbefugte, Diskretion an der Anmeldung, sichere Aufbewahrung sowie das Recht der Patienten auf Auskunft und Kopie ihrer Unterlagen.", syn: "Datenschutz-Grundverordnung, DS-GVO, Datenschutz, Patientendatenschutz, Datenschutzerklärung Praxis, Datenverarbeitung, Datenschutzhinweise", group: "Formulare & Verwaltung" },
  { k: "eAU (elektronische Arbeitsunfähigkeitsbescheinigung)", v: "Digitale Krankschreibung: Die Praxis übermittelt die Arbeitsunfähigkeitsdaten elektronisch direkt an die Krankenkasse, der Arbeitgeber ruft sie dort ab. Gesetzlich Versicherte erhalten auf Wunsch einen Papierausdruck für die eigenen Unterlagen.", syn: "elektronische AU, E-AU, e-AU, EAU, digitale Krankschreibung, elektronischer gelber Schein, Krankmeldung elektronisch, AU digital", group: "Formulare & Verwaltung" },
  { k: "eGK (elektronische Gesundheitskarte)", v: "Versichertenkarte der gesetzlichen Krankenkassen mit Chip, die jedes Quartal an der Anmeldung eingelesen wird und den Versicherungsschutz nachweist; sie ist zugleich der Schlüssel zu eRezept und ePA. Bei einem Kassenwechsel wird die alte Karte ungültig und eine neue ausgestellt — reicht der Patient sie nicht rechtzeitig nach, kann die Behandlung zunächst privat in Rechnung gestellt werden.", syn: "elektronische Gesundheitskarte, Versichertenkarte, Gesundheitskarte, Krankenkassenkarte, Chipkarte, Krankenversichertenkarte, KVK, Kassenwechsel, Versichertenstammdaten, VSDM", group: "Formulare & Verwaltung" },
  { k: "ePA (elektronische Patientenakte)", v: "Digitale, kassenübergreifende Akte, in der Befunde, Arztbriefe, Medikationsliste und weitere Gesundheitsdaten eines Versicherten gespeichert werden. Die Praxis befüllt sie über das Praxisverwaltungssystem; Patienten können der Nutzung widersprechen (Opt-out) und Zugriffe selbst steuern.", syn: "elektronische Patientenakte, EPA, E-Patientenakte, ePA für alle, digitale Patientenakte, digitale Gesundheitsakte, Patientenakte", group: "Formulare & Verwaltung" },
  { k: "eRezept (elektronisches Rezept)", v: "Digitale Form des Kassenrezepts für Arzneimittel: Der Arzt signiert die Verordnung elektronisch, Patienten lösen sie mit der elektronischen Gesundheitskarte, der eRezept-App oder einem Papierausdruck mit Code in der Apotheke ein. Für gesetzlich Versicherte ist es der verpflichtende Standard, das rosa Rezept dient nur noch als Ersatzverfahren.", syn: "E-Rezept, e-Rezept, ERezept, elektronische Verordnung, digitales Rezept, Rezept-App, Token, Rezeptcode, QR-Code-Rezept", group: "Formulare & Verwaltung" },
  { k: "Grünes Rezept", v: "Empfehlung des Arztes für rezeptfreie, apothekenpflichtige Arzneimittel, die der Patient selbst bezahlt. Manche Krankenkassen erstatten solche Präparate als Satzungsleistung anteilig; dafür dient das grüne Rezept als Beleg.", syn: "Empfehlungsrezept, grünes Rezeptformular, rezeptfreie Medikamente, OTC-Empfehlung, Selbstzahler-Empfehlung, apothekenpflichtig rezeptfrei", group: "Formulare & Verwaltung" },
  { k: "Hilfsmittelverordnung", v: "Verordnung von Hilfsmitteln wie Gehhilfen, Rollstühlen, Inkontinenzmaterial oder Blutzuckerteststreifen, meist auf Muster 16 mit angekreuzter „7“ und Angabe der Diagnose. Viele Hilfsmittel müssen vor der Abgabe von der Krankenkasse genehmigt werden; Grundlage ist das Hilfsmittelverzeichnis der GKV.", syn: "Hilfsmittel, Hilfsmittelrezept, Hilfsmittelverzeichnis, Hilfsmittelnummer, Sanitätshaus-Verordnung, Rollator-Rezept, Inkontinenzhilfen, Verordnung Hilfsmittel", group: "Formulare & Verwaltung" },
  { k: "IGeL (Individuelle Gesundheitsleistungen)", v: "Ärztliche Leistungen, die die gesetzliche Krankenkasse nicht bezahlt und die Patienten privat nach der Gebührenordnung für Ärzte (GOÄ) abgerechnet werden, zum Beispiel bestimmte Zusatz-Ultraschall- oder Vorsorgeuntersuchungen und reisemedizinische Leistungen. Vor der Leistung sind eine schriftliche Vereinbarung und Aufklärung nötig, anschließend erhält der Patient eine Rechnung.", syn: "Individuelle Gesundheitsleistungen, Igel-Leistung, IGEL, Selbstzahlerleistung, Privatleistung, Wunschleistung, GOÄ-Rechnung", group: "Formulare & Verwaltung" },
  { k: "Muster 1 (Arbeitsunfähigkeitsbescheinigung, Papier)", v: "Das klassische Papierformular für die Krankschreibung, früher als „gelber Schein“ bekannt. Es wird heute vor allem als Ersatzverfahren genutzt, etwa bei technischen Störungen der eAU, bei Hausbesuchen oder für Versicherte, für die die eAU nicht gilt.", syn: "AU, AU-Bescheinigung, Arbeitsunfähigkeitsbescheinigung, gelber Schein, Krankschreibung, Krankmeldung, Papier-AU, Ersatzverfahren AU, Muster 1", group: "Formulare & Verwaltung" },
  { k: "Muster 10 / 10A (Laborüberweisung / Laborauftrag)", v: "Formulare zur Anforderung von Laboruntersuchungen: Muster 10 ist die Überweisung an ein Facharztlabor als Auftragsleistung, Muster 10A der Anforderungsschein für Untersuchungen über die Laborgemeinschaft der Praxis. Sie begleiten die eingesandten Blut- und anderen Proben.", syn: "Laborschein, Laborüberweisung, Laborauftrag, Laboranforderung, Laborzettel, Anforderungsschein Labor, Muster 10, Muster 10A, Überweisung Labor", group: "Formulare & Verwaltung" },
  { k: "Muster 12 (Verordnung häuslicher Krankenpflege)", v: "Verordnung, mit der ein Pflegedienst Leistungen wie Medikamentengabe, Verbandswechsel oder Injektionen beim Patienten zu Hause übernimmt. Sie muss von der Krankenkasse genehmigt werden; unterschieden werden Erst- und Folgeverordnung.", syn: "häusliche Krankenpflege, HKP, HKP-Verordnung, Pflegedienstverordnung, Behandlungspflege, Verordnung Pflegedienst, Muster 12", group: "Formulare & Verwaltung" },
  { k: "Muster 13 (Heilmittelverordnung)", v: "Einheitliches Verordnungsformular für Heilmittel wie Physiotherapie (Krankengymnastik), Ergotherapie, Logopädie, Podologie und Ernährungstherapie. Diagnosegruppe, Heilmittel und Anzahl der Behandlungseinheiten richten sich nach dem Heilmittelkatalog.", syn: "Heilmittelverordnung, Heilmittelrezept, HMV, Physiotherapie-Rezept, Krankengymnastik-Verordnung, KG-Rezept, Ergotherapie-Verordnung, Logopädie-Verordnung, Podologie-Verordnung, Muster 13", group: "Formulare & Verwaltung" },
  { k: "Muster 16 (Kassenrezept, rosa Rezept)", v: "Das rosafarbene Arzneiverordnungsblatt für gesetzlich Versicherte; die Kasse übernimmt die Kosten abzüglich der Zuzahlung. Es wird auch für Hilfsmittel, Verbandmittel und Sprechstundenbedarf genutzt; für Arzneimittel ist es weitgehend durch das eRezept abgelöst und dient dort nur noch als Ersatzverfahren.", syn: "rosa Rezept, rotes Rezept, Kassenrezept, Arzneiverordnungsblatt, GKV-Rezept, Rezeptformular, Muster 16", group: "Formulare & Verwaltung" },
  { k: "Muster 2 (Verordnung von Krankenhausbehandlung)", v: "Formular für die Einweisung eines Kassenpatienten ins Krankenhaus, wenn ambulante Behandlung nicht ausreicht. Es enthält Diagnose und Fragestellung und wird dem Patienten für die Aufnahme in der Klinik mitgegeben.", syn: "Krankenhauseinweisung, Einweisung, Einweisungsschein, Klinikeinweisung, stationäre Einweisung, Verordnung Krankenhausbehandlung, Muster 2", group: "Formulare & Verwaltung" },
  { k: "Muster 36 (Präventionsempfehlung)", v: "Formular, mit dem der Arzt eine verhaltensbezogene Vorsorgemaßnahme empfiehlt, zum Beispiel Kurse zu Bewegung, Ernährung, Stressbewältigung oder Suchtmittelverzicht. Der Patient legt die Empfehlung seiner Krankenkasse vor, die sich an den Kosten zertifizierter Präventionskurse beteiligen kann.", syn: "Präventionsempfehlung, ärztliche Bescheinigung Präventionskurs, Primärprävention, Vorsorgeempfehlung, Empfehlung Gesundheitskurs, Muster 36", group: "Formulare & Verwaltung" },
  { k: "Muster 4 (Verordnung einer Krankenbeförderung)", v: "Der „Transportschein“: Verordnung für Fahrten zur Behandlung, etwa mit Taxi, Mietwagen, Krankentransport- oder Rettungswagen, wenn der Patient aus medizinischen Gründen nicht selbst fahren kann. Je nach Fahrtart muss die Krankenkasse die Beförderung vorab genehmigen.", syn: "Transportschein, Krankenbeförderung, Krankenfahrt, Fahrkostenverordnung, Taxischein, Beförderungsschein, KTW-Verordnung, Muster 4", group: "Formulare & Verwaltung" },
  { k: "Muster 6 (Überweisungsschein)", v: "Formular, mit dem der Hausarzt einen Kassenpatienten zur Mit-, Weiterbehandlung oder gezielten Diagnostik an einen Facharzt überweist. Es enthält Diagnose und Auftrag, bei Bedarf auch einen Dringlichkeitsvermerk oder Vermittlungscode für die Terminservicestelle.", syn: "Überweisung, Überweisungsschein, Facharztüberweisung, Überweisungsformular, Mitbehandlung, Weiterbehandlung, Konsiliaruntersuchung, Muster 6", group: "Formulare & Verwaltung" },
  { k: "Notfalldatensatz (NFDM)", v: "Freiwillig auf der elektronischen Gesundheitskarte bzw. künftig als elektronische Patientenkurzakte (ePKA) in der ePA gespeicherte Notfallinformationen wie Diagnosen, Dauermedikation, Allergien und Kontaktpersonen. Der Arzt legt die Daten mit Einwilligung des Patienten an; im Notfall können Behandler sie auch ohne PIN des Patienten auslesen.", syn: "Notfalldaten, NFDM, Notfalldatenmanagement, Patientenkurzakte, ePKA, Notfallpass, Notfalldaten eGK, Notfallinformationen", group: "Formulare & Verwaltung" },
  { k: "Organspendeausweis", v: "Dokument in Papierform oder Eintrag im zentralen Organspende-Register, mit dem eine Person festhält, ob sie einer Organ- und Gewebespende zustimmt, widerspricht oder die Entscheidung anderen überträgt. Hausarztpraxen halten Ausweise und Informationsmaterial bereit und informieren Patienten auf Wunsch ergebnisoffen.", syn: "Organspendeerklärung, Organspende-Register, Spenderausweis, Organspende, Gewebespende, Organspenderegister", group: "Formulare & Verwaltung" },
  { k: "Schweigepflichtentbindung", v: "Schriftliche Erklärung, mit der ein Patient die Praxis von der ärztlichen Schweigepflicht gegenüber bestimmten Stellen entbindet, etwa Versicherungen, anderen Ärzten oder Angehörigen. Ohne diese Entbindung dürfen keine Patientendaten oder Auskünfte weitergegeben werden; die Schweigepflicht gilt für das gesamte Praxisteam, auch für MFA.", syn: "Schweigepflicht, Entbindung von der Schweigepflicht, Schweigepflichtsentbindung, ärztliche Schweigepflicht, Schweigepflichterklärung, Auskunftsermächtigung, § 203 StGB", group: "Formulare & Verwaltung" },
  { k: "Terminservicestelle (116117)", v: "Zentrale Anlaufstelle der Kassenärztlichen Vereinigungen: Unter der Nummer 116117 werden Facharzt-, Psychotherapie- und Hausarzttermine vermittelt, außerhalb der Sprechzeiten ist sie zugleich der ärztliche Bereitschaftsdienst. Für dringliche Facharzttermine trägt die Praxis einen Vermittlungscode auf der Überweisung ein.", syn: "TSS, 116 117, 116117, Patientenservice, Terminvermittlung, Terminservice, Vermittlungscode, Dringlichkeitscode, ärztlicher Bereitschaftsdienst", group: "Formulare & Verwaltung" },
  { k: "Zuzahlung / Zuzahlungsbefreiung", v: "Die Belastungsgrenze beträgt 2 % (1 % bei schwerwiegend chronisch Kranken) der jährlichen Bruttoeinnahmen zum Lebensunterhalt. Bei Familien werden die Einkünfte des gesamten Haushalts zusammengerechnet und Freibeträge für Angehörige abgezogen; ist die Grenze überschritten, stellt die Kasse auf Antrag eine Befreiung für den Rest des Kalenderjahres aus.", syn: "Rezeptgebühr, Eigenanteil, Selbstbeteiligung, Zuzahlungsbefreiung, Befreiungskarte, Belastungsgrenze, zuzahlungsbefreit, Befreiungsausweis", group: "Formulare & Verwaltung" },

  // ===== Hygiene & Praxisorganisation =====
  { k: "Abwurfbehälter (Kanülenabwurf)", v: "Stich- und bruchfester Behälter zum sofortigen Entsorgen benutzter Kanülen, Nadeln und anderer spitzer Gegenstände, um Stichverletzungen zu vermeiden. Er steht griffbereit überall dort, wo gespritzt oder Blut abgenommen wird, und wird verschlossen entsorgt.", syn: "Kanülenabwurf, Kanülensammler, Kanülenabwurfbehälter, Spritzenabwurf, Nadelbehälter, Sharpsbehälter, Abwurfbox, gelbe Box, Entsorgungsbehälter Kanülen", group: "Hygiene & Praxisorganisation" },
  { k: "Aufbereitung von Medizinprodukten", v: "Der komplette Ablauf, mit dem benutzte Instrumente wieder sicher einsatzbereit gemacht werden: Vorreinigung, Reinigung, Desinfektion, Kontrolle und Pflege, Verpackung, Sterilisation und Lagerung. In der Hausarztpraxis betrifft das vor allem wiederverwendbare Instrumente wie Scheren, Pinzetten oder Nadelhalter.", syn: "Instrumentenaufbereitung, Medizinprodukteaufbereitung, Wiederaufbereitung, Aufbereitungskreislauf, Instrumente aufbereiten, MP-Aufbereitung, unkritisch semikritisch kritisch", group: "Hygiene & Praxisorganisation" },
  { k: "Autoklav (Dampfsterilisator)", v: "Gerät, das Instrumente mit heißem, unter Druck stehendem Wasserdampf (meist 121 bis 134 °C) sterilisiert und dadurch keimfrei macht. Steht in vielen Praxen zur Aufbereitung wiederverwendbarer Instrumente vor deren erneutem Einsatz.", syn: "Dampfsterilisator, Sterilisator, Dampf-Sterilisator, Sterilisationsgerät, Autoclav (falsch), Autoklave, Autoklav Praxis", group: "Hygiene & Praxisorganisation" },
  { k: "Desinfektion und Sterilisation", v: "Desinfektion senkt die Zahl der Krankheitserreger so weit, dass keine Infektionsgefahr mehr besteht; Sterilisation macht ein Produkt vollständig keimfrei, einschließlich widerstandsfähiger Sporen. In der Praxis werden Hände und Flächen desinfiziert, sterilisiert werden nur Instrumente, die in den Körper eindringen.", syn: "Desinfizieren, Sterilisieren, keimfrei machen, Entkeimung, Keimreduktion, Unterschied Desinfektion Sterilisation, Sterilistation (falsch), Desinfektion vs Sterilisation", group: "Hygiene & Praxisorganisation" },
  { k: "Flächendesinfektion", v: "Desinfektion von Oberflächen wie Liegen, Arbeitsflächen und Geräten, meist als Wischdesinfektion; nach dem Wischen muss die Fläche die angegebene Einwirkzeit lang feucht bleiben. Unterschieden wird zwischen routinemäßiger Desinfektion und gezielter Desinfektion nach einer sichtbaren Verunreinigung.", syn: "Wischdesinfektion, Oberflächendesinfektion, Flächen desinfizieren, Sprühdesinfektion, Flächendesinfektionsmittel, Liege desinfizieren, Scheuer-Wisch-Desinfektion", group: "Hygiene & Praxisorganisation" },
  { k: "Hautantiseptik (Hautdesinfektion)", v: "Desinfektion der Haut vor Eingriffen wie Injektionen, Blutentnahmen oder kleinen Wundversorgungen, um Keime an der Einstichstelle abzutöten; auch hier ist eine bestimmte Einwirkzeit einzuhalten. Gehört zu den Routinemaßnahmen vor jeder Spritze oder Blutabnahme.", syn: "Hautdesinfektion, Antiseptik, Antisepsis, Haut antiseptisch, Einstichstelle desinfizieren, Hautantiseptikum, Hautdesinfektionsmittel, Wunddesinfektion", group: "Hygiene & Praxisorganisation" },
  { k: "Hygieneplan", v: "Schriftliches Dokument, das für die Praxis festlegt, wer was womit und wie oft reinigt und desinfiziert, etwa Hände, Flächen und Instrumente. Er ist verpflichtend und dient zugleich als Nachschlagewerk für das Team und als Nachweis bei Kontrollen.", syn: "Hygieneplan, Desinfektionsplan, Reinigungsplan, Hygieneplan Praxis, Hygienemanagement, Hygienevorschriften, Hygieneplan erstellen", group: "Hygiene & Praxisorganisation" },
  { k: "Händedesinfektion (Händehygiene)", v: "Das gründliche Einreiben der Hände mit einem alkoholischen Desinfektionsmittel, um Krankheitserreger abzutöten; dabei muss die Einwirkzeit (meist etwa 30 Sekunden, Hände die ganze Zeit feucht halten) eingehalten werden. Sie gilt als wichtigste Einzelmaßnahme gegen die Übertragung von Keimen in der Praxis.", syn: "Händehygiene, hygienische Händedesinfektion, Hände desinfizieren, Handdesinfektion, Einwirkzeit, Einwirkzeit Händedesinfektion, Händedesinfektionsmittel, Händehygenie (falsch)", group: "Hygiene & Praxisorganisation" },
  { k: "Kühlkette (Impfstoffe)", v: "Die lückenlose Kühlung von Impfstoffen und bestimmten Medikamenten (meist +2 bis +8 °C) vom Hersteller bis zur Anwendung; wird die Kette unterbrochen, kann der Impfstoff unwirksam werden. In der Praxis wird sie mit einem überwachten Medikamentenkühlschrank und einem Temperaturprotokoll sichergestellt.", syn: "Kühlkette Impfstoffe, Kältekette, Kuehlkette, Impfstofflagerung, Medikamentenkühlschrank, Kühlschrank Impfstoffe, 2 bis 8 Grad, Temperaturüberwachung Impfstoff", group: "Hygiene & Praxisorganisation" },
  { k: "Medizinprodukte-Betreiberverordnung (MPBetreibV)", v: "Verordnung, die regelt, wie Medizinprodukte wie Geräte und Instrumente in der Praxis betrieben, aufbereitet, gewartet und kontrolliert werden müssen. Sie ist unter anderem Grundlage für das Medizinproduktebuch, das Bestandsverzeichnis und wiederkehrende Prüfungen.", syn: "MPBetreibV, Betreiberverordnung, MP-Betreiberverordnung, Medizinprodukte Betreiberverordnung, Medizinproduktebuch, Bestandsverzeichnis, MPG, Medizinproduktegesetz", group: "Hygiene & Praxisorganisation" },
  { k: "Meldepflichtige Erkrankungen (IfSG)", v: "Bestimmte Infektionskrankheiten und Erregernachweise, die nach dem Infektionsschutzgesetz (IfSG) an das Gesundheitsamt gemeldet werden müssen, zum Beispiel Masern, Keuchhusten oder bestimmte Darminfektionen. Die Meldung erfolgt teils namentlich und innerhalb festgelegter Fristen.", syn: "Meldepflicht, IfSG, Infektionsschutzgesetz, meldepflichtige Krankheiten, Gesundheitsamt melden, namentliche Meldung, Meldepflicht Arzt, § 6 IfSG, Infektionsschutz", group: "Hygiene & Praxisorganisation" },
  { k: "Nadelstichverletzung (Kanülenstichverletzung)", v: "Verletzung durch eine gebrauchte Kanüle, Nadel oder ein anderes spitzes Instrument, bei der Krankheitserreger wie Hepatitis-Viren oder HIV übertragen werden können. Sie gilt als meldepflichtiger Arbeitsunfall und erfordert ein festgelegtes Sofortvorgehen mit Betriebsarzt oder Durchgangsarzt.", syn: "Kanülenstichverletzung, Nadelstichverletzung, Stichverletzung, NSV, Nadelstich, Verletzung durch Kanüle, sich gestochen, Schnittverletzung Instrument", group: "Hygiene & Praxisorganisation" },
  { k: "Persönliche Schutzausrüstung (PSA)", v: "Schutzkleidung und -mittel, die das Personal vor Infektionen und Kontamination schützen, zum Beispiel Einmalhandschuhe, Mund-Nasen-Schutz oder FFP2-Maske, Schutzkittel und Schutzbrille. Welche Ausstattung nötig ist, richtet sich nach der jeweiligen Tätigkeit und der Infektionsgefahr.", syn: "PSA, PPE, persönliche Schutzausrüstung, Schutzkleidung, Schutzstufe, Einmalhandschuhe, FFP2-Maske, Mund-Nasen-Schutz, Mundschutz, Schutzkittel, Schutzbrille", group: "Hygiene & Praxisorganisation" },
  { k: "Reinigungs- und Desinfektionsgerät (RDG)", v: "Automatisches Gerät, das benutzte Instrumente maschinell reinigt und anschließend mit heißem Wasser thermisch desinfiziert, vergleichbar mit einem speziellen Geschirrspüler für Medizinprodukte. Es sorgt für eine gleichbleibende, dokumentierbare Aufbereitung, meist als Schritt vor der Sterilisation.", syn: "RDG, Thermodesinfektor, Reinigungs-Desinfektions-Gerät, Reinigungs- und Desinfektionsautomat, Instrumentenspülmaschine, Desinfektionsspülmaschine, maschinelle Aufbereitung", group: "Hygiene & Praxisorganisation" },
  { k: "RKI-Empfehlungen", v: "Fachliche Empfehlungen des Robert Koch-Instituts (RKI), der zentralen deutschen Behörde für Infektionsschutz, unter anderem zu Hygiene, Aufbereitung von Medizinprodukten und Impfungen (über die STIKO). Sie bilden die Grundlage vieler Hygienevorgaben in der Praxis.", syn: "Robert Koch-Institut, Robert-Koch-Institut, RKI, KRINKO, KRINKO-Empfehlung, Kommission für Krankenhaushygiene, STIKO, RKI Richtlinie", group: "Hygiene & Praxisorganisation" },
  { k: "Verfallsdatum und Anbruchdatum", v: "Das Verfallsdatum gibt an, bis wann ein Produkt (Medikament, Sterilgut, Desinfektionsmittel) verwendet werden darf; das Anbruchdatum wird beim ersten Öffnen vermerkt, weil viele Mittel nach dem Anbruch nur noch begrenzt haltbar sind. Beides ist wichtig bei der Kontrolle von Beständen und angebrochenen Flaschen.", syn: "Haltbarkeitsdatum, Ablaufdatum, Verwendbarkeitsdatum, MHD, Verfalldatum (falsch), Anbruchsdatum, Anbruch notieren, Haltbarkeit nach Anbruch, Expiry", group: "Hygiene & Praxisorganisation" },

  // ===== Praxisalltag & Verfahren =====
  { k: "Adhärenz (Compliance)", v: "Bezeichnet, wie zuverlässig ein Patient die vereinbarte Behandlung einhält, z. B. Medikamente regelmäßig einnimmt oder Kontrolltermine wahrnimmt. \"Compliance\" ist der ältere Begriff (Befolgen ärztlicher Anweisungen), \"Adhärenz\" betont die gemeinsam mit dem Patienten getroffene Therapieentscheidung.", syn: "Compliance, Therapietreue, Einnahmetreue, Non-Compliance, non-adhärent, Komplianz, Adhaerenz, Adherence, Complience, Kompliance", group: "Praxisalltag & Verfahren" },
  { k: "ambulant / stationär", v: "Ambulant heißt: Der Patient wird behandelt und geht danach wieder nach Hause (z. B. Praxisbesuch oder ambulante Operation). Stationär heißt: Er wird ins Krankenhaus aufgenommen und bleibt mindestens eine Nacht — wichtig u. a. bei Einweisungen und für Abrechnungsfragen.", syn: "ambulante Behandlung, stationäre Aufnahme, teilstationär, ambulantes Operieren, ambulante OP, Krankenhausaufenthalt, ambullant, stazionär", group: "Praxisalltag & Verfahren" },
  { k: "Anamnese (Krankengeschichte)", v: "Die Erhebung der Krankengeschichte im Gespräch: aktuelle Beschwerden, Vorerkrankungen, Medikamente, Allergien und Erkrankungen in der Familie. Steht am Anfang fast jedes Arztkontakts; bei Neupatienten wird sie in der Praxis oft mit einem Anamnesebogen vorbereitet.", syn: "Krankengeschichte, Anamneseerhebung, Eigenanamnese, Fremdanamnese, Familienanamnese, Medikamentenanamnese, Anamnesebogen, anamnestisch, Annamnese, Anamnäse", group: "Praxisalltag & Verfahren" },
  { k: "Attest (ärztliche Bescheinigung)", v: "Eine ärztliche Bescheinigung über einen Gesundheitszustand, z. B. für Schule, Sportbefreiung, Kita oder Reisefähigkeit. Viele Atteste sind keine Kassenleistung und werden dem Patienten privat nach GOÄ berechnet — ein häufiges Thema am Empfang.", syn: "ärztliche Bescheinigung, ärztliches Attest, Schulattest, Sportattest, Sportbefreiung, Gesundheitszeugnis, Bescheinigung, Attest ausstellen, Atest, Gefälligkeitsattest", group: "Praxisalltag & Verfahren" },
  { k: "Diagnose / Differenzialdiagnose", v: "Die Diagnose ist die festgestellte Erkrankung als Ergebnis von Anamnese, Untersuchung und ggf. Labor; Differenzialdiagnosen (abgekürzt DD) sind andere Erkrankungen mit ähnlichen Beschwerden, die noch ausgeschlossen werden müssen. In Befunden steht \"DD\" oft direkt hinter der Verdachtsdiagnose.", syn: "DD, Verdachtsdiagnose, Arbeitsdiagnose, Ausschlussdiagnose, Diagnosestellung, diagnostizieren, Differentialdiagnose, Differenzialdiagnostik, Diagnosen, Diagose", group: "Praxisalltag & Verfahren" },
  { k: "elektiv (planbarer Eingriff)", v: "Ein elektiver Eingriff ist medizinisch sinnvoll, aber zeitlich planbar — das Gegenteil eines Notfalls. Beispiel: eine geplante Hüftoperation, für die die Praxis in Ruhe Einweisung und Voruntersuchungen organisieren kann.", syn: "planbar, Wahleingriff, elektiver Eingriff, elektive Operation, Elektiv-OP, geplante Operation, Elektivsprechstunde, elektieve", group: "Praxisalltag & Verfahren" },
  { k: "Generikum", v: "Ein wirkstoffgleiches Nachahmerpräparat eines Originalmedikaments, dessen Patentschutz abgelaufen ist — meist deutlich günstiger. Im Praxisalltag wichtig wegen der Rabattverträge der Kassen: Die Apotheke gibt oft ein anderes wirkstoffgleiches Präparat ab, als auf dem Rezept steht (Aut-idem-Regelung).", syn: "Generika, Nachahmerpräparat, wirkstoffgleiches Medikament, Originalpräparat, aut idem, Aut-idem-Regelung, Rabattvertrag, Generikatausch, Genericum, Generikum Medikament", group: "Praxisalltag & Verfahren" },
  { k: "Indikation / Kontraindikation", v: "Die Indikation ist der medizinische Grund für eine Untersuchung oder Behandlung (Heilanzeige); die Kontraindikation ist ein Umstand, der dagegen spricht (Gegenanzeige), z. B. eine Allergie oder Schwangerschaft. Taucht häufig in Befunden und Arztbriefen auf, etwa als \"bei gegebener Indikation\" oder \"kontraindiziert\".", syn: "Heilanzeige, Gegenanzeige, indiziert, kontraindiziert, absolute Kontraindikation, relative Kontraindikation, Indikationsstellung, Indikazion, Kontraindikazion", group: "Praxisalltag & Verfahren" },
  { k: "Notfall / dringlich", v: "Ein Notfall ist akut lebensbedrohlich oder droht schwere Schäden zu verursachen und muss sofort versorgt werden (ggf. Rettungsdienst 112); dringlich bedeutet: zeitnah nötig, aber einige Stunden bis Tage aufschiebbar. Diese Einstufung (Ersteinschätzung/Triage) trifft die MFA täglich am Telefon und am Empfang bei der Terminvergabe.", syn: "Notfallpatient, Akutfall, akut, Dringlichkeit, Triage, Ersteinschätzung, Notfalltermin, Akutsprechstunde, lebensbedrohlich, Rettungsdienst, 112", group: "Praxisalltag & Verfahren" },
  { k: "Nüchternwert", v: "Ein Laborwert, der nach mehrstündiger Nahrungspause bestimmt wird (meist 8–12 Stunden nichts essen, nur Wasser trinken) — typisch sind Nüchternblutzucker und Blutfette. Wichtig für die Terminvergabe: Diese Patienten kommen morgens nüchtern zur Blutabnahme.", syn: "nüchtern, Nüchternblutzucker, Nüchternglukose, Nüchternblutentnahme, nüchtern zur Blutabnahme, Nahrungskarenz, Nüchternwerte, Nüchternheit, nuechtern", group: "Praxisalltag & Verfahren" },
  { k: "Off-Label-Use", v: "Der Einsatz eines zugelassenen Medikaments außerhalb seines offiziellen Zulassungsbereichs, etwa für eine andere Erkrankung, Dosierung oder Altersgruppe. In der Praxis relevant, weil die Krankenkasse die Kosten dann oft nur unter besonderen Voraussetzungen übernimmt.", syn: "Off-Label, zulassungsüberschreitende Anwendung, Off-Label-Verordnung, Off Label Use, Offlabel, Off-Lable-Use, Off-Label-Einsatz", group: "Praxisalltag & Verfahren" },
  { k: "Palliativversorgung", v: "Die Behandlung und Begleitung unheilbar kranker Menschen mit dem Ziel, Beschwerden wie Schmerzen zu lindern und Lebensqualität zu erhalten — nicht mehr zu heilen. Hausarztpraxen sind häufig eingebunden, etwa über die allgemeine (AAPV) oder spezialisierte ambulante Palliativversorgung (SAPV).", syn: "Palliativmedizin, palliativ, SAPV, AAPV, spezialisierte ambulante Palliativversorgung, Palliativpflege, Palliativstation, Hospiz, Sterbebegleitung, Paliativ, paliativ", group: "Praxisalltag & Verfahren" },
  { k: "Palpation / Perkussion / Auskultation", v: "Die drei klassischen Techniken der körperlichen Untersuchung: Palpation ist das Abtasten (z. B. des Bauches), Perkussion das Abklopfen (z. B. der Lunge) und Auskultation das Abhören mit dem Stethoskop (Herz, Lunge, Darm). Sie gehören in der Hausarztpraxis zu fast jeder Untersuchung, etwa beim Check-up.", syn: "Abtasten, Abklopfen, Abhören, Abhorchen, palpieren, perkutieren, auskultieren, Tastbefund, Klopfschall, Stethoskop, körperliche Untersuchung, Palpazion, Auskultazion, Percussion, Auskulation", group: "Praxisalltag & Verfahren" },
  { k: "Placebo", v: "Ein Scheinmedikament ohne Wirkstoff, das echten Arzneimitteln zum Verwechseln ähnlich sieht und vor allem in Studien als Vergleich dient. Der Placeboeffekt beschreibt, dass allein die Erwartung einer Wirkung Beschwerden messbar bessern kann.", syn: "Scheinmedikament, Scheinpräparat, Placeboeffekt, Placebokontrolle, Nocebo, Plazebo, Placebos, Plazeboeffekt", group: "Praxisalltag & Verfahren" },
  { k: "Prognose", v: "Die ärztliche Einschätzung des voraussichtlichen Krankheitsverlaufs — ob und wie gut eine Erkrankung ausheilt oder ob sie fortschreitet. In Arztbriefen z. B. als \"günstige\" oder \"infauste\" (aussichtslose) Prognose formuliert.", syn: "Heilungsaussicht, Krankheitsverlauf, Verlaufsvorhersage, prognostisch, gute Prognose, infaust, infauste Prognose, Krankheitsprognose, Prognose günstig", group: "Praxisalltag & Verfahren" },
  { k: "Prophylaxe", v: "Eine vorbeugende Maßnahme, die eine Erkrankung oder Komplikation verhindern soll — z. B. Impfungen oder die Thromboseprophylaxe nach Operationen. In Befunden häufig als Adjektiv \"prophylaktisch\" (vorbeugend).", syn: "Vorbeugung, Prävention, prophylaktisch, Thromboseprophylaxe, Impfprophylaxe, Expositionsprophylaxe, Rezidivprophylaxe, Profilaxe, Prophylaxen", group: "Praxisalltag & Verfahren" },
  { k: "Rehabilitation (Reha)", v: "Maßnahmen, die Patienten nach schwerer Krankheit, Operation oder Unfall wieder fit für Alltag und Beruf machen sollen — ambulant oder stationär, z. B. als Anschlussheilbehandlung (AHB) direkt nach dem Krankenhaus. Die Hausarztpraxis ist oft an Reha-Anträgen und den nötigen Unterlagen beteiligt.", syn: "Reha, medizinische Rehabilitation, Anschlussheilbehandlung, AHB, Reha-Antrag, Reha-Maßnahme, Rehaklinik, Kur, Rehabilitierung, Reha-Bericht", group: "Praxisalltag & Verfahren" },
  { k: "Remission", v: "Das vorübergehende oder dauerhafte Nachlassen der Krankheitszeichen, ohne dass zwingend eine Heilung vorliegt — der Begriff wird vor allem bei Krebs- und chronischen Erkrankungen verwendet. Man unterscheidet Vollremission (keine Krankheitszeichen mehr) und Teilremission (deutliche Besserung).", syn: "Rückbildung, Vollremission, komplette Remission, Teilremission, partielle Remission, remittierend, in Remission, Remmission, Remision", group: "Praxisalltag & Verfahren" },
  { k: "Rezidiv", v: "Das Wiederauftreten einer Erkrankung nach zunächst erfolgreicher Behandlung, umgangssprachlich der Rückfall — z. B. ein Tumorrezidiv oder \"rezidivierende Harnwegsinfekte\" (immer wiederkehrende Blasenentzündungen) im Befund.", syn: "Rückfall, rezidivierend, Rezidivprophylaxe, Lokalrezidiv, Tumorrezidiv, wiederkehrend, erneutes Auftreten, Rezediv, Rezidief, Recidiv", group: "Praxisalltag & Verfahren" },
  { k: "Überweisung / Einweisung", v: "Mit einer Überweisung (Muster 6) schickt die Praxis den Patienten zur Diagnostik oder Mitbehandlung zu einem anderen ambulanten Arzt, z. B. Facharzt; mit einer Einweisung (Verordnung von Krankenhausbehandlung, Muster 2) wird eine stationäre Aufnahme im Krankenhaus veranlasst. Beide Formulare werden im Praxisalltag meist von der MFA vorbereitet.", syn: "Überweisungsschein, Muster 6, Facharztüberweisung, Einweisungsschein, Muster 2, Krankenhauseinweisung, Verordnung von Krankenhausbehandlung, stationäre Einweisung, Ueberweisung, Überweisungen", group: "Praxisalltag & Verfahren" },
];
